module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 저작권 보호기간 만료 공공저작물."},"kids":{"label":"어린이","note":"어린이용 의역"}},"chapters":[{"chapter":1,"title":"지혜의 시작","verses":{"krv":[{"n":1,"t":"다윗의 아들 이스라엘 왕 솔로몬의 잠언이라"},{"n":2,"t":"이는 지혜와 훈계를 알게 하며 명철의 말씀을 깨닫게 하며"},{"n":3,"t":"지혜롭게, 의롭게, 공평하게, 정직하게, 행할일에 대하여 훈계를 받게 하며"},{"n":4,"t":"어리석은 자로 슬기롭게 하며 젊은 자에게 지식과 근신함을 주기위한 것이니"},{"n":5,"t":"지혜있는 자는 듣고 학식이 더할 것이요 명철한 자는 모략을 얻을 것이라"},{"n":6,"t":"잠언과 비유와 지혜있는 자의 말과 그 오묘한 말을 깨달으리라"},{"n":7,"t":"여호와를 경외하는 것이 지식의 근본이어늘 미련한 자는 지혜와 훈계를 멸시하느니라"},{"n":8,"t":"내 아들아 네 아비의 훈계를 들으며 네 어미의 법을 떠나지 말라"},{"n":9,"t":"이는 네 머리의 아름다운 관이요 네 목의 금사슬이니라"},{"n":10,"t":"내 아들아 악한 자가 너를 꾈지라도 좇지 말라"},{"n":11,"t":"그들이 네게 말하기를 우리와 함께 가자 우리가 가만히 엎드렸다가 사람의 피를 흘리자 죄없는 자를 까닭없이 숨어 기다리다가"},{"n":12,"t":"음부 같이 그들을 산 채로 삼키며 무덤에 내려가는 자 같게 통으로 삼키자"},{"n":13,"t":"우리가 온갖 보화를 얻으며 빼앗은 것으로 우리 집에 채우리니"},{"n":14,"t":"너는 우리와 함께 제비를 뽑고 우리가 함께 전대 하나만 두자 할지라도"},{"n":15,"t":"내 아들아 그들과 함께 길에 다니지 말라 네 발을 금하여 그 길을 밟지 말라"},{"n":16,"t":"대저 그 발은 악으로 달려가며 피를 흘리는데 빠름이니라"},{"n":17,"t":"무릇 새가 그물 치는 것을 보면 헛 일이겠거늘"},{"n":18,"t":"그들의 가만히 엎드림은 자기의 피를 흘릴 뿐이요 숨어 기다림은 자기의 생명을 해할 뿐이니"},{"n":19,"t":"무릇 이를 탐하는 자의 길은 다 이러하여 자기의 생명을 잃게 하느니라"},{"n":20,"t":"지혜가 길거리에서 부르며 광장에서 소리를 높이며"},{"n":21,"t":"훤화하는 길 머리에서 소리를 지르며 성문 어귀와 성중에서 그 소리를 발하여 가로되"},{"n":22,"t":"너희 어리석은 자들은 어리석음을 좋아하며 거만한 자들은 거만을 기뻐하며 미련한 자들은 지식을 미워하니 어느 때까지 하겠느냐"},{"n":23,"t":"나의 책망을 듣고 돌이키라 보라 내가 나의 신을 너희에게 부어주며 나의 말을 너희에게 보이리라"},{"n":24,"t":"내가 부를지라도 너희가 듣기 싫어 하였고 내가 손을 펼지라도 돌아보는 자가 없었고"},{"n":25,"t":"도리어 나의 모든 교훈을 멸시하며 나의 책망을 받지 아니하였은즉"},{"n":26,"t":"너희가 재앙을 만날 때에 내가 웃을 것이며 너희에게 두려움이 임할 때에 내가 비웃으리라"},{"n":27,"t":"너희의 두려움이 광풍같이 임하겠고 너희의 재앙이 폭풍같이 임하리니"},{"n":28,"t":"그 때에 너희가 나를 부르리라 그래도 내가 대답지 아니하겠고 부지런히 나를 찾으리라 그래도 나를 만나지 못하리니"},{"n":29,"t":"대저 너희가 지식을 미워하며 여호와 경외하기를 즐거워하지 아니하며"},{"n":30,"t":"나의 교훈을 받지 아니하고 나의 모든 책망을 업신여겼음이라"},{"n":31,"t":"그러므로 자기 행위의 열매를 먹으며 자기 꾀에 배부르리라"},{"n":32,"t":"어리석은 자의 퇴보는 자기를 죽이며 미련한 자의 안일은 자기를 멸망시키려니와"},{"n":33,"t":"오직 나를 듣는 자는 안연히 살며 재앙의 두려움이 없이 평안하리라"}],"kids":[{"n":1,"t":"다윗의 아들, 이스라엘 왕 솔로몬의 잠언(지혜의 말)이에요."},{"n":2,"t":"이는 지혜와 훈계(가르침)를 알게 하며, 명철(슬기)의 말씀을 깨닫게 하며,"},{"n":3,"t":"지혜롭게, 의롭게, 공평하게, 정직(올바름)하게 행할 일에 대하여 훈계(가르침)를 받게 하며,"},{"n":4,"t":"어리석은 자로 슬기롭게 하며, 젊은 자에게 지식과 근신(조심함)함을 주기 위한 것이니,"},{"n":5,"t":"지혜 있는 자는 듣고 학식이 더할 것이요, 명철(슬기)한 자는 모략(좋은 꾀)을 얻을 것이라."},{"n":6,"t":"잠언(지혜의 말)과 비유와 지혜 있는 자의 말과 그 오묘(깊은 비밀)한 말을 깨달으리라."},{"n":7,"t":"여호와를 경외(존경하고 두려워)하는 것이 지식의 근본(뿌리)이어늘, 미련한 자는 지혜와 훈계(가르침)를 멸시(업신여김)하느니라."},{"n":8,"t":"내 아들아, 네 아비(아버지)의 훈계(가르침)를 들으며, 네 어미(어머니)의 법을 떠나지 말라."},{"n":9,"t":"이는 네 머리의 아름다운 관이요, 네 목의 금사슬이니라."},{"n":10,"t":"내 아들아, 악한 자가 너를 꾈지라도(꼬일지라도) 좇지(따르지) 말라."},{"n":11,"t":"그들이 네게 말하기를 \'우리와 함께 가자. 우리가 가만히 엎드렸다가 사람의 피를 흘리자. 죄 없는 자를 까닭 없이 숨어 기다리다가,"},{"n":12,"t":"음부(죽은 자의 곳) 같이 그들을 산 채로 삼키며, 무덤에 내려가는 자 같게 통으로 삼키자."},{"n":13,"t":"우리가 온갖 보화(보물)를 얻으며 빼앗은 것으로 우리 집에 채우리니,"},{"n":14,"t":"너는 우리와 함께 제비를 뽑고, 우리가 함께 전대(돈 주머니) 하나만 두자\' 할지라도,"},{"n":15,"t":"내 아들아, 그들과 함께 길에 다니지 말라. 네 발을 금(막)하여 그 길을 밟지 말라."},{"n":16,"t":"대저(무릇) 그 발은 악으로 달려가며, 피를 흘리는 데 빠름이니라."},{"n":17,"t":"무릇 새가 그물 치는 것을 보면 헛일이겠거늘,"},{"n":18,"t":"그들의 가만히 엎드림은 자기의 피를 흘릴 뿐이요, 숨어 기다림은 자기의 생명을 해(상하게)할 뿐이니,"},{"n":19,"t":"무릇 이(이익)를 탐(욕심내)하는 자의 길은 다 이러하여, 자기의 생명을 잃게 하느니라."},{"n":20,"t":"지혜가 길거리에서 부르며, 광장에서 소리를 높이며,"},{"n":21,"t":"훤화(시끄러움)하는 길 머리에서 소리를 지르며, 성문 어귀와 성중(성 안)에서 그 소리를 발(드러내)하여 말하기를,"},{"n":22,"t":"\\"너희 어리석은 자들은 어리석음을 좋아하며, 거만한 자들은 거만을 기뻐하며, 미련한 자들은 지식을 미워하니, 어느 때까지 하겠느냐?"},{"n":23,"t":"나의 책망(꾸짖음)을 듣고 돌이키라. 보라, 내가 나의 신(영)을 너희에게 부어주며, 나의 말을 너희에게 보이리라."},{"n":24,"t":"내가 부를지라도 너희가 듣기 싫어하였고, 내가 손을 펼지라도 돌아보는 자가 없었고,"},{"n":25,"t":"도리어 나의 모든 교훈(가르침)을 멸시(업신여김)하며, 나의 책망(꾸짖음)을 받지 아니하였은즉,"},{"n":26,"t":"너희가 재앙을 만날 때에 내가 웃을 것이며, 너희에게 두려움이 임할 때에 내가 비웃으리라."},{"n":27,"t":"너희의 두려움이 광풍(거센 바람) 같이 임하겠고, 너희의 재앙이 폭풍 같이 임하리니,"},{"n":28,"t":"그 때에 너희가 나를 부르리라. 그래도 내가 대답지 아니하겠고, 부지런히 나를 찾으리라. 그래도 나를 만나지 못하리니,"},{"n":29,"t":"대저(무릇) 너희가 지식을 미워하며, 여호와 경외(존경하고 두려워)하기를 즐거워하지 아니하며,"},{"n":30,"t":"나의 교훈(가르침)을 받지 아니하고, 나의 모든 책망(꾸짖음)을 업신여겼음이라."},{"n":31,"t":"그러므로 자기 행위(행함)의 열매를 먹으며, 자기 꾀에 배부르리라."},{"n":32,"t":"어리석은 자의 퇴보(돌이킴)는 자기를 죽이며, 미련한 자의 안일(편안함에 빠짐)은 자기를 멸망시키려니와,"},{"n":33,"t":"오직 나를 듣는 자는 안연(편안)히 살며, 재앙의 두려움이 없이 평안하리라.\\""}]}},{"chapter":2,"title":"지혜가 지키는 길","verses":{"krv":[{"n":1,"t":"내 아들아 네가 만일 나의 말을 받으며 나의 계명을 네게 간직하며"},{"n":2,"t":"네 귀를 지혜에 기울이며 네 마음을 명철에 두며"},{"n":3,"t":"지식을 불러 구하며 명철을 얻으려고 소리를 높이며"},{"n":4,"t":"은을 구하는 것 같이 그것을 구하며 감추인 보배를 찾는 것 같이 그것을 찾으면"},{"n":5,"t":"여호와 경외하기를 깨달으며 하나님을 알게 되리니"},{"n":6,"t":"대저 여호와는 지혜를 주시며 지식과 명철을 그 입에서 내심이며"},{"n":7,"t":"그는 정직한 자를 위하여 완전한 지혜를 예비하시며 행실이 온전한 자에게 방패가 되시나니"},{"n":8,"t":"대저 그는 공평의 길을 보호하시며 그 성도들의 길을 보전하려 하심이니라"},{"n":9,"t":"그런즉 네가 공의와 공평과 정직 곧 모든 선한 길을 깨달을 것이라"},{"n":10,"t":"곧 지혜가 네 마음에 들어가며 지식이 네 영혼에 즐겁게 될 것이요"},{"n":11,"t":"근신이 너를 지키며 명철이 너를 보호하여"},{"n":12,"t":"악한 자의 길과 패역을 말하는 자에게서 건져내리라"},{"n":13,"t":"이 무리는 정직한 길을 떠나 어두운 길로 행하며"},{"n":14,"t":"행악하기를 기뻐하며 악인의 패역을 즐거워하나니"},{"n":15,"t":"그 길은 구부러지고 그 행위는 패역하리라"},{"n":16,"t":"지혜가 또 너를 음녀에게서, 말로 호리는 이방 계집에게서 구원 하리니"},{"n":17,"t":"그는 소시의 짝을 버리며 그 하나님의 언약을 잊어버린자라"},{"n":18,"t":"그 집은 사망으로, 그 길은 음부로 기울어졌나니"},{"n":19,"t":"누구든지 그에게로 가는 자는 돌아오지 못하며 또 생명길을 얻지 못하느니라"},{"n":20,"t":"지혜가 너로 선한 자의 길로 행하게 하며 또 의인의 길을 지키게하리니"},{"n":21,"t":"대저 정직한 자는 땅에 거하며 완전한 자는 땅에 남아 있으리라"},{"n":22,"t":"그러나 악인은 땅에서 끊어지겠고 궤휼한 자는 땅에서 뽑히리라"}],"kids":[{"n":1,"t":"내 아들아, 네가 만일 나의 말을 받으며, 나의 계명을 네게 간직하며,"},{"n":2,"t":"네 귀를 지혜에 기울이며, 네 마음을 명철(슬기)에 두며,"},{"n":3,"t":"지식을 불러 구하며, 명철(슬기)을 얻으려고 소리를 높이며,"},{"n":4,"t":"은을 구하는 것 같이 그것을 구하며, 감추인 보배를 찾는 것 같이 그것을 찾으면,"},{"n":5,"t":"여호와 경외(존경하고 두려워)하기를 깨달으며, 하나님을 알게 되리니,"},{"n":6,"t":"대저(무릇) 여호와는 지혜를 주시며, 지식과 명철(슬기)을 그 입에서 내심이며,"},{"n":7,"t":"그는 정직(올바른)한 자를 위하여 완전한 지혜를 예비(준비)하시며, 행실이 온전한 자에게 방패가 되시나니,"},{"n":8,"t":"대저(무릇) 그는 공평의 길을 보호하시며, 그 성도(거룩한 백성)들의 길을 보전(보호)하려 하심이니라."},{"n":9,"t":"그런즉 네가 공의(옳음)와 공평과 정직(올바름), 곧 모든 선한 길을 깨달을 것이라."},{"n":10,"t":"곧 지혜가 네 마음에 들어가며, 지식이 네 영혼에 즐겁게 될 것이요,"},{"n":11,"t":"근신(조심함)이 너를 지키며, 명철(슬기)이 너를 보호하여,"},{"n":12,"t":"악한 자의 길과, 패역(거역)을 말하는 자에게서 건져내리라."},{"n":13,"t":"이 무리는 정직(올바른)한 길을 떠나 어두운 길로 행하며,"},{"n":14,"t":"행악(악을 행함)하기를 기뻐하며, 악인의 패역(거역)을 즐거워하나니,"},{"n":15,"t":"그 길은 구부러지고, 그 행위(행함)는 패역(거역)하리라."},{"n":16,"t":"지혜가 또 너를 음녀(부도덕한 여인)에게서, 말로 호리는 이방 계집(다른 나라 여인)에게서 구원하리니,"},{"n":17,"t":"그는 소시(어렸을 때)의 짝을 버리며, 그 하나님의 언약(약속)을 잊어버린 자라."},{"n":18,"t":"그 집은 사망(죽음)으로, 그 길은 음부(죽은 자의 곳)로 기울어졌나니,"},{"n":19,"t":"누구든지 그에게로 가는 자는 돌아오지 못하며, 또 생명 길을 얻지 못하느니라."},{"n":20,"t":"지혜가 너로 선한 자의 길로 행하게 하며, 또 의인의 길을 지키게 하리니,"},{"n":21,"t":"대저(무릇) 정직(올바른)한 자는 땅에 거(머무름)하며, 완전한 자는 땅에 남아 있으리라."},{"n":22,"t":"그러나 악인은 땅에서 끊어지겠고, 궤휼(속임)한 자는 땅에서 뽑히리라."}]}},{"chapter":3,"title":"지혜와 명철","verses":{"krv":[{"n":1,"t":"내 아들아 나의 법을 잊어버리지 말고 네 마음으로 나의 명령을 지키라"},{"n":2,"t":"그리하면 그것이 너로 장수하여 많은 해를 누리게 하며 평강을 더하게 하리라"},{"n":3,"t":"인자와 진리로 네게서 떠나지 않게 하고 그것을 네 목에 매며 네 마음판에 새기라"},{"n":4,"t":"그리하면 네가 하나님과 사람 앞에서 은총과 귀중히 여김을 받으리라"},{"n":5,"t":"너는 마음을 다하여 여호와를 의뢰하고 네 명철을 의지하지 말라"},{"n":6,"t":"너는 범사에 그를 인정하라 그리하면 네 길을 지도하시리라"},{"n":7,"t":"스스로 지혜롭게 여기지 말지어다 여호와를 경외하며 악을 떠날지어다"},{"n":8,"t":"이것이 네 몸에 양약이 되어 네 골수로 윤택하게 하리라"},{"n":9,"t":"네 재물과 네 소산물의 처음 익은 열매로 여호와를 공경하라"},{"n":10,"t":"그리하면 네 창고가 가득히 차고 네 즙틀에 새 포도즙이 넘치리라"},{"n":11,"t":"내 아들아 여호와의 징계를 경히 여기지 말라 그 꾸지람을 싫어 하지 말라"},{"n":12,"t":"대저 여호와께서 그 사랑하시는 자를 징계하시기를 마치 아비가 그 기뻐하는 아들을 징계함 같이 하시느니라"},{"n":13,"t":"지혜를 얻은 자와 명철을 얻은 자는 복이 있나니"},{"n":14,"t":"이는 지혜를 얻는 것이 은을 얻는 것보다 낫고 그 이익이 정금보다 나음이니라"},{"n":15,"t":"지혜는 진주보다 귀하니 너의 사모하는 모든 것으로 이에 비교할수 없도다"},{"n":16,"t":"그 우편 손에는 장수가 있고 그 좌편 손에는 부귀가 있나니"},{"n":17,"t":"그 길은 즐거운 길이요 그 첩경은 다 평강이니라"},{"n":18,"t":"지혜는 그 얻은 자에게 생명 나무라 지혜를 가진 자는 복되도다"},{"n":19,"t":"여호와께서는 지혜로 땅을 세우셨으며 명철로 하늘을 굳게 펴셨고"},{"n":20,"t":"그 지식으로 해양이 갈라지게 하셨으며 공중에서 이슬이 내리게 하셨느니라"},{"n":21,"t":"내 아들아 완전한 지혜와 근신을 지키고 이것들로 네 눈 앞에서 떠나지 않게 하라"},{"n":22,"t":"그리하면 그것이 네 영혼의 생명이 되며 네 목에 장식이 되리니"},{"n":23,"t":"네가 네 길을 안연히 행하겠고 네 발이 거치지 아니하겠으며"},{"n":24,"t":"네가 누울 때에 두려워하지 아니하겠고 네가 누운즉 네 잠이 달리로다"},{"n":25,"t":"너는 창졸간의 두려움이나 악인의 멸망이 임할 때나 두려워하지 말라"},{"n":26,"t":"대저 여호와는 너의 의지할 자이시라 네 발을 지켜 걸리지 않게 하시리라"},{"n":27,"t":"네 손이 선을 베풀 힘이 있거든 마땅히 받을 자에게 베풀기를 아끼지 말며"},{"n":28,"t":"네게 있거든 이웃에게 이르기를 갔다가 다시 오라 내일 주겠노라 하지말며"},{"n":29,"t":"네 이웃이 네 곁에서 안연히 살거든 그를 모해하지 말며"},{"n":30,"t":"사람이 네게 악을 행하지 아니하였거든 까닭없이 더불어 다투지 말며"},{"n":31,"t":"포학한 자를 부러워하지 말며 그 아무 행위든지 좇지 말라"},{"n":32,"t":"대저 패역한 자는 여호와의 미워하심을 입거니와 정직한 자에게는 그의 교통하심이 있으며"},{"n":33,"t":"악인의 집에는 여호와의 저주가 있거니와 의인의 집에는 복이 있느니라"},{"n":34,"t":"진실로 그는 거만한 자를 비웃으시며 겸손한 자에게 은혜를 베푸시나니"},{"n":35,"t":"지혜로운 자는 영광을 기업으로 받거니와 미련한 자의 현달함은 욕이 되느니라"}],"kids":[{"n":1,"t":"내 아들아, 나의 법을 잊어버리지 말고, 네 마음으로 나의 명령을 지키라."},{"n":2,"t":"그리하면 그것이 너로 장수(오래 삶)하여 많은 해를 누리게 하며, 평강(평안)을 더하게 하리라."},{"n":3,"t":"인자(자비)와 진리로 네게서 떠나지 않게 하고, 그것을 네 목에 매며 네 마음판에 새기라."},{"n":4,"t":"그리하면 네가 하나님과 사람 앞에서 은총(사랑받음)과 귀중(귀하게)히 여김을 받으리라."},{"n":5,"t":"너는 마음을 다하여 여호와를 의뢰(의지)하고, 네 명철(슬기)을 의지하지 말라."},{"n":6,"t":"너는 범사(모든 일)에 그를 인정하라. 그리하면 네 길을 지도(이끌어 주심)하시리라."},{"n":7,"t":"스스로 지혜롭게 여기지 말지어다. 여호와를 경외(존경하고 두려워)하며 악을 떠날지어다."},{"n":8,"t":"이것이 네 몸에 양약(좋은 약)이 되어, 네 골수(뼛속)로 윤택(부드럽고 윤기)하게 하리라."},{"n":9,"t":"네 재물과 네 소산물(거둔 것)의 처음 익은 열매로 여호와를 공경하라."},{"n":10,"t":"그리하면 네 창고가 가득히 차고, 네 즙틀에 새 포도즙이 넘치리라."},{"n":11,"t":"내 아들아, 여호와의 징계(가르침의 벌)를 경(가볍게)히 여기지 말라. 그 꾸지람을 싫어하지 말라."},{"n":12,"t":"대저(무릇) 여호와께서 그 사랑하시는 자를 징계(가르침의 벌)하시기를, 마치 아비(아버지)가 그 기뻐하는 아들을 징계함 같이 하시느니라."},{"n":13,"t":"지혜를 얻은 자와 명철(슬기)을 얻은 자는 복이 있나니,"},{"n":14,"t":"이는 지혜를 얻는 것이 은을 얻는 것보다 낫고, 그 이익이 정금(순금)보다 낫기 때문이니라."},{"n":15,"t":"지혜는 진주보다 귀하니, 너의 사모(간절히 바람)하는 모든 것으로 이에 비교할 수 없도다."},{"n":16,"t":"그 우편(오른편) 손에는 장수(오래 삶)가 있고, 그 좌편(왼편) 손에는 부귀(부유함과 귀함)가 있나니,"},{"n":17,"t":"그 길은 즐거운 길이요, 그 첩경(지름길)은 다 평강(평안)이니라."},{"n":18,"t":"지혜는 그 얻은 자에게 생명 나무라. 지혜를 가진 자는 복되도다."},{"n":19,"t":"여호와께서는 지혜로 땅을 세우셨으며, 명철(슬기)로 하늘을 굳게 펴셨고,"},{"n":20,"t":"그 지식으로 해양(바다)이 갈라지게 하셨으며, 공중에서 이슬이 내리게 하셨느니라."},{"n":21,"t":"내 아들아, 완전한 지혜와 근신(조심함)을 지키고, 이것들로 네 눈 앞에서 떠나지 않게 하라."},{"n":22,"t":"그리하면 그것이 네 영혼의 생명이 되며, 네 목에 장식이 되리니,"},{"n":23,"t":"네가 네 길을 안연(편안)히 행하겠고, 네 발이 거치지(걸리지) 아니하겠으며,"},{"n":24,"t":"네가 누울 때에 두려워하지 아니하겠고, 네가 누운즉 네 잠이 달리로다(달리라)."},{"n":25,"t":"너는 창졸간(갑자기)의 두려움이나, 악인의 멸망이 임할 때나, 두려워하지 말라."},{"n":26,"t":"대저(무릇) 여호와는 너의 의지할 자이시라. 네 발을 지켜 걸리지 않게 하시리라."},{"n":27,"t":"네 손이 선을 베풀 힘이 있거든, 마땅히 받을 자에게 베풀기를 아끼지 말며,"},{"n":28,"t":"네게 있거든 이웃에게 이르기를 \'갔다가 다시 오라. 내일 주겠노라\' 하지 말며,"},{"n":29,"t":"네 이웃이 네 곁에서 안연(편안)히 살거든 그를 모해(꾀로 해함)하지 말며,"},{"n":30,"t":"사람이 네게 악을 행하지 아니하였거든 까닭 없이 더불어 다투지 말며,"},{"n":31,"t":"포학(포악)한 자를 부러워하지 말며, 그 아무 행위(행함)든지 좇지(따르지) 말라."},{"n":32,"t":"대저(무릇) 패역(거역)한 자는 여호와의 미워하심을 입거니와, 정직(올바른)한 자에게는 그의 교통(친밀히 사귐)하심이 있으며,"},{"n":33,"t":"악인의 집에는 여호와의 저주가 있거니와, 의인의 집에는 복이 있느니라."},{"n":34,"t":"진실로 그는 거만한 자를 비웃으시며, 겸손한 자에게 은혜를 베푸시나니,"},{"n":35,"t":"지혜로운 자는 영광을 기업(분깃)으로 받거니와, 미련한 자의 현달(높이 됨)함은 욕이 되느니라."}]}},{"chapter":4,"title":"마음을 지키는 길","verses":{"krv":[{"n":1,"t":"아들들아 아비의 훈계를 들으며 명철을 얻기에 주의하라"},{"n":2,"t":"내가 선한 도리를 너희에게 전하노니 내 법을 떠나지 말라"},{"n":3,"t":"나도 내 아버지에게 아들이었었으며 내 어머니 보기에 유약한 외아들이었었노라"},{"n":4,"t":"아버지가 내게 가르쳐 이르기를 내 말을 네 마음에 두라 내 명령을 지키라 그리하면 살리라"},{"n":5,"t":"지혜를 얻으며 명철을 얻으라 내 입의 말을 잊지 말며 어기지 말라"},{"n":6,"t":"지혜를 버리지 말라 그가 너를 보호하리라 그를 사랑하라 그가 너를 지키리라"},{"n":7,"t":"지혜가 제일이니 지혜를 얻으라 무릇 너의 얻은 것을 가져 명철을 얻을지니라"},{"n":8,"t":"그를 높이라 그리하면 그가 너를 높이 들리라 만일 그를 품으면 그가 너를 영화롭게 하리라"},{"n":9,"t":"그가 아름다운 관을 네 머리에 두겠고 영화로운 면류관을 네게 주리라 하였느니라"},{"n":10,"t":"내 아들아 들으라 내 말을 받으라 그리하면 네 생명의 해가 길리라"},{"n":11,"t":"내가 지혜로운 길로 네게 가르쳤으며 정직한 첩경으로 너를 인도하였은즉"},{"n":12,"t":"다닐 때에 네 걸음이 곤란하지 아니하겠고 달려갈 때에 실족하지 아니하리라"},{"n":13,"t":"훈계를 굳게 잡아 놓치지 말고 지키라 이것이 네 생명이니라"},{"n":14,"t":"사특한 자의 첩경에 들어가지 말며 악인의 길로 다니지 말지어다"},{"n":15,"t":"그 길을 피하고 지나가지 말며 돌이켜 떠나갈지어다"},{"n":16,"t":"그들은 악을 행하지 못하면 자지 못하며 사람을 넘어뜨리지 못하면 잠이 오지 아니하며"},{"n":17,"t":"불의의 떡을 먹으며 강포의 술을 마심이니라"},{"n":18,"t":"의인의 길은 돋는 햇볕 같아서 점점 빛나서 원만한 광명에 이르거니와"},{"n":19,"t":"악인의 길은 어둠 같아서 그가 거쳐 넘어져도 그것이 무엇인지 깨닫지 못하느니라"},{"n":20,"t":"내 아들아 내 말에 주의하며 나의 이르는 것에 네 귀를 기울이라"},{"n":21,"t":"그것을 네 눈에서 떠나게 말며 네 마음 속에 지키라"},{"n":22,"t":"그것은 얻는 자에게 생명이 되며 그 온 육체의 건강이 됨이니라"},{"n":23,"t":"무릇 지킬만한 것보다 더욱 네 마음을 지키라 생명의 근원이 이에서 남이니라"},{"n":24,"t":"궤휼을 네 입에서 버리며 사곡을 네 입술에서 멀리하라"},{"n":25,"t":"네 눈은 바로 보며 네 눈꺼풀은 네 앞을 곧게 살펴"},{"n":26,"t":"네 발의 행할 첩경을 평탄케 하며 네 모든 길을 든든히하라"},{"n":27,"t":"우편으로나 좌편으로나 치우치지 말고 네 발을 악에서 떠나게 하라"}],"kids":[{"n":1,"t":"아들들아, 아비(아버지)의 훈계(가르침)를 들으며, 명철(슬기)을 얻기에 주의하라."},{"n":2,"t":"내가 선한 도리(가르침)를 너희에게 전하노니, 내 법을 떠나지 말라."},{"n":3,"t":"나도 내 아버지에게 아들이었으며, 내 어머니 보기에 유약(어리고 약함)한 외아들이었느니라."},{"n":4,"t":"아버지가 내게 가르쳐 이르기를, \'내 말을 네 마음에 두라. 내 명령을 지키라. 그리하면 살리라."},{"n":5,"t":"지혜를 얻으며 명철(슬기)을 얻으라. 내 입의 말을 잊지 말며 어기지 말라."},{"n":6,"t":"지혜를 버리지 말라. 그가 너를 보호하리라. 그를 사랑하라. 그가 너를 지키리라."},{"n":7,"t":"지혜가 제일이니 지혜를 얻으라. 무릇 너의 얻은 것을 가져 명철(슬기)을 얻을지니라."},{"n":8,"t":"그를 높이라. 그리하면 그가 너를 높이 들리라. 만일 그를 품으면 그가 너를 영화(영광스럽게)롭게 하리라."},{"n":9,"t":"그가 아름다운 관을 네 머리에 두겠고, 영화로운 면류관(왕관)을 네게 주리라\' 하였느니라."},{"n":10,"t":"내 아들아, 들으라. 내 말을 받으라. 그리하면 네 생명의 해가 길리라."},{"n":11,"t":"내가 지혜로운 길로 네게 가르쳤으며, 정직(올바른)한 첩경(지름길)으로 너를 인도하였은즉,"},{"n":12,"t":"다닐 때에 네 걸음이 곤란하지 아니하겠고, 달려갈 때에 실족(넘어짐)하지 아니하리라."},{"n":13,"t":"훈계(가르침)를 굳게 잡아 놓치지 말고 지키라. 이것이 네 생명이니라."},{"n":14,"t":"사특(사악)한 자의 첩경(지름길)에 들어가지 말며, 악인의 길로 다니지 말지어다."},{"n":15,"t":"그 길을 피하고 지나가지 말며, 돌이켜 떠나갈지어다."},{"n":16,"t":"그들은 악을 행하지 못하면 자지 못하며, 사람을 넘어뜨리지 못하면 잠이 오지 아니하며,"},{"n":17,"t":"불의의 떡(빵)을 먹으며, 강포(난폭)의 술을 마심이니라."},{"n":18,"t":"의인의 길은 돋는 햇볕 같아서 점점 빛나서 원만한 광명(빛)에 이르거니와,"},{"n":19,"t":"악인의 길은 어둠 같아서, 그가 거쳐 넘어져도 그것이 무엇인지 깨닫지 못하느니라."},{"n":20,"t":"내 아들아, 내 말에 주의하며, 나의 이르는 것에 네 귀를 기울이라."},{"n":21,"t":"그것을 네 눈에서 떠나게 말며, 네 마음 속에 지키라."},{"n":22,"t":"그것은 얻는 자에게 생명이 되며, 그 온 육체의 건강이 됨이니라."},{"n":23,"t":"무릇 지킬 만한 것보다 더욱 네 마음을 지키라. 생명의 근원(샘)이 이에서 남이니라."},{"n":24,"t":"궤휼(속임)을 네 입에서 버리며, 사곡(사악)을 네 입술에서 멀리하라."},{"n":25,"t":"네 눈은 바로 보며, 네 눈꺼풀은 네 앞을 곧게 살펴,"},{"n":26,"t":"네 발의 행할 첩경(지름길)을 평탄(평평)케 하며, 네 모든 길을 든든히 하라."},{"n":27,"t":"우편(오른쪽)으로나 좌편(왼쪽)으로나 치우치지 말고, 네 발을 악에서 떠나게 하라."}]}},{"chapter":5,"title":"음녀를 멀리하라","verses":{"krv":[{"n":1,"t":"내 아들아 내 지혜에 주의하며 내 명철에 네 귀를 기울여서"},{"n":2,"t":"근신을 지키며 네 입술로 지식을 지키도록 하라"},{"n":3,"t":"대저 음녀의 입술은 꿀을 떨어뜨리며 그 입은 기름보다 미끄러우나"},{"n":4,"t":"나중은 쑥 같이 쓰고 두 날 가진 칼같이 날카로우며"},{"n":5,"t":"그 발은 사지로 내려가며 그 걸음은 음부로 나아가나니"},{"n":6,"t":"그는 생명의 평탄한 길을 찾지 못하며 자기 길이 든든치 못하여 그것을 깨닫지 못하느니라"},{"n":7,"t":"그런즉 아들들아 나를 들으며 내 입의 말을 버리지 말고"},{"n":8,"t":"네 길을 그에게서 멀리하라 그 집 문에도 가까이 가지 말라"},{"n":9,"t":"두렵건대 네 존영이 남에게 잃어버리게 되며 네 수한이 잔포자에게 빼앗기게 될까 하노라"},{"n":10,"t":"두렵건대 타인이 네 재물로 충족하게 되며 네 수고한 것이 외인의 집에 있게될까 하노라"},{"n":11,"t":"두렵건대 마지막에 이르러 네 몸 네 육체가 쇠패할 때에 네가 한탄하여"},{"n":12,"t":"말하기를 내가 어찌하여 훈계를 싫어하며 내 마음이 꾸지람을 가벼이 여기고"},{"n":13,"t":"내 선생의 목소리를 청종치 아니하며 나를 가르치는 이에게 귀를 기울이지 아니하였던고"},{"n":14,"t":"많은 무리들이 모인 중에서 모든 악에 거의 빠지게 되었었노라 하게 될까 하노라"},{"n":15,"t":"너는 네 우물에서 물을 마시며 네 샘에서 흐르는 물을 마시라"},{"n":16,"t":"어찌하여 네 샘물을 집 밖으로 넘치게 하겠으며 네 도랑물을 거리로 흘러가게 하겠느냐"},{"n":17,"t":"그 물로 네게만 있게 하고 타인으로 더불어 그것을 나누지 말라"},{"n":18,"t":"네 샘으로 복되게 하라 네가 젊어서 취한 아내를 즐거워하라"},{"n":19,"t":"그는 사랑스러운 암사슴 같고 아름다운 암노루 같으니 너는 그 품을 항상 족하게 여기며 그 사랑을 항상 연모하라"},{"n":20,"t":"내 아들아 어찌하여 음녀를 연모하겠으며 어찌하여 이방 계집의 가슴을 안겠느냐"},{"n":21,"t":"대저 사람의 길은 여호와의 눈 앞에 있나니 그가 그 모든 길을 평탄케 하시느니라"},{"n":22,"t":"악인은 자기의 악에 걸리며 그 죄의 줄에 매이나니"},{"n":23,"t":"그는 훈계를 받지 아니함을 인하여 죽겠고 미련함이 많음을 인하여 혼미하게 되느니라"}],"kids":[{"n":1,"t":"내 아들아, 내 지혜에 주의하며, 내 명철(슬기)에 네 귀를 기울여서,"},{"n":2,"t":"근신(조심함)을 지키며, 네 입술로 지식을 지키도록 하라."},{"n":3,"t":"대저(무릇) 음녀(부도덕한 여인)의 입술은 꿀을 떨어뜨리며, 그 입은 기름보다 미끄러우나,"},{"n":4,"t":"나중은 쑥같이 쓰고, 두 날 가진 칼같이 날카로우며,"},{"n":5,"t":"그 발은 사지(죽음의 자리)로 내려가며, 그 걸음은 음부(죽은 자의 곳)로 나아가나니,"},{"n":6,"t":"그는 생명의 평탄(평평)한 길을 찾지 못하며, 자기 길이 든든치 못하여 그것을 깨닫지 못하느니라."},{"n":7,"t":"그런즉 아들들아, 나를 들으며 내 입의 말을 버리지 말고,"},{"n":8,"t":"네 길을 그에게서 멀리하라. 그 집 문에도 가까이 가지 말라."},{"n":9,"t":"두렵건대 네 존영(귀한 영광)이 남에게 잃어버리게 되며, 네 수한(목숨의 햇수)이 잔포자(잔인하고 포악한 자)에게 빼앗기게 될까 하노라."},{"n":10,"t":"두렵건대 타인(다른 사람)이 네 재물로 충족(만족)하게 되며, 네 수고한 것이 외인(낯선 사람)의 집에 있게 될까 하노라."},{"n":11,"t":"두렵건대 마지막에 이르러, 네 몸 네 육체가 쇠패(쇠하여 망함)할 때에 네가 한탄하여,"},{"n":12,"t":"말하기를 \'내가 어찌하여 훈계(가르침)를 싫어하며, 내 마음이 꾸지람을 가벼이 여기고,"},{"n":13,"t":"내 선생의 목소리를 청종(듣고 따름)치 아니하며, 나를 가르치는 이에게 귀를 기울이지 아니하였던고?"},{"n":14,"t":"많은 무리들이 모인 중에서 모든 악에 거의 빠지게 되었었노라\' 하게 될까 하노라."},{"n":15,"t":"너는 네 우물에서 물을 마시며, 네 샘에서 흐르는 물을 마시라."},{"n":16,"t":"어찌하여 네 샘물을 집 밖으로 넘치게 하겠으며, 네 도랑물을 거리로 흘러가게 하겠느냐?"},{"n":17,"t":"그 물로 네게만 있게 하고, 타인(다른 사람)으로 더불어 그것을 나누지 말라."},{"n":18,"t":"네 샘으로 복되게 하라. 네가 젊어서 취(맞이)한 아내를 즐거워하라."},{"n":19,"t":"그는 사랑스러운 암사슴 같고, 아름다운 암노루 같으니, 너는 그 품을 항상 족(만족)하게 여기며, 그 사랑을 항상 연모(사랑함)하라."},{"n":20,"t":"내 아들아, 어찌하여 음녀(부도덕한 여인)를 연모(사랑함)하겠으며, 어찌하여 이방 계집(다른 나라 여인)의 가슴을 안겠느냐?"},{"n":21,"t":"대저(무릇) 사람의 길은 여호와의 눈 앞에 있나니, 그가 그 모든 길을 평탄(평평)케 하시느니라."},{"n":22,"t":"악인은 자기의 악에 걸리며, 그 죄의 줄에 매이나니,"},{"n":23,"t":"그는 훈계(가르침)를 받지 아니함을 인하여 죽겠고, 미련함이 많음을 인하여 혼미(어지러움)하게 되느니라."}]}},{"chapter":6,"title":"게으름과 유혹의 경계","verses":{"krv":[{"n":1,"t":"내 아들아 네가 만일 이웃을 위하여 담보하며 타인을 위하여 보증하였으면"},{"n":2,"t":"네 입의 말로 네가 얽혔으며 네 입의 말로 인하여 잡히게 되었느니라"},{"n":3,"t":"내 아들아 네가 네 이웃의 손에 빠졌은즉 이같이 하라 너는 곧 가서 겸손히 네 이웃에게 간구하여 스스로 구원하되"},{"n":4,"t":"네 눈으로 잠들게 하지 말며 눈꺼풀로 감기게 하지 말고"},{"n":5,"t":"노루가 사냥군의 손에서 벗어나는 것 같이 새가 그물 치는 자의 손에서 벗어나는 것 같이 스스로 구원하라"},{"n":6,"t":"게으른 자여 개미에게로 가서 그 하는 것을 보고 지혜를 얻으라"},{"n":7,"t":"개미는 두령도 없고 간역자도 없고 주권자도 없으되"},{"n":8,"t":"먹을 것을 여름 동안에 예비하며 추수 때에 양식을 모으느니라"},{"n":9,"t":"게으른 자여 네가 어느 때까지 눕겠느냐 네가 어느 때에 잠이 깨어 일어나겠느나"},{"n":10,"t":"좀더 자자, 좀더 졸자, 손을 모으고 좀더 눕자 하면"},{"n":11,"t":"네 빈궁이 강도 같이 오며 네 곤핍이 군사 같이 이르리라"},{"n":12,"t":"불량하고 악한 자는 그 행동에 궤휼한 입을 벌리며"},{"n":13,"t":"눈짓을 하며 발로 뜻을 보이며 손가락질로 알게 하며"},{"n":14,"t":"그 마음에 패역을 품으며 항상 악을 꾀하여 다툼을 일으키는자라"},{"n":15,"t":"그러므로 그 재앙이 갑자기 임한즉 도움을 얻지 못하고 당장에 패망하리라"},{"n":16,"t":"여호와의 미워하시는 것 곧 그 마음에 싫어하시는 것이 육 칠 가지니"},{"n":17,"t":"곧 교만한 눈과 거짓된 혀와 무죄한 자의 피를 흘리는 손과"},{"n":18,"t":"악한 계교를 꾀하는 마음과 빨리 악으로 달려가는 발과"},{"n":19,"t":"거짓을 말하는 망령된 증인과 및 형제 사이를 이간하는 자니라"},{"n":20,"t":"내 아들아 네 아비의 명령을 지키며 네 어미의 법을 떠나지 말고"},{"n":21,"t":"그것을 항상 네 마음에 새기며 네 목에 매라"},{"n":22,"t":"그것이 너의 다닐 때에 너를 인도하며 너의 잘 때에 너를 보호하며 너의 깰 때에 너로 더불어 말하리니"},{"n":23,"t":"대저 명령은 등불이요 법은 빛이요 훈계의 책망은 곧 생명의 길이라"},{"n":24,"t":"이것이 너를 지켜서 악한 계집에게, 이방 계집의 혀로 호리는 말에 빠지지 않게 하리라"},{"n":25,"t":"네 마음에 그 아름다운 색을 탐하지 말며 그 눈꺼풀에 홀리지 말라"},{"n":26,"t":"음녀로 인하여 사람이 한조각 떡만 남게 됨이며 음란한 계집은 귀한 생명을 사냥함이니라"},{"n":27,"t":"사람이 불을 품에 품고야 어찌 그 옷이 타지 아니하겠으며"},{"n":28,"t":"사람이 숯불을 밟고야 어찌 그 발이 데지 아니하겠느나"},{"n":29,"t":"남의 아내와 통간하는 자도 이와 같을 것이라 무릇 그를 만지기만 하는 자도 죄 없게 되지 아니하리라"},{"n":30,"t":"도적이 만일 주릴 때에 배를 채우려고 도적질하면 사람이 그를 멸시치는 아니하려니와"},{"n":31,"t":"들키면 칠배를 갚아야 하리니 심지어 자기 집에 있는 것을 다 내어주게 되리라"},{"n":32,"t":"부녀와 간음하는 자는 무지한 자라 이것을 행하는 자는 자기의 영혼을 망하게 하며"},{"n":33,"t":"상함과 능욕을 받고 부끄러움을 씻을 수 없게 되나니"},{"n":34,"t":"그 남편이 투기함으로 분노하여 원수를 갚는 날에 용서하지 아니하고"},{"n":35,"t":"아무 벌금도 돌아 보지 아니하며 많은 선물을 줄지라도 듣지 아니하리라"}],"kids":[{"n":1,"t":"내 아들아, 네가 만일 이웃을 위하여 담보하며, 타인(다른 사람)을 위하여 보증하였으면,"},{"n":2,"t":"네 입의 말로 네가 얽혔으며, 네 입의 말로 인하여 잡히게 되었느니라."},{"n":3,"t":"내 아들아, 네가 네 이웃의 손에 빠졌은즉 이같이 하라. 너는 곧 가서 겸손히 네 이웃에게 간구(부탁)하여 스스로 구원하되,"},{"n":4,"t":"네 눈으로 잠들게 하지 말며, 눈꺼풀로 감기게 하지 말고,"},{"n":5,"t":"노루가 사냥꾼의 손에서 벗어나는 것 같이, 새가 그물 치는 자의 손에서 벗어나는 것 같이 스스로 구원하라."},{"n":6,"t":"게으른 자여, 개미에게로 가서 그 하는 것을 보고 지혜를 얻으라."},{"n":7,"t":"개미는 두령(우두머리)도 없고, 간역자(감독)도 없고, 주권자(다스리는 자)도 없으되,"},{"n":8,"t":"먹을 것을 여름 동안에 예비(준비)하며, 추수 때에 양식을 모으느니라."},{"n":9,"t":"게으른 자여, 네가 어느 때까지 눕겠느냐? 네가 어느 때에 잠이 깨어 일어나겠느냐?"},{"n":10,"t":"\\"좀더 자자, 좀더 졸자, 손을 모으고 좀더 눕자\\" 하면,"},{"n":11,"t":"네 빈궁(가난)이 강도 같이 오며, 네 곤핍(어려움)이 군사 같이 이르리라."},{"n":12,"t":"불량(나쁘)하고 악한 자는 그 행동에 궤휼(속임)한 입을 벌리며,"},{"n":13,"t":"눈짓을 하며, 발로 뜻을 보이며, 손가락질로 알게 하며,"},{"n":14,"t":"그 마음에 패역(거역)을 품으며, 항상 악을 꾀하여 다툼을 일으키는 자라."},{"n":15,"t":"그러므로 그 재앙이 갑자기 임한즉, 도움을 얻지 못하고 당장에 패망(망함)하리라."},{"n":16,"t":"여호와의 미워하시는 것, 곧 그 마음에 싫어하시는 것이 육칠 가지니,"},{"n":17,"t":"곧 교만한 눈과, 거짓된 혀와, 무죄(죄 없는)한 자의 피를 흘리는 손과,"},{"n":18,"t":"악한 계교(꾀)를 꾀하는 마음과, 빨리 악으로 달려가는 발과,"},{"n":19,"t":"거짓을 말하는 망령(허망)된 증인과, 및 형제 사이를 이간(사이를 갈라놓음)하는 자니라."},{"n":20,"t":"내 아들아, 네 아비(아버지)의 명령을 지키며, 네 어미(어머니)의 법을 떠나지 말고,"},{"n":21,"t":"그것을 항상 네 마음에 새기며, 네 목에 매라."},{"n":22,"t":"그것이 너의 다닐 때에 너를 인도하며, 너의 잘 때에 너를 보호하며, 너의 깰 때에 너와 더불어 말하리니,"},{"n":23,"t":"대저(무릇) 명령은 등불이요 법은 빛이요, 훈계(가르침)의 책망(꾸짖음)은 곧 생명의 길이라."},{"n":24,"t":"이것이 너를 지켜서 악한 계집에게, 이방 계집(다른 나라 여인)의 혀로 호리는 말에 빠지지 않게 하리라."},{"n":25,"t":"네 마음에 그 아름다운 색을 탐(욕심내)하지 말며, 그 눈꺼풀에 홀리지 말라."},{"n":26,"t":"음녀(부도덕한 여인)로 인하여 사람이 한 조각 떡(빵)만 남게 됨이며, 음란한 계집은 귀한 생명을 사냥함이니라."},{"n":27,"t":"사람이 불을 품에 품고야 어찌 그 옷이 타지 아니하겠으며,"},{"n":28,"t":"사람이 숯불을 밟고야 어찌 그 발이 데지 아니하겠느냐?"},{"n":29,"t":"남의 아내와 통간(부정한 관계)하는 자도 이와 같을 것이라. 무릇 그를 만지기만 하는 자도 죄 없게 되지 아니하리라."},{"n":30,"t":"도적(도둑)이 만일 주릴(굶주릴) 때에 배를 채우려고 도적질하면, 사람이 그를 멸시(업신여김)치는 아니하려니와,"},{"n":31,"t":"들키면 칠 배(7배)를 갚아야 하리니, 심지어 자기 집에 있는 것을 다 내어주게 되리라."},{"n":32,"t":"부녀(다른 사람의 아내)와 간음(부부 외 사람과 잠자리 같이함)하는 자는 무지(앎이 없음)한 자라. 이것을 행하는 자는 자기의 영혼을 망하게 하며,"},{"n":33,"t":"상함과 능욕(욕보임)을 받고, 부끄러움을 씻을 수 없게 되나니,"},{"n":34,"t":"그 남편이 투기(질투)함으로 분노하여 원수를 갚는 날에 용서하지 아니하고,"},{"n":35,"t":"아무 벌금도 돌아보지 아니하며, 많은 선물을 줄지라도 듣지 아니하리라."}]}},{"chapter":7,"title":"지혜 없는 자의 위험","verses":{"krv":[{"n":1,"t":"내 아들아 내 말을 지키며 내 명령을 네게 간직하라"},{"n":2,"t":"내 명령을 지켜서 살며 내 법을 네 눈동자처럼 지키라"},{"n":3,"t":"이것을 네 손가락에 매며 이것을 네 마음판에 새기라"},{"n":4,"t":"지혜에게 너는 내 누이라 하며 명철에게 너는 내 친족이라 하라"},{"n":5,"t":"그리하면 이것이 너를 지켜서 음녀에게, 말로 호리는 이방 계집에게 빠지지 않게 하리라"},{"n":6,"t":"내가 내 집 들창으로, 살창으로 내어다보다가"},{"n":7,"t":"어리석은자 중에, 소년 중에 한 지혜 없는 자를 보았노라"},{"n":8,"t":"그가 거리를 지나 음녀의 골목 모퉁이로 가까이 하여 그 집으로 들어가는데"},{"n":9,"t":"저물 때, 황혼 때, 깊은밤 흑암 중에라"},{"n":10,"t":"그 때에 기생의 옷을 입은 간교한 계집이 그를 맞으니"},{"n":11,"t":"이 계집은 떠들며 완패하며 그 발이 집에 머물지 아니하여"},{"n":12,"t":"어떤 때에는 거리, 어떤 때에는 광장 모퉁이, 모퉁이에 서서 사람을 기다리는 자라"},{"n":13,"t":"그 계집이 그를 붙잡고 입을 맞추며 부끄러움을 모르는 얼굴로 말하되"},{"n":14,"t":"내가 화목제를 드려서 서원한 것을 오늘날 갚았노라"},{"n":15,"t":"이러므로 내가 너를 맞으려고 나와서 네 얼굴을 찾다가 너를 만났도다"},{"n":16,"t":"내 침상에는 화문 요와 애굽의 문채 있는 이불을 폈고"},{"n":17,"t":"몰약과 침향과 계피를 뿌렸노라"},{"n":18,"t":"오라 우리가 아침까지 흡족하게 서로 사랑하며 사랑함으로 희락 하자"},{"n":19,"t":"남편은 집을 떠나 먼 길을 갔는데"},{"n":20,"t":"은 주머니를 가졌은즉 보름에나 집에 돌아오리라 하여"},{"n":21,"t":"여러가지 고운 말로 혹하게 하며 입술의 호리는 말로 꾀므로"},{"n":22,"t":"소년이 곧 그를 따랐으니 소가 푸주로 가는 것 같고 미련한자가 벌을 받으려고 쇠사슬에 매이러 가는 것과 일반이라"},{"n":23,"t":"필경은 살이 그 간을 뚫기까지에 이를 것이라 새가 빨리 그물로 들어가되 그 생명을 잃어버릴 줄을 알지 못함과 일반이니라"},{"n":24,"t":"아들들아 나를 듣고 내 입의 말에 주의하라"},{"n":25,"t":"네 마음이 음녀의 길로 치우치지 말며 그 길에 미혹지 말지어다"},{"n":26,"t":"대저 그가 많은 사람을 상하여 엎드러지게 하였나니 그에게 죽은자가 허다하니라"},{"n":27,"t":"그 집은 음부의 길이라 사망의 방으로 내려가느니라"}],"kids":[{"n":1,"t":"내 아들아, 내 말을 지키며, 내 명령을 네게 간직하라."},{"n":2,"t":"내 명령을 지켜서 살며, 내 법을 네 눈동자처럼 지키라."},{"n":3,"t":"이것을 네 손가락에 매며, 이것을 네 마음판에 새기라."},{"n":4,"t":"지혜에게 \\"너는 내 누이라\\" 하며, 명철(슬기)에게 \\"너는 내 친족이라\\" 하라."},{"n":5,"t":"그리하면 이것이 너를 지켜서 음녀(부도덕한 여인)에게, 말로 호리는 이방 계집(다른 나라 여인)에게 빠지지 않게 하리라."},{"n":6,"t":"내가 내 집 들창으로, 살창(작은 창)으로 내어다보다가,"},{"n":7,"t":"어리석은 자 중에, 소년 중에 한 지혜 없는 자를 보았노라."},{"n":8,"t":"그가 거리를 지나 음녀(부도덕한 여인)의 골목 모퉁이로 가까이 하여 그 집으로 들어가는데,"},{"n":9,"t":"저물 때, 황혼 때, 깊은 밤 흑암(어두움) 중이라."},{"n":10,"t":"그 때에 기생의 옷을 입은 간교(꾀가 많은)한 계집이 그를 맞으니,"},{"n":11,"t":"이 계집은 떠들며 완패(고집부림)하며, 그 발이 집에 머물지 아니하여,"},{"n":12,"t":"어떤 때에는 거리, 어떤 때에는 광장 모퉁이, 모퉁이에 서서 사람을 기다리는 자라."},{"n":13,"t":"그 계집이 그를 붙잡고 입을 맞추며, 부끄러움을 모르는 얼굴로 말하되,"},{"n":14,"t":"\\"내가 화목제(화평을 위한 제사)를 드려서 서원(맹세 약속)한 것을 오늘날 갚았노라."},{"n":15,"t":"이러므로 내가 너를 맞으려고 나와서 네 얼굴을 찾다가 너를 만났도다."},{"n":16,"t":"내 침상(잠자리)에는 화문(꽃무늬) 요와 애굽(이집트)의 문채(무늬) 있는 이불을 폈고,"},{"n":17,"t":"몰약과 침향과 계피(향료)를 뿌렸노라."},{"n":18,"t":"오라, 우리가 아침까지 흡족하게 서로 사랑하며, 사랑함으로 희락(기쁨)하자."},{"n":19,"t":"남편은 집을 떠나 먼 길을 갔는데,"},{"n":20,"t":"은 주머니를 가졌은즉 보름에나 집에 돌아오리라\\" 하여,"},{"n":21,"t":"여러 가지 고운 말로 혹(홀)하게 하며, 입술의 호리는 말로 꾀므로,"},{"n":22,"t":"소년이 곧 그를 따랐으니, 소가 푸주(고기 파는 곳)로 가는 것 같고, 미련한 자가 벌을 받으려고 쇠사슬에 매이러 가는 것과 일반(같음)이라."},{"n":23,"t":"필경은(결국은) 살(화살)이 그 간을 뚫기까지에 이를 것이라. 새가 빨리 그물로 들어가되 그 생명을 잃어버릴 줄을 알지 못함과 일반(같음)이니라."},{"n":24,"t":"아들들아, 나를 듣고 내 입의 말에 주의하라."},{"n":25,"t":"네 마음이 음녀(부도덕한 여인)의 길로 치우치지 말며, 그 길에 미혹지 말지어다."},{"n":26,"t":"대저(무릇) 그가 많은 사람을 상하여 엎드러지게 하였나니, 그에게 죽은 자가 허다(매우 많음)하니라."},{"n":27,"t":"그 집은 음부(죽은 자의 곳)의 길이라. 사망(죽음)의 방으로 내려가느니라."}]}},{"chapter":8,"title":"지혜의 초청","verses":{"krv":[{"n":1,"t":"지혜가 부르지 아니하느냐 명철이 소리를 높이지 아니하느냐"},{"n":2,"t":"그가 길가의 높은 곳과 사거리에 서며"},{"n":3,"t":"성문 곁과 문 어귀와 여러 출입하는 문에서 불러 가로되"},{"n":4,"t":"사람들아 내가 너희를 부르며 내가 인자들에게 소리를 높이노라"},{"n":5,"t":"어리석은 자들아 너희는 명철할지니라 미련한 자들아 너희는 마음이 밝을지니라 너희는 들을지어다"},{"n":6,"t":"내가 가장 선한 것을 말하리라 내 입술을 열어 정직을 내리라"},{"n":7,"t":"내 입은 진리를 말하며 내 입술은 악을 미워하느니라"},{"n":8,"t":"내 입의 말은 다 의로운즉 그 가운데 굽은 것과 패역한 것이 없나니"},{"n":9,"t":"이는 다 총명 있는 자의 밝히 아는 바요 지식 얻은 자의 정직히 여기는 바니라"},{"n":10,"t":"너희가 은을 받지 말고 나의 훈계를 받으며 정금보다 지식을 얻으라"},{"n":11,"t":"대저 지혜는 진주보다 나으므로 무릇 원하는 것을 이에 비교할 수 없음이니라"},{"n":12,"t":"나 지혜는 명철로 주소를 삼으며 지식과 근신을 찾아 얻나니"},{"n":13,"t":"여호와를 경외하는 것은 악을 미워하는 것이라 나는 교만과 거만과 악한 행실과 패역한 입을 미워하느니라"},{"n":14,"t":"내게는 도략과 참 지식이 있으며 나는 명철이라 내게 능력이 있으므로"},{"n":15,"t":"나로 말미암아 왕들이 치리하며 방백들이 공의를 세우며"},{"n":16,"t":"나로 말미암아 재상과 존귀한자 곧 세상의 모든 재판관들이 다스리느니라"},{"n":17,"t":"나를 사랑하는 자들이 나의 사랑을 입으며 나를 간절히 찾는 자가 나를 만날 것이니라"},{"n":18,"t":"부귀가 내게 있고 장구한 재물과 의도 그러하니라"},{"n":19,"t":"내 열매는 금이나 정금보다 나으며 내 소득은 천은보다 나으니라"},{"n":20,"t":"나는 의로운 길로 행하며 공평한 길 가운데로 다니나니"},{"n":21,"t":"이는 나를 사랑하는 자로 재물을 얻어서 그 곳간에 채우게 하려 함이니라"},{"n":22,"t":"여호와께서 그 조화의 시작 곧 태초에 일하시기 전에 나를 가지셨으며"},{"n":23,"t":"만세 전부터 상고부터, 땅이 생기기 전부터, 내가 세움을 입었나니"},{"n":24,"t":"아직 바다가 생기지 아니하였고 큰 샘들이 있기 전에 내가 이미 났으며"},{"n":25,"t":"산이 세우심을 입기 전에 언덕이 생기기 전에 내가 이미 났으니"},{"n":26,"t":"하나님이 아직 땅도 들도 세상 진토의 근원도 짓지 아니하셨을 때에라"},{"n":27,"t":"그가 하늘을 지으시며 궁창으로 해면에 두르실 때에 내가 거기 있었고"},{"n":28,"t":"그가 위로 구름 하늘을 견고하게 하시며 바다의 샘들을 힘있게 하시며"},{"n":29,"t":"바다의 한계를 정하여 물로 명령을 거스리지 못하게 하시며 또 땅의 기초를 정하실 때에"},{"n":30,"t":"내가 그 곁에 있어서 창조자가 되어 날마다 그 기뻐하신 바가 되었으며 항상 그 앞에서 즐거워하였으며"},{"n":31,"t":"사람이 거처할 땅에서 즐거워하며 인자들을 기뻐하였었느니라"},{"n":32,"t":"아들들아 이제 내게 들으라 내 도를 지키는 자가 복이 있느니라"},{"n":33,"t":"훈계를 들어서 지혜를 얻으라 그것을 버리지 말라"},{"n":34,"t":"누구든지 내게 들으며 날마다 내 문 곁에서 기다리며 문설주 옆에서 기다리는 자는 복이 있나니"},{"n":35,"t":"대저 나를 얻는 자는 생명을 얻고 여호와께 은총을 얻을 것임이니라"},{"n":36,"t":"그러나 나를 잃는 자는 자기의 영혼을 해하는 자라 무릇 나를 미워하는 자는 사망을 사랑하느니라"}],"kids":[{"n":1,"t":"지혜가 부르지 아니하느냐? 명철(슬기)이 소리를 높이지 아니하느냐?"},{"n":2,"t":"그가 길가의 높은 곳과 사거리에 서며,"},{"n":3,"t":"성문 곁과 문 어귀와 여러 출입하는 문에서 불러 말하기를,"},{"n":4,"t":"\\"사람들아, 내가 너희를 부르며, 내가 인자(사람의 아들)들에게 소리를 높이노라."},{"n":5,"t":"어리석은 자들아, 너희는 명철(슬기)할지니라. 미련한 자들아, 너희는 마음이 밝을지니라. 너희는 들을지어다."},{"n":6,"t":"내가 가장 선한 것을 말하리라. 내 입술을 열어 정직(올바름)을 내리라."},{"n":7,"t":"내 입은 진리를 말하며, 내 입술은 악을 미워하느니라."},{"n":8,"t":"내 입의 말은 다 의로운즉, 그 가운데 굽은 것과 패역(거역)한 것이 없나니,"},{"n":9,"t":"이는 다 총명(슬기) 있는 자의 밝히 아는 바요, 지식 얻은 자의 정직(올바름)히 여기는 바니라."},{"n":10,"t":"너희가 은을 받지 말고 나의 훈계(가르침)를 받으며, 정금(순금)보다 지식을 얻으라."},{"n":11,"t":"대저(무릇) 지혜는 진주보다 나으므로, 무릇 원하는 것을 이에 비교할 수 없음이니라."},{"n":12,"t":"나 지혜는 명철(슬기)로 주소(머무는 곳)를 삼으며, 지식과 근신(조심함)을 찾아 얻나니,"},{"n":13,"t":"여호와를 경외(존경하고 두려워)하는 것은 악을 미워하는 것이라. 나는 교만과 거만과 악한 행실과 패역(거역)한 입을 미워하느니라."},{"n":14,"t":"내게는 도략(꾀)과 참 지식이 있으며, 나는 명철(슬기)이라. 내게 능력이 있으므로,"},{"n":15,"t":"나로 말미암아 왕들이 치리(다스림)하며, 방백(높은 관리)들이 공의(옳음)를 세우며,"},{"n":16,"t":"나로 말미암아 재상(높은 관리)과 존귀(귀)한 자, 곧 세상의 모든 재판관들이 다스리느니라."},{"n":17,"t":"나를 사랑하는 자들이 나의 사랑을 입으며, 나를 간절히 찾는 자가 나를 만날 것이니라."},{"n":18,"t":"부귀(부유함과 귀함)가 내게 있고, 장구(오래 가는)한 재물과 의도 그러하니라."},{"n":19,"t":"내 열매는 금이나 정금(순금)보다 나으며, 내 소득은 천은(좋은 은)보다 나으니라."},{"n":20,"t":"나는 의로운 길로 행하며, 공평한 길 가운데로 다니나니,"},{"n":21,"t":"이는 나를 사랑하는 자로 재물을 얻어서 그 곳간(창고)에 채우게 하려 함이니라."},{"n":22,"t":"여호와께서 그 조화(만드심)의 시작, 곧 태초에 일하시기 전에 나를 가지셨으며,"},{"n":23,"t":"만세(영원) 전부터, 상고(아주 옛날)부터, 땅이 생기기 전부터, 내가 세움을 입었나니,"},{"n":24,"t":"아직 바다가 생기지 아니하였고, 큰 샘들이 있기 전에 내가 이미 났으며,"},{"n":25,"t":"산이 세우심을 입기 전에, 언덕이 생기기 전에 내가 이미 났으니,"},{"n":26,"t":"하나님이 아직 땅도, 들도, 세상 진토(흙)의 근원도 짓지 아니하셨을 때라."},{"n":27,"t":"그가 하늘을 지으시며, 궁창(하늘)으로 해면(바다 표면)에 두르실 때에 내가 거기 있었고,"},{"n":28,"t":"그가 위로 구름 하늘을 견고(굳게)하게 하시며, 바다의 샘들을 힘있게 하시며,"},{"n":29,"t":"바다의 한계를 정하여 물로 명령을 거스르지 못하게 하시며, 또 땅의 기초를 정하실 때에,"},{"n":30,"t":"내가 그 곁에 있어서 창조자가 되어, 날마다 그 기뻐하신 바가 되었으며, 항상 그 앞에서 즐거워하였으며,"},{"n":31,"t":"사람이 거처(살 곳)할 땅에서 즐거워하며, 인자(사람의 아들)들을 기뻐하였느니라."},{"n":32,"t":"아들들아, 이제 내게 들으라. 내 도(가르침)를 지키는 자가 복이 있느니라."},{"n":33,"t":"훈계(가르침)를 들어서 지혜를 얻으라. 그것을 버리지 말라."},{"n":34,"t":"누구든지 내게 들으며, 날마다 내 문 곁에서 기다리며, 문설주(문기둥) 옆에서 기다리는 자는 복이 있나니,"},{"n":35,"t":"대저(무릇) 나를 얻는 자는 생명을 얻고, 여호와께 은총을 얻을 것임이니라."},{"n":36,"t":"그러나 나를 잃는 자는 자기의 영혼을 해(상하게)하는 자라. 무릇 나를 미워하는 자는 사망(죽음)을 사랑하느니라.\\""}]}},{"chapter":9,"title":"지혜와 어리석음","verses":{"krv":[{"n":1,"t":"지혜가 그 집을 짓고 일곱 기둥을 다듬고"},{"n":2,"t":"짐승을 잡으며 포도주를 혼합하여 상을 갖추고"},{"n":3,"t":"그 여종을 보내어 성중 높은 곳에서 불러 이르기를"},{"n":4,"t":"무릇 어리석은 자는 이리로 돌이키라 또 지혜 없는 자에게 이르기를"},{"n":5,"t":"너는 와서 내 식물을 먹으며 내 혼합한 포도주를 마시고"},{"n":6,"t":"어리석음을 버리고 생명을 얻으라 명철의 길을 행하라 하느니라"},{"n":7,"t":"거만한 자를 징계하는 자는 도리어 능욕을 받고 악인을 책망하는자는 도리어 흠을 잡히느니라"},{"n":8,"t":"거만한 자를 책망하지 말라 그가 너를 미워할까 두려우니라 지혜있는 자를 책망하라 그가 너를 사랑하리라"},{"n":9,"t":"지혜 있는 자에게 교훈을 더하라 그가 더욱 지혜로와질 것이요 의로운 사람을 가르치라 그의 학식이 더하리라"},{"n":10,"t":"여호와를 경외하는 것이 지혜의 근본이요 거룩하신 자를 아는 것이 명철이니라"},{"n":11,"t":"나 지혜로 말미암아 네 날이 많아질 것이요 네 생명의 해가 더하리라"},{"n":12,"t":"네가 만일 지혜로우면 그 지혜가 네게 유익할 것이나 네가 만일 거만하면 너 홀로 해를 당하리라"},{"n":13,"t":"미련한 계집이 떠들며 어리석어서 아무 것도 알지 못하고"},{"n":14,"t":"자기 집 문에 앉으며 성읍 높은 곳에 있는 자리에 앉아서"},{"n":15,"t":"자기 길을 바로 가는 행객을 불러 이르되"},{"n":16,"t":"무릇 어리석은 자는 이리로 돌이키라 또 지혜없는 자에게 이르기를"},{"n":17,"t":"도적질한 물이 달고 몰래 먹는 떡이 맛이 있다 하는도다"},{"n":18,"t":"오직 그 어리석은 자는 죽은 자가 그의 곳에 있는 것과 그의 객들이 음부 깊은 곳에 있는 것을 알지 못하느니라"}],"kids":[{"n":1,"t":"지혜가 그 집을 짓고, 일곱 기둥을 다듬고,"},{"n":2,"t":"짐승을 잡으며, 포도주를 혼합(섞)하여 상을 갖추고,"},{"n":3,"t":"그 여종을 보내어 성중(성 안) 높은 곳에서 불러 이르기를,"},{"n":4,"t":"\\"무릇 어리석은 자는 이리로 돌이키라\\" 또 지혜 없는 자에게 이르기를,"},{"n":5,"t":"\\"너는 와서 내 식물(음식)을 먹으며, 내 혼합(섞은)한 포도주를 마시고,"},{"n":6,"t":"어리석음을 버리고 생명을 얻으라. 명철(슬기)의 길을 행하라\\" 하느니라."},{"n":7,"t":"거만한 자를 징계(가르침의 벌)하는 자는 도리어 능욕(욕보임)을 받고, 악인을 책망(꾸짖음)하는 자는 도리어 흠을 잡히느니라."},{"n":8,"t":"거만한 자를 책망(꾸짖음)하지 말라. 그가 너를 미워할까 두려우니라. 지혜 있는 자를 책망하라. 그가 너를 사랑하리라."},{"n":9,"t":"지혜 있는 자에게 교훈(가르침)을 더하라. 그가 더욱 지혜로와질 것이요, 의로운 사람을 가르치라. 그의 학식이 더하리라."},{"n":10,"t":"여호와를 경외(존경하고 두려워)하는 것이 지혜의 근본(뿌리)이요, 거룩하신 자를 아는 것이 명철(슬기)이니라."},{"n":11,"t":"나 지혜로 말미암아 네 날이 많아질 것이요, 네 생명의 해가 더하리라."},{"n":12,"t":"네가 만일 지혜로우면 그 지혜가 네게 유익할 것이나, 네가 만일 거만하면 너 홀로 해를 당하리라."},{"n":13,"t":"미련한 계집이 떠들며, 어리석어서 아무 것도 알지 못하고,"},{"n":14,"t":"자기 집 문에 앉으며, 성읍 높은 곳에 있는 자리에 앉아서,"},{"n":15,"t":"자기 길을 바로 가는 행객(나그네)을 불러 이르되,"},{"n":16,"t":"\\"무릇 어리석은 자는 이리로 돌이키라\\" 또 지혜 없는 자에게 이르기를,"},{"n":17,"t":"\\"도적질(훔친)한 물이 달고, 몰래 먹는 떡이 맛이 있다\\" 하는도다."},{"n":18,"t":"오직 그 어리석은 자는 죽은 자가 그의 곳에 있는 것과, 그의 객(손님)들이 음부(죽은 자의 곳) 깊은 곳에 있는 것을 알지 못하느니라."}]}},{"chapter":10,"title":"솔로몬의 잠언","verses":{"krv":[{"n":1,"t":"솔로몬의 잠언이라 지혜로운 아들은 아비로 기쁘게 하거니와 미련한 아들은 어미의 근심이니라"},{"n":2,"t":"불의의 재물은 무익하여도 의리는 죽음에서 건지느니라"},{"n":3,"t":"여호와께서 의인의 영혼은 주리지 않게 하시나 악인의 소욕은 물리치시느니라"},{"n":4,"t":"손을 게으르게 놀리는 자는 가난하게 되고 손이 부지런한 자는 부하게 되느니라"},{"n":5,"t":"여름에 거두는 자는 지혜로운 아들이나 추수 때에 자는 자는 부끄러움을 끼치는 아들이니라"},{"n":6,"t":"의인의 머리에는 복이 임하거늘 악인의 입은 독을 머금었느니라"},{"n":7,"t":"의인을 기념할 때에는 칭찬하거니와 악인의 이름은 썩으리라"},{"n":8,"t":"마음이 지혜로운 자는 명령을 받거니와 입이 미련한 자는 패망하리라"},{"n":9,"t":"바른 길로 행하는 자는 걸음이 평안하려니와 굽은 길로 행하는 자는 드러나리라"},{"n":10,"t":"눈짓하는 자는 근심을 끼치고 입이 미련한 자는 패망하느니라"},{"n":11,"t":"의인의 입은 생명의 샘이라도 악인의 입은 독을 머금었느니라"},{"n":12,"t":"미움은 다툼을 일으켜도 사랑은 모든 허물을 가리우느니라"},{"n":13,"t":"명철한 자의 입술에는 지혜가 있어도 지혜 없는 자의 등을 위하여는 채찍이 있느니라"},{"n":14,"t":"지혜로운 자는 지식을 간직하거니와 미련한 자의 입은 멸망에 가까우니라"},{"n":15,"t":"부자의 재물은 그의 견고한 성이요 가난한 자의 궁핍은 그의 패망이니라"},{"n":16,"t":"의인의 수고는 생명에 이르고 악인의 소득은 죄에 이르느니라"},{"n":17,"t":"훈계를 지키는 자는 생명길로 행하여도 징계를 버리는 자는 그릇가느니라"},{"n":18,"t":"미워함을 감추는 자는 거짓의 입술을 가진 자요 참소하는 자는 미련한 자니라"},{"n":19,"t":"말이 많으면 허물을 면키 어려우나 그 입술을 제어하는 자는 지혜가 있느니라"},{"n":20,"t":"의인의 혀는 천은과 같거니와 악인의 마음은 가치가 적으니라"},{"n":21,"t":"의인의 입술은 여러 사람을 교육하나 미련한 자는 지식이 없으므로 죽느니라"},{"n":22,"t":"여호와께서 복을 주시므로 사람으로 부하게 하시고 근심을 겸하여 주지 아니하시느니라"},{"n":23,"t":"미련한 자는 행악으로 낙을 삼는 것 같이 명철한 자는 지혜로 낙을 삼느니라"},{"n":24,"t":"악인에게는 그의 두려워하는 것이 임하거니와 의인은 그 원하는 것이 이루어지느니라"},{"n":25,"t":"회리바람이 지나가면 악인은 없어져도 의인은 영원한 기초 같으니라"},{"n":26,"t":"게으른 자는 그 부리는 사람에게 마치 이에 초 같고 눈에 연기 같으니라"},{"n":27,"t":"여호와를 경외하면 장수하느니라 그러나 악인의 연세는 짧아지느니라"},{"n":28,"t":"의인의 소망은 즐거움을 이루어도 악인의 소망은 끊어지느니라"},{"n":29,"t":"여호와의 도가 정직한 자에게는 산성이요 행악하는 자에게는 멸망이니라"},{"n":30,"t":"의인은 영영히 이동되지 아니하여도 악인은 땅에 거하지 못하게 되느니라"},{"n":31,"t":"의인의 입은 지혜를 내어도 패역한 혀는 베임을 당할 것이니라"},{"n":32,"t":"의인의 입술은 기쁘게 할 것을 알거늘 악인의 입은 패역을 말하느니라"}],"kids":[{"n":1,"t":"이것은 솔로몬의 잠언이에요. 지혜로운 아들은 아빠를 기쁘게 하지만 어리석은 아들은 엄마의 근심거리가 돼요."},{"n":2,"t":"옳지 않은 방법으로 얻은 재물은 아무 도움이 안 되지만 의롭게 사는 것은 죽음에서도 건져 줘."},{"n":3,"t":"하나님은 옳은 사람이 굶주리지 않게 하시지만 나쁜 사람이 바라는 것은 채워 주지 않으셔."},{"n":4,"t":"손을 게으르게 놀리는 사람은 가난해지지만 부지런히 손을 움직이는 사람은 풍족해진단다."},{"n":5,"t":"여름에 부지런히 거두는 사람은 지혜로운 아들이고 추수 때에 잠만 자는 사람은 부모를 부끄럽게 하는 아들이야."},{"n":6,"t":"옳게 사는 사람의 머리에는 복이 내리지만 나쁜 사람의 입에는 독이 가득해."},{"n":7,"t":"옳은 사람을 기억할 때는 칭찬이 따르지만 나쁜 사람의 이름은 곧 잊혀지고 말지."},{"n":8,"t":"마음이 지혜로운 사람은 가르침을 잘 받아들이지만 입이 가벼운 어리석은 사람은 결국 무너지게 돼."},{"n":9,"t":"바른 길로 가는 사람은 마음이 편안하지만 굽은 길로 가는 사람은 결국 그 잘못이 드러나게 돼."},{"n":10,"t":"못된 눈짓을 하는 사람은 다른 사람에게 걱정을 끼치고 함부로 말하는 어리석은 사람은 결국 망하게 돼."},{"n":11,"t":"옳은 사람의 입은 생명을 주는 샘 같지만 나쁜 사람의 입은 독을 품고 있어."},{"n":12,"t":"미움은 다툼을 일으키지만 사랑은 모든 잘못을 덮어 준단다."},{"n":13,"t":"깨달은 사람의 입술에는 지혜가 있지만 분별 없는 사람의 등에는 매가 따른단다."},{"n":14,"t":"지혜로운 사람은 지식을 마음에 잘 간직하지만 어리석은 사람의 입은 화를 부른단다."},{"n":15,"t":"부자의 재산은 든든한 성벽 같지만 가난한 사람의 어려움은 그를 무너뜨릴 수도 있어."},{"n":16,"t":"옳은 사람이 일해서 얻는 것은 생명으로 이어지지만 나쁜 사람이 얻는 것은 죄로 이어져."},{"n":17,"t":"가르침을 잘 지키는 사람은 생명의 길로 가지만 충고를 무시하는 사람은 길을 잃게 돼."},{"n":18,"t":"미움을 감추는 사람은 거짓말하는 사람이고 다른 사람을 흉보고 다니는 사람은 어리석은 사람이야."},{"n":19,"t":"말이 많으면 잘못을 피하기 어려워. 입을 잘 다스리는 사람이 지혜로운 사람이야."},{"n":20,"t":"옳은 사람의 말은 순은처럼 귀하지만 나쁜 사람의 마음은 값이 별로 없어."},{"n":21,"t":"옳은 사람의 입은 여러 사람을 잘 가르치지만 어리석은 사람은 분별이 없어서 결국 망하게 돼."},{"n":22,"t":"하나님이 복을 주시면 사람이 부유해지는데 거기에 걱정을 함께 주지는 않으셔."},{"n":23,"t":"어리석은 사람은 나쁜 짓을 즐거움으로 삼지만 분별 있는 사람은 지혜를 즐거움으로 삼는단다."},{"n":24,"t":"나쁜 사람에게는 두려워하던 일이 결국 닥쳐오지만 옳은 사람에게는 바라는 좋은 일이 이루어져."},{"n":25,"t":"거센 바람이 한번 지나가면 나쁜 사람은 흔적도 없이 사라지지만 옳은 사람은 영원한 기초처럼 굳건히 서 있어."},{"n":26,"t":"게으른 사람은 그를 일 시키는 사람에게 이에 시린 식초 같고 눈에 들어오는 연기 같단다."},{"n":27,"t":"하나님을 두려워하고 공경하면 오래 살게 되지만 나쁜 사람의 삶은 짧아지게 돼."},{"n":28,"t":"옳은 사람이 바라는 것은 기쁨으로 이루어지지만 나쁜 사람이 바라는 것은 결국 끊어지고 말지."},{"n":29,"t":"하나님의 길은 정직한 사람에게는 든든한 요새지만 나쁜 일을 하는 사람에게는 무너지는 자리야."},{"n":30,"t":"옳은 사람은 영원히 흔들리지 않지만 나쁜 사람은 그 땅에 머물 수 없게 돼."},{"n":31,"t":"옳은 사람의 입은 지혜를 내놓지만 비뚤어진 말을 하는 혀는 결국 잘리고 말 거야."},{"n":32,"t":"옳은 사람의 입술은 좋은 말을 할 줄 알지만 나쁜 사람의 입은 비뚤어진 말만 한단다."}]}},{"chapter":11,"title":"의인의 길","verses":{"krv":[{"n":1,"t":"속이는 저울은 여호와께서 미워하셔도 공평한 추는 그가 기뻐하시느니라"},{"n":2,"t":"교만이 오면 욕도 오거니와 겸손한 자에게는 지혜가 있느니라"},{"n":3,"t":"정직한 자의 성실은 자기를 인도하거니와 사특한 자의 패역은 자기를 망케하느니라"},{"n":4,"t":"재물은 진노하시는 날에 무익하나 의리는 죽음을 면케 하느니라"},{"n":5,"t":"완전한 자는 그 의로 인하여 그 길이 곧게 되려니와 악한 자는 그 악을 인하여 넘어지리라"},{"n":6,"t":"정직한 자는 그 의로 인하여 구원을 얻으려니와 사특한 자는 자기의 악에 잡히리라"},{"n":7,"t":"악인은 죽을 때에 그 소망이 끊어지나니 불의의 소망이 없어지느니라"},{"n":8,"t":"의인은 환난에서 구원을 얻고 악인은 와서 그를 대신하느니라"},{"n":9,"t":"사특한 자는 입으로 그 이웃을 망하게 하여도 의인은 그 지식으로 말미암아 구원을 얻느니라"},{"n":10,"t":"의인이 형통하면 성읍이 즐거워하고 악인이 패망하면 기뻐 외치느니라"},{"n":11,"t":"성읍은 정직한 자의 축원을 인하여 진흥하고 악한 자의 입을 인하여 무너지느니라"},{"n":12,"t":"지혜 없는 자는 그 이웃을 멸시하나 명철한 자는 잠잠하느니라"},{"n":13,"t":"두루 다니며 한담하는 자는 남의 비밀을 누설하나 마음이 신실한자는 그런 것을 숨기느니라"},{"n":14,"t":"도략이 없으면 백성이 망하여도 모사가 많으면 평안을 누리느니라"},{"n":15,"t":"타인을 위하여 보증이 되는 자는 손해를 당하여도 보증이 되기를 싫어하는 자는 평안하니라"},{"n":16,"t":"유덕한 여자는 존영을 얻고 근면한 남자는 재물을 얻느니라"},{"n":17,"t":"인자한 자는 자기의 영혼을 이롭게 하고 잔인한 자는 자기의 몸을 해롭게 하느니라"},{"n":18,"t":"악인의 삯은 허무하되 의를 뿌린 자의 상은 확실하니라"},{"n":19,"t":"의를 굳게 지키는 자는 생명에 이르고 악을 따르는 자는 사망에 이르느니라"},{"n":20,"t":"마음이 패려한 자는 여호와의 미움을 받아도 행위가 온전한 자는 그의 기뻐하심을 받느니라"},{"n":21,"t":"악인은 피차 손을 잡을지라도 벌을 면치 못할 것이나 의인의 자손은 구원을 얻으리라"},{"n":22,"t":"아름다운 여인이 삼가지 아니하는 것은 마치 돼지 코에 금고리 같으니라"},{"n":23,"t":"의인의 소원은 오직 선하나 악인의 소망은 진노를 이루느니라"},{"n":24,"t":"흩어 구제하여도 더욱 부하게 되는 일이 있나니 과도히 아껴도 가난하게 될 뿐이니라"},{"n":25,"t":"구제를 좋아하는 자는 풍족하여질 것이요 남을 윤택하게 하는 자는 윤택하여지리라"},{"n":26,"t":"곡식을 내지 아니하는 자는 백성에게 저주를 받을 것이나 파는 자는 그 머리에 복이 임하리라"},{"n":27,"t":"선을 간절히 구하는 자는 은총을 얻으려니와 악을 더듬어 찾는 자에게는 악이 임하리라"},{"n":28,"t":"자기의 재물을 의지하는 자는 패망하려니와 의인은 푸른 잎사귀 같아서 번성하리라"},{"n":29,"t":"자기 집을 해롭게 하는 자의 소득은 바람이라 미련한 자는 마음이 지혜로운 자의 종이 되리라"},{"n":30,"t":"의인의 열매는 생명나무라 지혜로운 자는 사람을 얻느니라"},{"n":31,"t":"보라 의인이라도 이 세상에서 보응을 받겠거든 하물며 악인과 죄인이리요"}],"kids":[{"n":1,"t":"속이는 저울을 하나님이 싫어하시지만 정확한 저울추는 하나님이 기뻐하셔."},{"n":2,"t":"잘난 척하면 부끄러움이 따라오지만 겸손한 사람에게는 지혜가 함께해."},{"n":3,"t":"정직한 사람의 진실함은 자기를 좋은 길로 이끌지만 비뚤어진 사람의 거짓은 자기를 망치게 해."},{"n":4,"t":"어려운 날이 닥치면 재물도 소용없지만 옳게 사는 것은 죽음에서도 건져 주지."},{"n":5,"t":"바르게 사는 사람은 자기 길을 곧게 만들지만 나쁜 사람은 자기가 한 잘못 때문에 넘어져."},{"n":6,"t":"정직한 사람의 의로움이 자기를 구해 주지만 못된 사람은 자기 잘못에 자기가 걸려 넘어져."},{"n":7,"t":"나쁜 사람은 죽을 때 모든 희망이 끊어지고 잘못된 길에서 바라던 것도 다 사라져 버려."},{"n":8,"t":"옳은 사람은 어려움에서 구원받지만 나쁜 사람은 결국 그 어려움 속으로 들어가게 돼."},{"n":9,"t":"못된 사람은 말 한마디로 이웃을 망하게 하지만 옳은 사람은 지혜로 어려움에서 빠져나와."},{"n":10,"t":"옳은 사람이 잘되면 마을이 다 함께 기뻐하고 나쁜 사람이 망하면 사람들이 환호하지."},{"n":11,"t":"마을은 정직한 사람의 축복으로 잘 자라지만 나쁜 사람의 말 때문에 무너지기도 해."},{"n":12,"t":"분별 없는 사람은 이웃을 함부로 무시하지만 깨달은 사람은 조용히 입을 다물 줄 알아."},{"n":13,"t":"여기저기 다니며 수다 떠는 사람은 비밀을 흘려 버리지만 마음이 진실한 사람은 비밀을 잘 지켜."},{"n":14,"t":"좋은 조언이 없으면 백성이 흔들리지만 좋은 조언이 많으면 평안을 누리게 돼."},{"n":15,"t":"모르는 사람의 보증을 함부로 서면 손해를 보지만 보증 서기를 싫어하는 사람은 안전해."},{"n":16,"t":"마음이 고운 여자는 존경을 받고 부지런한 남자는 재물을 얻어."},{"n":17,"t":"다른 사람에게 친절한 사람은 자기에게도 좋은 일이 생기지만 사납고 모진 사람은 자기를 다치게 해."},{"n":18,"t":"나쁜 사람이 받는 보상은 헛되지만 의롭게 살아가는 사람은 분명한 상을 받아."},{"n":19,"t":"의로움을 굳게 지키면 생명에 이르지만 나쁜 길을 따라가면 죽음에 이르게 돼."},{"n":20,"t":"마음이 비뚤어진 사람은 하나님이 싫어하시지만 바르게 사는 사람은 하나님이 기뻐하셔."},{"n":21,"t":"나쁜 사람들이 손을 맞잡는다 해도 벌을 피할 수는 없지만 옳은 사람의 자손은 구원을 얻게 돼."},{"n":22,"t":"분별 없는 예쁜 여자는 마치 돼지 코에 끼운 금 고리 같단다."},{"n":23,"t":"옳은 사람의 바람은 오직 좋은 것이지만 나쁜 사람의 바람은 결국 벌로 끝나."},{"n":24,"t":"나누어 주어도 더 부유해지는 사람이 있고 너무 인색하게 굴어도 오히려 가난해지는 사람이 있어."},{"n":25,"t":"즐겁게 나누는 사람은 풍성해지고 다른 사람을 도와주는 사람은 자기도 좋아져."},{"n":26,"t":"곡식을 쌓아 두기만 하는 사람은 사람들의 미움을 받지만 필요할 때 파는 사람은 머리에 복을 받아."},{"n":27,"t":"좋은 일을 부지런히 찾는 사람은 사랑을 받지만 나쁜 일을 찾아다니는 사람에게는 나쁜 일이 찾아와."},{"n":28,"t":"재물만 의지하는 사람은 결국 무너지지만 옳은 사람은 푸른 잎사귀처럼 잘 자라."},{"n":29,"t":"자기 가족을 힘들게 하는 사람은 결국 아무것도 얻지 못하고 어리석은 사람은 지혜로운 사람의 일꾼이 될 거야."},{"n":30,"t":"옳은 사람이 맺는 열매는 생명의 나무 같고 지혜로운 사람은 다른 사람의 마음을 얻어."},{"n":31,"t":"옳은 사람도 이 세상에서 자기 행동의 결과를 받는데 하물며 나쁜 짓을 하는 사람은 어떻겠니?"}]}},{"chapter":12,"title":"훈계와 지식","verses":{"krv":[{"n":1,"t":"훈계를 좋아하는 자는 지식을 좋아하나니 징계를 싫어하는 자는 짐승과 같으니라"},{"n":2,"t":"선인은 여호와께 은총을 받으려니와 악을 꾀하는 자는 정죄하심을 받으리라"},{"n":3,"t":"사람이 악으로 굳게 서지 못하나니 의인의 뿌리는 움직이지 아니하느니라"},{"n":4,"t":"어진 여인은 그 지아비의 면류관이나 욕을 끼치는 여인은 그 지아비로 뼈가 썩음 같게 하느니라"},{"n":5,"t":"의인의 생각은 공직하여도 악인의 도모는 궤휼이니라"},{"n":6,"t":"악인의 말은 사람을 엿보아 피를 흘리자 하는 것이어니와 정직한 자의 입은 사람을 구원하느니라"},{"n":7,"t":"악인은 엎드러져서 소멸되려니와 의인의 집은 서있으리라"},{"n":8,"t":"사람은 그 지혜대로 칭찬을 받으려니와 마음이 패려한 자는 멸시를 받으리라"},{"n":9,"t":"비천히 여김을 받을지라도 종을 부리는 자는 스스로 높은체 하고도 음식이 핍절한 자보다 나으니라"},{"n":10,"t":"의인은 그 육축의 생명을 돌아보나 악인의 긍휼은 잔인이니라"},{"n":11,"t":"자기의 토지를 경작하는 자는 먹을 것이 많거니와 방탕한 것을 따르는 자는 지혜가 없느니라"},{"n":12,"t":"악인은 불의의 이를 탐하나 의인은 그 뿌리로 말미암아 결실하느니라"},{"n":13,"t":"악인은 입술의 허물로 인하여 그물에 걸려도 의인은 환난에서 벗어나느니라"},{"n":14,"t":"사람은 입의 열매로 인하여 복록에 족하며 그 손의 행하는 대로 자기가 받느니라"},{"n":15,"t":"미련한 자는 자기 행위를 바른 줄로 여기나 지혜로운 자는 권고를 듣느니라"},{"n":16,"t":"미련한 자는 분노를 당장에 나타내거니와 슬기로운 자는 수욕을 참느니라"},{"n":17,"t":"진리를 말하는 자는 의를 나타내어도 거짓 증인은 궤휼을 말하느니라"},{"n":18,"t":"혹은 칼로 찌름같이 함부로 말하거니와 지혜로운 자의 혀는 양약 같으니라"},{"n":19,"t":"진실한 입술은 영원히 보존되거니와 거짓 혀는 눈 깜짝일 동안만 있을뿐이니라"},{"n":20,"t":"악을 꾀하는 자의 마음에는 궤휼이 있고 화평을 논하는 자에게는 희락이 있느니라"},{"n":21,"t":"의인에게는 아무 재앙도 임하지 아니하려니와 악인에게는 앙화가 가득하리라"},{"n":22,"t":"거짓 입술은 여호와께 미움을 받아도 진실히 행하는 자는 그의 기뻐하심을 받느니라"},{"n":23,"t":"슬기로운 자는 지식을 감추어 두어도 미련한 자의 마음은 미련한것을 전파하느니라"},{"n":24,"t":"부지런한 자의 손은 사람을 다스리게 되어도 게으른 자는 부림을 받느니라"},{"n":25,"t":"근심이 사람의 마음에 있으면 그것으로 번뇌케 하나 선한 말은 그것을 즐겁게 하느니라"},{"n":26,"t":"의인은 그 이웃의 인도자가 되나 악인의 소행은 자기를 미혹하게하느니라"},{"n":27,"t":"게으른 자는 그 잡을 것도 사냥하지 아니하나니 사람의 부귀는 부지런한 것이니라"},{"n":28,"t":"의로운 길에 생명이 있나니 그 길에는 사망이 없느니라"}],"kids":[{"n":1,"t":"가르침을 좋아하는 사람은 지식을 사랑하지만 충고를 싫어하는 사람은 짐승과 다를 게 없어."},{"n":2,"t":"좋은 사람은 하나님께 사랑을 받지만 나쁜 일을 꾸미는 사람은 벌을 받게 돼."},{"n":3,"t":"사람이 나쁜 일로는 절대 든든히 서지 못하지만 옳은 사람의 뿌리는 흔들리지 않아."},{"n":4,"t":"마음 좋은 아내는 남편의 자랑이지만 부끄러운 아내는 남편의 뼛속까지 힘들게 해."},{"n":5,"t":"옳은 사람의 생각은 정직하지만 나쁜 사람의 계획은 속임수로 가득해."},{"n":6,"t":"못된 사람의 말은 누군가를 넘어뜨리지만 정직한 사람의 입은 사람들을 살려."},{"n":7,"t":"나쁜 사람은 한순간에 무너져 사라지지만 옳은 사람의 집은 든든히 서 있어."},{"n":8,"t":"사람은 자기 지혜만큼 칭찬을 받지만 마음이 비뚤어진 사람은 무시를 당해."},{"n":9,"t":"사람들에게 평범해 보여도 자기 일을 잘하는 사람이 잘난 척하면서 먹을 것도 없는 사람보다 훨씬 나아."},{"n":10,"t":"옳은 사람은 자기가 기르는 짐승의 생명까지 보살피지만 나쁜 사람은 사랑한다 하면서도 결국 잔인하게 굴어."},{"n":11,"t":"자기 밭을 부지런히 가꾸는 사람은 먹을 것이 풍성하지만 헛된 것을 좇아다니는 사람은 분별이 없어."},{"n":12,"t":"나쁜 사람은 옳지 못한 이익을 탐내지만 옳은 사람은 든든한 뿌리로 좋은 열매를 맺어."},{"n":13,"t":"못된 사람은 자기 말 때문에 함정에 걸리지만 옳은 사람은 어려움에서 빠져나오게 돼."},{"n":14,"t":"사람은 자기 입에서 나오는 말의 결과로 좋은 것을 얻고 손으로 한 일의 결과를 자기가 받아."},{"n":15,"t":"어리석은 사람은 자기 행동이 다 옳다고 생각하지만 지혜로운 사람은 다른 사람의 조언을 잘 들어."},{"n":16,"t":"어리석은 사람은 화가 나면 바로 드러내지만 슬기로운 사람은 부끄러운 일도 잘 참아."},{"n":17,"t":"진실을 말하는 사람은 옳은 것을 드러내지만 거짓 증인은 속이는 말만 해."},{"n":18,"t":"칼로 찌르듯 함부로 말하는 사람이 있는가 하면 지혜로운 사람의 말은 좋은 약 같아."},{"n":19,"t":"진실한 입술은 오래오래 남지만 거짓말하는 혀는 잠깐 동안만 통해."},{"n":20,"t":"나쁜 일을 꾸미는 사람의 마음에는 속임수가 있고 평화를 의논하는 사람의 마음에는 기쁨이 있어."},{"n":21,"t":"옳은 사람에게는 큰 재앙이 닥치지 않지만 나쁜 사람에게는 화가 가득 차게 돼."},{"n":22,"t":"거짓말하는 입술은 하나님이 싫어하시지만 진실하게 행동하는 사람은 하나님이 기뻐하셔."},{"n":23,"t":"슬기로운 사람은 자기 지식을 함부로 자랑하지 않지만 어리석은 사람은 어리석은 말을 마구 떠벌려."},{"n":24,"t":"부지런한 사람의 손은 사람들을 이끄는 자리에 오르지만 게으른 사람은 다른 사람의 지시를 받게 돼."},{"n":25,"t":"마음에 근심이 있으면 그것 때문에 힘들지만 따뜻한 한마디는 그 마음을 기쁘게 해 줘."},{"n":26,"t":"옳은 사람은 이웃에게 좋은 길잡이가 되지만 나쁜 사람의 행동은 결국 자기 자신을 길 잃게 만들어."},{"n":27,"t":"게으른 사람은 잡은 것조차 제대로 손질하지 않지만 부지런한 사람은 풍족한 삶을 얻게 돼."},{"n":28,"t":"옳은 길에 생명이 있고 그 길에는 죽음이 없단다."}]}},{"chapter":13,"title":"지혜로운 아들의 삶","verses":{"krv":[{"n":1,"t":"지혜로운 아들은 아비의 훈계를 들으나 거만한 자는 꾸지람을 즐겨 듣지 아니하느니라"},{"n":2,"t":"사람은 입의 열매로 인하여 복록을 누리거니와 마음이 궤사한 자는 강포를 당하느니라"},{"n":3,"t":"입을 지키는 자는 그 생명을 보전하나 입술을 크게 벌리는 자에게는 멸망이 오느니라"},{"n":4,"t":"게으른 자는 마음으로 원하여도 얻지 못하나 부지런한 자의 마음은 풍족함을 얻느니라"},{"n":5,"t":"의인은 거짓말을 미워하나 악인은 행위가 흉악하여 부끄러운데 이르느니라"},{"n":6,"t":"의는 행실이 정직한 자를 보호하고 악은 죄인을 패망케 하느니라"},{"n":7,"t":"스스로 부한 체 하여도 아무 것도 없는 자가 있고 스스로 가난한체 하여도 재물이 많은 자가 있느니라"},{"n":8,"t":"사람의 재물이 그 생명을 속할 수는 있으나 가난한 자는 협박을 받을 일이 없느니라"},{"n":9,"t":"의인의 빛은 환하게 빛나고 악인의 등불은 꺼지느니라"},{"n":10,"t":"교만에서는 다툼만 일어날 뿐이라 권면을 듣는 자는 지혜가 있느니라"},{"n":11,"t":"망령되이 얻은 재물은 줄어가고 손으로 모은 것은 늘어가느니라"},{"n":12,"t":"소망이 더디 이루게 되면 그것이 마음을 상하게 하나니 소원이 이루는 것은 곧 생명나무니라"},{"n":13,"t":"말씀을 멸시하는 자는 패망을 이루고 계명을 두려워하는 자는 상을 얻느니라"},{"n":14,"t":"지혜 있는 자의 교훈은 생명의 샘이라 사람으로 사망의 그물을 벗어나게 하느니라"},{"n":15,"t":"선한 지혜는 은혜를 베푸나 궤사한 자의 길은 험하니라"},{"n":16,"t":"무릇 슬기로운 자는 지식으로 행하여도 미련한 자는 자기의 미련한 것을 나타내느니라"},{"n":17,"t":"악한 사자는 재앙에 빠져도 충성된 사신은 양약이 되느니라"},{"n":18,"t":"훈계를 저버리는 자에게는 궁핍과 수욕이 이르거니와 경계를 지키는 자는 존영을 얻느니라"},{"n":19,"t":"소원을 성취하면 마음에 달아도 미련한 자는 악에서 떠나기를 싫어하느니라"},{"n":20,"t":"지혜로운 자와 동행하면 지혜를 얻고 미련한 자와 사귀면 해를 받느니라"},{"n":21,"t":"재앙은 죄인을 따르고 선한 보응은 의인에게 이르느니라"},{"n":22,"t":"선인은 그 산업을 자자 손손에게 끼쳐도 죄인의 재물은 의인을 위하여 쌓이느니라"},{"n":23,"t":"가난한 자는 밭을 경작하므로 양식이 많아지거늘 혹 불의로 인하여 가산을 탕패하는 자가 있느니라"},{"n":24,"t":"초달을 차마 못하는 자는 그 자식을 미워함이라 자식을 사랑하는자는 근실히 징계하느니라"},{"n":25,"t":"의인은 포식하여도 악인의 배는 주리느니라"}],"kids":[{"n":1,"t":"지혜로운 아들은 아빠의 가르침을 잘 듣지만 잘난 척하는 사람은 꾸지람을 듣기 싫어해."},{"n":2,"t":"사람은 자기 입에서 나온 말의 결과를 받아 좋은 것을 누리지만 마음이 나쁜 사람은 거친 일을 당해."},{"n":3,"t":"입을 잘 지키는 사람은 생명을 지키지만 함부로 입을 여는 사람은 큰 어려움을 당하게 돼."},{"n":4,"t":"게으른 사람은 마음으로만 바랄 뿐 얻지 못하지만 부지런한 사람의 마음은 풍성하게 채워져."},{"n":5,"t":"옳은 사람은 거짓말을 싫어하지만 나쁜 사람은 못된 짓을 하다가 결국 부끄러움을 당해."},{"n":6,"t":"의로움은 정직하게 사는 사람을 지켜 주지만 죄는 못된 사람을 무너뜨려."},{"n":7,"t":"부자인 척하지만 아무것도 가진 게 없는 사람이 있고 가난한 척하지만 재산이 많은 사람도 있어."},{"n":8,"t":"부자는 자기 재산으로 위험에서 빠져나오기도 하지만 가난한 사람은 누구도 협박할 마음을 먹지 않아."},{"n":9,"t":"옳은 사람의 빛은 밝게 빛나지만 나쁜 사람의 등불은 결국 꺼져 버리지."},{"n":10,"t":"잘난 척하는 마음에서는 다툼만 생기지만 좋은 권면을 듣는 사람은 지혜로워."},{"n":11,"t":"헛된 방법으로 모은 재물은 점점 줄어들지만 부지런히 모은 것은 점점 늘어나."},{"n":12,"t":"바라던 일이 자꾸 미뤄지면 마음이 아프지만 바라던 일이 이루어지면 그것이 곧 생명의 나무 같단다."},{"n":13,"t":"가르침을 무시하는 사람은 스스로 무너지지만 가르침을 두려워하는 사람은 상을 받아."},{"n":14,"t":"지혜로운 사람의 가르침은 생명의 샘이라서 죽음의 함정에서 빠져나오게 해 줘."},{"n":15,"t":"선한 지혜는 사랑을 받지만 못된 길은 험하기만 해."},{"n":16,"t":"슬기로운 사람은 무엇이든 알고 행동하지만 어리석은 사람은 자기 어리석음을 그대로 드러내."},{"n":17,"t":"나쁜 심부름꾼은 일을 망쳐서 어려움을 가져오지만 진실한 심부름꾼은 좋은 약과 같단다."},{"n":18,"t":"가르침을 무시하는 사람에게는 가난과 부끄러움이 따르지만 충고를 잘 받는 사람은 존경을 받게 돼."},{"n":19,"t":"바라던 것이 이루어지면 마음이 달콤하지만 어리석은 사람은 나쁜 일에서 떠나기를 싫어해."},{"n":20,"t":"지혜로운 사람과 함께 다니면 지혜를 얻고 어리석은 사람과 어울리면 해를 입게 돼."},{"n":21,"t":"죄를 짓는 사람에게는 재앙이 따라오지만 옳은 사람에게는 좋은 보상이 따라와."},{"n":22,"t":"좋은 사람은 자기 재산을 자손 대대로 물려주지만 죄지은 사람의 재산은 결국 옳은 사람을 위해 쌓이게 돼."},{"n":23,"t":"가난한 사람도 밭을 부지런히 가꾸면 먹을 것이 풍성해지지만 나쁜 짓으로 재산을 다 날리는 사람도 있어."},{"n":24,"t":"자식을 가르치지 않는 사람은 사실 자식을 사랑하지 않는 거야. 자식을 사랑하는 사람은 부지런히 바르게 가르친단다."},{"n":25,"t":"옳은 사람은 배부르게 먹지만 나쁜 사람의 배는 항상 굶주리게 돼."}]}},{"chapter":14,"title":"정직한 길","verses":{"krv":[{"n":1,"t":"무릇 지혜로운 여인은 그 집을 세우되 미련한 여인은 자기 손으 로 그것을 허느니라"},{"n":2,"t":"정직하게 행하는 자는 여호와를 경외하여도 패역하게 행하는 자는 여호와를 경멸히 여기느니라"},{"n":3,"t":"미련한 자는 교만하여 입으로 매를 자청하고 지혜로운 자는 입술로 스스로 보전하느니라"},{"n":4,"t":"소가 없으면 구유는 깨끗하려니와 소의 힘으로 얻는 것이 많으니라"},{"n":5,"t":"신실한 증인은 거짓말을 아니하여도 거짓 증인은 거짓말을 뱉느니라"},{"n":6,"t":"거만한 자는 지혜를 구하여도 얻지 못하거니와 명철한 자는 지식얻기가 쉬우니라"},{"n":7,"t":"너는 미련한 자의 앞을 떠나라 그 입술에 지식 있음을 보지 못함이니라"},{"n":8,"t":"슬기로운 자의 지혜는 자기의 길을 아는 것이라도 미련한 자의 어리석음은 속이는 것이니라"},{"n":9,"t":"미련한 자는 죄를 심상히 여겨도 정직한 자 중에는 은혜가 있느니라"},{"n":10,"t":"마음의 고통은 자기가 알고 마음의 즐거움도 타인이 참예하지 못하느니라"},{"n":11,"t":"악한 자의 집은 망하겠고 정직한 자의 장막은 흥하리라"},{"n":12,"t":"어떤 길은 사람의 보기에 바르나 필경은 사망의 길이니라"},{"n":13,"t":"웃을 때에도 마음에 슬픔이 있고 즐거움의 끝에도 근심이 있느니라"},{"n":14,"t":"마음이 패려한 자는 자기 행위로 보응이 만족하겠고 선한 사람도 자기의 행위로 그러하리라"},{"n":15,"t":"어리석은 자는 온갖 말을 믿으나 슬기로운 자는 그 행동을 삼가느니라"},{"n":16,"t":"지혜로운 자는 두려워하여 악을 떠나나 어리석은 자는 방자하여 스스로 믿느니라"},{"n":17,"t":"노하기를 속히 하는 자는 어리석은 일을 행하고 악한 계교를 꾀하는 자는 미움을 받느니라"},{"n":18,"t":"어리석은 자는 어리석음으로 기업을 삼아도 슬기로운 자는 지식으로 면류관을 삼느니라"},{"n":19,"t":"악인은 선인 앞에 엎드리고 불의자는 의인의 문에 엎드리느니라"},{"n":20,"t":"가난한 자는 그 이웃에게도 미움을 받게 되나 부요한 자는 친구가 많으니라"},{"n":21,"t":"그 이웃을 업신여기는 자는 죄를 범하는 자요 빈곤한 자를 불쌍 히 여기는 자는 복이 있는 자니라"},{"n":22,"t":"악을 도모하는 자는 그릇 가는 것이 아니냐 선을 도모하는 자에 게는 인자와 진리가 있으리라"},{"n":23,"t":"모든 수고에는 이익이 있어도 입술의 말은 궁핍을 이룰 뿐이니라"},{"n":24,"t":"지혜로운 자의 재물은 그의 면류관이요 미련한 자의 소유는 다만 그 미련한 것이니라"},{"n":25,"t":"진실한 증인은 사람의 생명을 구원하여도 거짓말을 뱉는 사람은 속이느니라"},{"n":26,"t":"여호와를 경외하는 자에게는 견고한 의뢰가 있나니 그 자녀들에게 피난처가 있으리라"},{"n":27,"t":"여호와를 경외하는 것은 생명의 샘이라 사망의 그물에서 벗어나게 하느니라"},{"n":28,"t":"백성이 많은 것은 왕의 영광이요 백성이 적은 것은 주권자의 패망이니라"},{"n":29,"t":"노하기를 더디 하는 자는 크게 명철하여도 마음이 조급한 자는 어리석음을 나타내느니라"},{"n":30,"t":"마음의 화평은 육신의 생명이나 시기는 뼈의 썩음이니라"},{"n":31,"t":"가난한 사람을 학대하는 자는 그를 지으신 이를 멸시하는 자요 궁핍한 사람을 불쌍히 여기는 자는 주를 존경하는 자니라"},{"n":32,"t":"악인은 그 환난에 엎드러져도 의인은 그 죽음에도 소망이 있느니라"},{"n":33,"t":"지혜는 명철한 자의 마음에 머물거니와 미련한 자의 속에 있는 것은 나타나느니라"},{"n":34,"t":"의는 나라로 영화롭게 하고 죄는 백성을 욕되게 하느니라"},{"n":35,"t":"슬기롭게 행하는 신하는 왕의 은총을 입고 욕을 끼치는 신하는 그의 진노를 당하느니라"}],"kids":[{"n":1,"t":"지혜로운 여자는 자기 집을 잘 세워 가지만 어리석은 여자는 자기 손으로 자기 집을 무너뜨려."},{"n":2,"t":"정직하게 사는 사람은 하나님을 두려워하는 사람이고 비뚤어지게 사는 사람은 하나님을 우습게 여기는 사람이야."},{"n":3,"t":"어리석은 사람은 잘난 척하다가 자기 입으로 매를 부르지만 지혜로운 사람의 입은 자기를 지켜 줘."},{"n":4,"t":"소가 없으면 외양간이 깨끗하지만 소의 힘이 있어야 얻는 것이 많아지지."},{"n":5,"t":"진실한 증인은 거짓말을 안 하지만 거짓 증인은 거짓말을 마구 쏟아 내."},{"n":6,"t":"잘난 척하는 사람은 지혜를 찾아도 얻지 못하지만 깨달은 사람은 지식을 쉽게 얻어."},{"n":7,"t":"어리석은 사람 곁에는 오래 머물지 마라. 그 입에서는 좋은 지식을 찾아볼 수 없어."},{"n":8,"t":"슬기로운 사람의 지혜는 자기가 가야 할 길을 아는 거고 어리석은 사람의 어리석음은 자기를 속이는 거야."},{"n":9,"t":"어리석은 사람은 죄를 가볍게 여기지만 정직한 사람들 사이에는 따뜻한 마음이 있어."},{"n":10,"t":"마음의 아픔은 자기 자신만 알고 마음의 기쁨도 남이 다 알 수는 없는 거야."},{"n":11,"t":"나쁜 사람의 집은 결국 무너지지만 정직한 사람의 집은 점점 잘되게 돼."},{"n":12,"t":"어떤 길은 사람 보기에는 바른 길 같지만 결국은 죽음으로 가는 길일 수 있어."},{"n":13,"t":"웃고 있을 때에도 마음에는 슬픔이 있을 수 있고 즐거움 뒤에 걱정이 따라오기도 해."},{"n":14,"t":"마음이 비뚤어진 사람은 자기가 한 짓의 결과를 받고 선한 사람도 자기가 한 좋은 일의 결과를 받아."},{"n":15,"t":"어리석은 사람은 무슨 말이든 다 믿지만 슬기로운 사람은 자기 행동을 조심해서 살펴."},{"n":16,"t":"지혜로운 사람은 무서운 일을 조심하면서 나쁜 일에서 떠나지만 어리석은 사람은 마음대로 행동하면서 자기를 너무 믿어."},{"n":17,"t":"화를 빨리 내는 사람은 어리석은 일을 저지르고 나쁜 일을 꾸미는 사람은 미움을 받아."},{"n":18,"t":"분별 없는 사람은 어리석음을 자랑처럼 가지지만 슬기로운 사람은 지식으로 자기 머리를 빛나게 해."},{"n":19,"t":"결국엔 나쁜 사람도 옳은 사람 앞에 무릎을 꿇고 못된 사람도 옳은 사람의 문 앞에 엎드리게 돼."},{"n":20,"t":"가난한 사람은 이웃에게도 미움을 받기 쉽지만 부유한 사람에게는 친구가 많이 모여."},{"n":21,"t":"이웃을 무시하는 사람은 죄를 짓는 거고 어려운 사람을 불쌍히 여기는 사람은 복을 받아."},{"n":22,"t":"나쁜 일을 꾸미는 사람은 잘못된 길로 가는 거지만 좋은 일을 꾸미는 사람에게는 사랑과 진실이 함께해."},{"n":23,"t":"모든 수고에는 이익이 있지만 말만 많고 행동이 없으면 결국 가난해질 뿐이야."},{"n":24,"t":"지혜로운 사람에게는 재물이 자랑스러운 왕관이 되지만 어리석은 사람에게 남는 건 어리석음뿐이야."},{"n":25,"t":"진실한 증인은 사람의 생명을 구해 주지만 거짓말을 쏟아 내는 사람은 사람들을 속여."},{"n":26,"t":"하나님을 두려워하고 공경하는 사람에게는 든든한 힘이 있고 그 자녀들도 안전한 피난처를 얻게 돼."},{"n":27,"t":"하나님을 두려워하는 마음은 생명의 샘이라서 죽음의 함정에서 빠져나오게 해 줘."},{"n":28,"t":"백성이 많은 것은 왕의 영광이고 백성이 적어지는 것은 다스리는 사람에게 큰 문제야."},{"n":29,"t":"화내기를 천천히 하는 사람은 매우 지혜로운 사람이지만 마음이 급한 사람은 자기 어리석음을 다 드러내게 돼."},{"n":30,"t":"평온한 마음은 우리 몸을 살리지만 누군가를 시기하는 마음은 뼛속까지 썩게 만들어."},{"n":31,"t":"가난한 사람을 함부로 대하는 사람은 그 사람을 만드신 하나님을 무시하는 사람이고 어려운 사람을 불쌍히 여기는 사람은 하나님을 공경하는 사람이야."},{"n":32,"t":"나쁜 사람은 어려운 일을 만나면 그대로 쓰러지지만 옳은 사람은 죽음 앞에서도 희망이 있어."},{"n":33,"t":"지혜는 깨달은 사람의 마음에 차분히 머물지만 어리석은 사람 속에 있는 것은 곧 다 드러나 버려."},{"n":34,"t":"의로움은 나라를 영광스럽게 하고 죄는 그 나라 백성을 부끄럽게 만들어."},{"n":35,"t":"슬기롭게 일하는 사람은 윗사람의 사랑을 받지만 부끄러움을 끼치는 사람은 윗사람의 화를 사게 돼."}]}},{"chapter":15,"title":"온순한 대답","verses":{"krv":[{"n":1,"t":"유순한 대답은 분노를 쉬게 하여도 과격한 말은 노를 격동하느니라"},{"n":2,"t":"지혜 있는 자의 혀는 지식을 선히 베풀고 미련한 자의 입은 미련한 것을 쏟느니라"},{"n":3,"t":"여호와의 눈은 어디서든지 악인과 선인을 감찰하시느니라"},{"n":4,"t":"온량한 혀는 곧 생명 나무라도 패려한 혀는 마음을 상하게 하느니라"},{"n":5,"t":"아비의 훈계를 업신여기는 자는 미련한 자요 경계를 받는 자는 슬기를 얻을 자니라"},{"n":6,"t":"의인의 집에는 많은 보물이 있어도 악인의 소득은 고통이 되느니라"},{"n":7,"t":"지혜로운 자의 입술은 지식을 전파하여도 미련한 자의 마음은 정함이 없느니라"},{"n":8,"t":"악인의 제사는 여호와께서 미워하셔도 정직한 자의 기도는 그가 기뻐하시느니라"},{"n":9,"t":"악인의 길은 여호와께서 미워하셔도 의를 따라가는 자는 그가 사랑하시느니라"},{"n":10,"t":"도를 배반하는 자는 엄한 징계를 받을 것이요 견책을 싫어하는 자는 죽을 것이니라"},{"n":11,"t":"음부와 유명도 여호와의 앞에 드러나거든 하물며 인생의 마음이리요"},{"n":12,"t":"거만한 자는 견책 받기를 좋아하지 아니하며 지혜 있는 자에게로 가지도 아니하느니라"},{"n":13,"t":"마음의 즐거움은 얼굴을 빛나게 하여도 마음의 근심은 심령을 상하게 하느니라"},{"n":14,"t":"명철한 자의 마음은 지식을 요구하고 미련한 자의 입은 미련한 것을 즐기느니라"},{"n":15,"t":"고난 받는 자는 그 날이 다 험악하나 마음이 즐거운자는 항상 잔치하느니라"},{"n":16,"t":"가산이 적어도 여호와를 경외하는 것이 크게 부하고 번뇌하는 것보다 나으니라"},{"n":17,"t":"여간 채소를 먹으며 서로 사랑하는 것이 살진 소를 먹으며 서로 미워하는 것보다 나으니라"},{"n":18,"t":"분을 쉽게 내는 자는 다툼을 일으켜도 노하기를 더디하는 자는 시비를 그치게 하느니라"},{"n":19,"t":"게으른 자의 길은 가시울타리 같으나 정직한 자의 길은 대로니라"},{"n":20,"t":"지혜로운 아들은 아비를 즐겁게 하여도 미련한 자는 어미를 업신여기느니라"},{"n":21,"t":"무지한 자는 미련한 것을 즐겨하여도 명철한 자는 그 길을 바르게 하느니라"},{"n":22,"t":"의논이 없으면 경영이 파하고 모사가 많으면 경영이 성립하느니라"},{"n":23,"t":"사람은 그 입의 대답으로 말미암아 기쁨을 얻나니 때에 맞은 말이 얼마나 아름다운고"},{"n":24,"t":"지혜로운 자는 위로 향한 생명길로 말미암음으로 그 아래 있는 음부를 떠나게 되느니라"},{"n":25,"t":"여호와는 교만한 자의 집을 허시며 과부의 지계를 정하시느니라"},{"n":26,"t":"악한 꾀는 여호와의 미워하시는 것이라도 선한 말은 정결하니라"},{"n":27,"t":"이를 탐하는 자는 자기 집을 해롭게 하나 뇌물을 싫어하는 자는 사느니라"},{"n":28,"t":"의인의 마음은 대답할 말을 깊이 생각하여도 악인의 입은 악을 쏟느니라"},{"n":29,"t":"여호와는 악인을 멀리 하시고 의인의 기도를 들으시느니라"},{"n":30,"t":"눈의 밝은 것은 마음을 기쁘게 하고 좋은 기별은 뼈를 윤택하게 하느니라"},{"n":31,"t":"생명의 경계를 듣는 귀는 지혜로운 자 가운데 있느니라"},{"n":32,"t":"훈계 받기를 싫어하는 자는 자기의 영혼을 경히 여김이라 견책을 달게 받는 자는 지식을 얻느니라"},{"n":33,"t":"여호와를 경외하는 것은 지혜의 훈계라 겸손은 존귀의 앞잡이니 라"}],"kids":[{"n":1,"t":"부드럽게 대답하면 화가 누그러지지만 거친 말은 더 큰 화를 불러일으켜."},{"n":2,"t":"지혜로운 사람의 혀는 지식을 좋게 전해 주지만 어리석은 사람의 입은 어리석은 말을 쏟아 내."},{"n":3,"t":"하나님의 눈은 어디에 있든지 나쁜 사람과 좋은 사람을 다 보고 계셔."},{"n":4,"t":"부드러운 말은 생명의 나무 같지만 비뚤어진 말은 사람의 마음을 다치게 해."},{"n":5,"t":"아빠의 가르침을 무시하는 사람은 어리석은 사람이고 충고를 잘 받는 사람은 슬기로워."},{"n":6,"t":"옳은 사람의 집에는 좋은 것이 가득하지만 나쁜 사람이 얻는 것은 결국 괴로움이 돼."},{"n":7,"t":"지혜로운 사람의 입은 지식을 잘 전해 주지만 어리석은 사람의 마음은 갈피를 못 잡아."},{"n":8,"t":"나쁜 사람이 드리는 예배는 하나님이 싫어하시지만 정직한 사람의 기도는 기쁘게 받으셔."},{"n":9,"t":"나쁜 사람의 길은 하나님이 싫어하시지만 의로움을 따르는 사람은 하나님이 사랑하셔."},{"n":10,"t":"옳은 길을 떠나는 사람은 호된 가르침을 받게 되고 충고 듣기를 싫어하는 사람은 결국 망하게 돼."},{"n":11,"t":"깊은 무덤조차 하나님 앞에 다 드러나 있는데 하물며 사람의 마음은 더더욱 그러시지."},{"n":12,"t":"잘난 척하는 사람은 충고 듣는 것을 싫어하고 지혜로운 사람 곁으로도 가려 하지 않아."},{"n":13,"t":"즐거운 마음은 얼굴을 환하게 하지만 마음의 근심은 영혼까지 힘들게 해."},{"n":14,"t":"깨달은 사람의 마음은 지식을 더 알고 싶어 하지만 어리석은 사람의 입은 어리석은 것을 즐겨."},{"n":15,"t":"힘든 일을 겪는 사람은 모든 날이 험하게 느껴지지만 마음이 즐거운 사람은 매일이 잔치와 같아."},{"n":16,"t":"재산이 적어도 하나님을 두려워하며 사는 것이 재산이 많아도 걱정에 시달리며 사는 것보다 훨씬 좋아."},{"n":17,"t":"채소만 먹어도 서로 사랑하는 것이 살진 고기를 먹으면서 서로 미워하는 것보다 훨씬 나아."},{"n":18,"t":"화를 잘 내는 사람은 다툼을 일으키지만 천천히 화내는 사람은 싸움을 잠재워."},{"n":19,"t":"게으른 사람의 길은 가시덤불 같지만 정직한 사람의 길은 넓고 평탄한 큰길 같아."},{"n":20,"t":"지혜로운 아들은 아빠를 기쁘게 하지만 어리석은 사람은 엄마를 슬프게 해."},{"n":21,"t":"분별 없는 사람은 어리석은 일을 즐기지만 깨달은 사람은 자기 길을 바르게 다듬어."},{"n":22,"t":"의논할 사람이 없으면 계획이 무너지지만 좋은 조언이 많으면 일이 잘 되어 가."},{"n":23,"t":"자기 입에서 알맞은 대답이 나오면 기뻐. 때에 맞는 한마디 말이 얼마나 아름다운지!"},{"n":24,"t":"지혜로운 사람은 위를 향하는 생명의 길로 가서 아래의 무서운 곳을 멀리하게 돼."},{"n":25,"t":"하나님은 잘난 척하는 사람의 집을 허물지만 외로운 사람들의 자리는 든든히 지켜 주셔."},{"n":26,"t":"못된 계획은 하나님이 싫어하시지만 좋은 말은 깨끗하고 아름다운 거야."},{"n":27,"t":"옳지 않은 이익을 탐하는 사람은 자기 집을 망치지만 뇌물을 싫어하는 사람은 잘 살게 돼."},{"n":28,"t":"옳은 사람은 대답할 말을 깊이 생각하지만 나쁜 사람의 입은 나쁜 말을 그대로 쏟아 내."},{"n":29,"t":"하나님은 나쁜 사람과는 멀리 계시지만 옳은 사람의 기도는 잘 들으셔."},{"n":30,"t":"환한 눈빛은 마음을 기쁘게 하고 좋은 소식은 뼛속까지 시원하게 해 줘."},{"n":31,"t":"생명을 살리는 충고를 잘 듣는 귀를 가진 사람은 지혜로운 사람들 가운데 있는 거야."},{"n":32,"t":"가르침을 싫어하는 사람은 자기 자신을 가볍게 여기는 사람이지만 충고를 달게 받는 사람은 지식을 얻어."},{"n":33,"t":"하나님을 두려워하고 공경하는 것이 지혜를 배우는 길이고 겸손은 존귀로 가는 길잡이가 되어 줘."}]}},{"chapter":16,"title":"마음의 계획","verses":{"krv":[{"n":1,"t":"마음의 경영은 사람에게 있어도 말의 응답은 여호와께로서 나느니라"},{"n":2,"t":"사람의 행위가 자기 보기에는 모두 깨끗하여도 여호와는 심령을 감찰하시느니라"},{"n":3,"t":"너의 행사를 여호와께 맡기라 그리하면 너의 경영하는 것이 이루리라"},{"n":4,"t":"여호와께서 온갖 것을 그 씌움에 적당하게 지으셨나니 악인도 악한 날에 적당하게 하셨느니라"},{"n":5,"t":"무릇 마음이 교만한 자를 여호와께서 미워하시나니 피차 손을 잡을지라도 벌을 면치 못하리라"},{"n":6,"t":"인자와 진리로 인하여 죄악이 속하게 되고 여호와를 경외함으로 인하여 악에서 떠나게 되느니라"},{"n":7,"t":"사람의 행위가 여호와를 기쁘시게 하면 그 사람의 원수라도 그로 더불어 화목하게 하시느니라"},{"n":8,"t":"적은 소득이 의를 겸하면 많은 소득이 불의를 겸한 것보다 나으니라"},{"n":9,"t":"사람이 마음으로 자기의 길을 계획할지라도 그 걸음을 인도하는 자는 여호와시니라"},{"n":10,"t":"하나님의 말씀이 왕의 입술에 있은즉 재판할 때에 그 입이 그릇하지 아니하리라"},{"n":11,"t":"공평한 간칭과 명칭은 여호와의 것이요 주머니 속의 추돌들도 다 그의 지으신 것이니라"},{"n":12,"t":"악을 행하는 것은 왕의 미워할 바니 이는 그 보좌가 공의로 말미암아 굳게 섬이니라"},{"n":13,"t":"의로운 입술은 왕들의 기뻐하는 것이요 정직히 말하는 자는 그들의 사랑을 입느니라"},{"n":14,"t":"왕의 진노는 살륙의 사자와 같아도 지혜로운 사람은 그것을 쉬게하리라"},{"n":15,"t":"왕의 희색에 생명이 있나니 그 은택이 늦은 비를 내리는 구름과 같으니라"},{"n":16,"t":"지혜를 얻는 것이 금을 얻는 것보다 얼마나 나은고 명철을 얻는 것이 은을 얻는 것보다 더욱 나으니라"},{"n":17,"t":"악을 떠나는 것은 정직한 사람의 대로니 그 길을 지키는 자는 자기의 영혼을 보전하느니라"},{"n":18,"t":"교만은 패망의 선봉이요 거만한 마음은 넘어짐의 앞잡이니라"},{"n":19,"t":"겸손한 자와 함께하여 마음을 낮추는 것이 교만한 자와 함께 하여 탈취물을 나누는 것보다 나으니라"},{"n":20,"t":"삼가 말씀에 주의하는 자는 좋은 것을 얻나니 여호와를 의지하는자가 복이 있느니라"},{"n":21,"t":"마음이 지혜로운 자가 명철하다 일컬음을 받고 입이 선한 자가 남의 학식을 더하게 하느니라"},{"n":22,"t":"명철한 자에게는 그 명철이 생명의 샘이 되거니와 미련한 자에게는 그 미련한 것이 징계가 되느니라"},{"n":23,"t":"지혜로운 자의 마음은 그 입을 슬기롭게 하고 또 그 입술에 지식을 더하느니라"},{"n":24,"t":"선한 말은 꿀송이 같아서 마음에 달고 뼈에 양약이 되느니라"},{"n":25,"t":"어떤 길은 사람의 보기에 바르나 필경은 사망의 길이니라"},{"n":26,"t":"노력하는 자는 식욕을 인하여 애쓰나니 이는 그 입이 자기를 독촉함이니라"},{"n":27,"t":"불량한 자는 악을 꾀하나니 그 입술에는 맹렬한 불 같은 것이 있느니라"},{"n":28,"t":"패려한 자는 다툼을 일으키고 말장이는 친한 벗을 이간하느니라"},{"n":29,"t":"강포한 사람은 그 이웃을 꾀어 불선한 길로 인도하느니라"},{"n":30,"t":"눈을 감는 자는 패역한 일을 도모하며 입술을 닫는 자는 악한 일을 이루느니라"},{"n":31,"t":"백발은 영화의 면류관이라 의로운 길에서 얻으리라"},{"n":32,"t":"노하기를 더디하는 자는 용사보다 낫고 자기의 마음을 다스리는 자는 성을 빼앗는 자보다 나으니라"},{"n":33,"t":"사람이 제비는 뽑으나 일을 작정하기는 여호와께 있느니라"}],"kids":[{"n":1,"t":"마음으로 계획을 세우는 것은 사람이지만 말의 답을 주시는 분은 하나님이셔."},{"n":2,"t":"사람은 자기 행동이 다 깨끗해 보이지만 하나님은 그 마음속 깊은 곳까지 살펴보셔."},{"n":3,"t":"네가 하는 일을 하나님께 맡겨라. 그러면 네가 계획한 일이 이루어질 거야."},{"n":4,"t":"하나님은 모든 것을 다 알맞게 만드셨고 나쁜 사람도 결국 자기 행동에 맞는 결과를 받게 하셨어."},{"n":5,"t":"마음이 잘난 척하는 사람을 하나님은 싫어하셔. 그런 사람들이 손을 맞잡는다 해도 벌을 피할 수는 없어."},{"n":6,"t":"사랑과 진실로 죄가 씻기고 하나님을 두려워하면 나쁜 일에서 떠나게 돼."},{"n":7,"t":"사람이 한 일이 하나님을 기쁘게 하면 그 사람의 원수까지도 화해하게 만들어 주셔."},{"n":8,"t":"적게 얻어도 옳게 사는 것이 많이 얻으면서 나쁜 짓을 하는 것보다 훨씬 나아."},{"n":9,"t":"사람이 마음으로 자기 길을 계획해도 그 걸음을 이끌어 가시는 분은 하나님이셔."},{"n":10,"t":"왕의 입에는 하나님의 말씀이 머물러야 해. 그래야 재판할 때 잘못된 판단을 하지 않아."},{"n":11,"t":"공평한 저울과 접시 저울은 하나님께 속해 있고 주머니에 든 저울추도 다 하나님이 만드신 거야."},{"n":12,"t":"나쁜 일을 하는 것은 왕들도 싫어해. 왕의 자리는 옳음 위에 든든히 세워지기 때문이야."},{"n":13,"t":"옳은 말을 하는 입술을 왕들이 기뻐하고 정직하게 말하는 사람을 사랑해."},{"n":14,"t":"왕이 화내면 무서운 일이 따르지만 지혜로운 사람은 그 화를 가라앉힐 줄 알아."},{"n":15,"t":"왕의 웃는 얼굴에는 생명이 있고 그 사랑은 가뭄 끝의 단비를 내리는 구름 같아."},{"n":16,"t":"지혜를 얻는 것이 금을 얻는 것보다 훨씬 좋고 깨달음을 얻는 것이 은을 얻는 것보다 훨씬 나아."},{"n":17,"t":"나쁜 일에서 떠나는 길이 정직한 사람의 큰길이고 자기 길을 지키는 사람은 자기 영혼을 지키게 돼."},{"n":18,"t":"잘난 척하는 마음은 멸망보다 먼저 오고 거만한 마음은 넘어짐보다 먼저 와."},{"n":19,"t":"겸손한 사람들과 함께 마음을 낮추는 것이 잘난 척하는 사람들과 함께 빼앗은 것을 나누는 것보다 나아."},{"n":20,"t":"말씀을 마음에 새기는 사람은 좋은 것을 얻고 하나님을 의지하는 사람은 복을 받아."},{"n":21,"t":"마음이 지혜로운 사람은 깨달은 사람이라 불리고 선한 말을 하는 사람은 다른 사람의 배움을 더해 줘."},{"n":22,"t":"깨달은 사람에게는 깨달음이 생명의 샘이 되지만 어리석은 사람에게는 어리석음이 큰 벌이 돼."},{"n":23,"t":"지혜로운 사람의 마음은 그 입을 슬기롭게 하고 그 입술에 지식을 더해 줘."},{"n":24,"t":"좋은 말은 꿀송이 같아서 마음에 달고 뼛속까지 약이 된단다."},{"n":25,"t":"어떤 길은 사람 보기에는 바른 길 같지만 결국은 죽음으로 가는 길일 수 있어."},{"n":26,"t":"열심히 일하는 사람은 배고픔이 자기를 채찍질하기 때문이지. 입이 자기를 일하게 만드는 거야."},{"n":27,"t":"못된 사람은 나쁜 일을 꾸미고 그 입술에는 뜨거운 불 같은 말이 있어."},{"n":28,"t":"비뚤어진 사람은 다툼을 일으키고 말 옮기는 사람은 가까운 친구 사이도 갈라놓아."},{"n":29,"t":"거친 사람은 자기 이웃을 꾀어 좋지 않은 길로 끌고 가."},{"n":30,"t":"눈짓하는 사람은 비뚤어진 일을 꾸미고 입술을 굳게 닫고 있는 사람도 나쁜 일을 이뤄내려 해."},{"n":31,"t":"흰머리는 영광의 왕관 같아서 옳은 길에서 살아온 사람이 받게 돼."},{"n":32,"t":"화내기를 천천히 하는 사람이 용감한 군인보다 낫고 자기 마음을 잘 다스리는 사람이 성을 빼앗는 사람보다 나아."},{"n":33,"t":"제비를 뽑는 건 사람이지만 모든 일이 어떻게 될지 정하시는 분은 하나님이셔."}]}},{"chapter":17,"title":"화목과 절제","verses":{"krv":[{"n":1,"t":"마른 떡 한 조각만 있고도 화목하는 것이 육선이 집에 가득하고 다투는 것보다 나으니라"},{"n":2,"t":"슬기로운 종은 주인의 부끄러움을 끼치는 아들을 다스리겠고 또 그 아들들 중에서 유업을 나눠 얻으리라"},{"n":3,"t":"도가니는 은을, 풀무는 금을 연단하거니와 여호와는 마음을 연단 하시느니라"},{"n":4,"t":"악을 행하는 자는 궤사한 입술을 잘 듣고 거짓말을 하는 자는 악한 혀에 귀를 기울이느니라"},{"n":5,"t":"가난한 자를 조롱하는 자는 이를 지으신 주를 멸시하는 자요 사람의 재앙을 기뻐하는 자는 형벌을 면치 못할 자니라"},{"n":6,"t":"손자는 노인의 면류관이요 아비는 자식의 영화니라"},{"n":7,"t":"분외의 말을 하는 것도 미련한 자에게 합당치 아니하거든 하물며 거짓말을 하는 것이 존귀한 자에게 합당하겠느냐"},{"n":8,"t":"뇌물은 임자의 보기에 보석 같은즉 어디로 향하든지 형통케 하느니라"},{"n":9,"t":"허물을 덮어 주는 자는 사랑을 구하는 자요 그것을 거듭 말하는 자는 친한 벗을 이간하는 자니라"},{"n":10,"t":"한 마디로 총명한 자를 경계하는 것이 매 백개로 미련한 자를 때리는 것보다 더욱 깊이 박이느니라"},{"n":11,"t":"악한 자는 반역만 힘쓰나니 그러므로 그에게 잔인한 사자가 보냄을 입으리라"},{"n":12,"t":"차라리 새끼 빼앗긴 암콤을 만날지언정 미련한 일을 행하는 미련한 자를 만나지 말 것이니라"},{"n":13,"t":"누구든지 악으로 선을 갚으면 악이 그 집을 떠나지 아니하리라"},{"n":14,"t":"다투는 시작은 방축에서 물이 새는 것 같은즉 싸움이 일어나기 전에 시비를 그칠 것이니라"},{"n":15,"t":"악인을 의롭다 하며 의인을 악하다 하는 이 두 자는 다 여호와의 미워하심을 입느니라"},{"n":16,"t":"미련한 자는 무지하거늘 손에 값을 가지고 지혜를 사려 함은 어찜인고"},{"n":17,"t":"친구는 사랑이 끊이지 아니하고 형제는 위급한 때까지 위하여 났느니라"},{"n":18,"t":"지혜없는 자는 남의 손을 잡고 그 이웃 앞에서 보증이 되느니라"},{"n":19,"t":"다툼을 좋아하는 자는 죄과를 좋아하는 자요 자기 문을 높이는 자는 파괴를 구하는 자니라"},{"n":20,"t":"마음이 사특한 자는 복을 얻지 못하고 혀가 패역한 자는 재앙에 빠지느니라"},{"n":21,"t":"미련한 자를 낳는 자는 근심을 당하나니 미련한 자의 아비는 낙이 없느니라"},{"n":22,"t":"마음의 즐거움은 양약이라도 심령의 근심은 뼈로 마르게 하느니라"},{"n":23,"t":"악인은 사람의 품에서 뇌물을 받고 재판을 굽게 하느니라"},{"n":24,"t":"지혜는 명철한 자의 앞에 있거늘 미련한 자는 눈을 땅 끝에 두느니라"},{"n":25,"t":"미련한 아들은 그 아비의 근심이 되고 그 어미의 고통이 되느니 라"},{"n":26,"t":"의인을 벌하는 것과 귀인을 정직하다고 때리는 것이 선치 못하니라"},{"n":27,"t":"말을 아끼는 자는 지식이 있고 성품이 안존한 자는 명철하니라"},{"n":28,"t":"미련한 자라도 잠잠하면 지혜로운 자로 여기우고 그 입술을 닫히면 슬기로운 자로 여기우느니라"}],"kids":[{"n":1,"t":"마른 빵 한 조각만 있어도 사이좋게 지내는 것이 좋은 음식이 가득해도 매일 다투는 것보다 훨씬 나아."},{"n":2,"t":"슬기로운 일꾼은 부모를 부끄럽게 하는 아들을 다스리게 되고 형제들과 함께 유산을 나눠 받기도 해."},{"n":3,"t":"도가니로 은을 정제하고 풀무로 금을 단련하듯이 하나님은 사람의 마음을 단련하셔."},{"n":4,"t":"나쁜 일을 하는 사람은 못된 입에서 나오는 말을 잘 듣고 거짓말하는 사람은 못된 혀가 하는 말에 귀를 기울여."},{"n":5,"t":"가난한 사람을 비웃는 사람은 그 사람을 만드신 하나님을 무시하는 거고 다른 사람의 불행을 기뻐하는 사람은 벌을 피할 수 없어."},{"n":6,"t":"손주는 어르신의 영광의 왕관이고 아빠는 자식들의 자랑이야."},{"n":7,"t":"어리석은 사람에게 화려한 말이 어울리지 않는데 하물며 귀한 자리에 있는 사람에게 거짓말이 어떻게 어울리겠니?"},{"n":8,"t":"뇌물을 주는 사람은 그것을 보석처럼 여기고 어디서든 자기 일이 잘 풀린다고 생각해."},{"n":9,"t":"다른 사람의 잘못을 덮어 주는 사람은 사랑을 키우는 사람이고 그 잘못을 자꾸 들춰내는 사람은 친한 친구 사이를 갈라놓는 사람이야."},{"n":10,"t":"슬기로운 사람에게는 말 한마디만 해도 마음에 깊이 새겨지지만 어리석은 사람은 매 백 대를 맞아도 깨닫지 못해."},{"n":11,"t":"못된 사람은 어긋난 일만 자꾸 하니까 결국 호된 결과가 그 사람에게 닥쳐."},{"n":12,"t":"차라리 새끼를 빼앗긴 곰을 만날지언정 어리석은 일을 하고 있는 어리석은 사람은 만나지 마라."},{"n":13,"t":"누구든 좋은 일을 받고 나쁜 일로 갚으면 그 집에서 나쁜 일이 떠나지 않을 거야."},{"n":14,"t":"다툼이 시작되는 건 둑에서 물이 새는 것 같아. 그러니 싸움이 커지기 전에 얼른 멈춰라."},{"n":15,"t":"나쁜 사람을 옳다고 하고 옳은 사람을 나쁘다고 하는 사람은 둘 다 하나님이 싫어하셔."},{"n":16,"t":"어리석은 사람은 분별이 없는데 손에 돈을 가지고 지혜를 사겠다고 한들 무슨 소용이 있겠니?"},{"n":17,"t":"친구는 언제든 사랑하는 사이이고 형제는 어려운 때를 위해 함께 태어난 사람이야."},{"n":18,"t":"분별 없는 사람은 다른 사람의 손을 잡고 이웃 앞에서 함부로 보증을 서."},{"n":19,"t":"다툼을 좋아하는 사람은 죄를 좋아하는 사람이고 자기 집 문을 너무 높이는 사람은 결국 무너질 일을 자초하는 거야."},{"n":20,"t":"마음이 비뚤어진 사람은 복을 얻지 못하고 거짓말하는 혀를 가진 사람은 재앙에 빠져."},{"n":21,"t":"어리석은 아들을 낳은 사람은 걱정이 가득하고 어리석은 아들의 아빠에게는 기쁜 일이 없어."},{"n":22,"t":"즐거운 마음은 좋은 약이지만 마음이 슬프고 답답하면 뼈가 마르도록 힘들어져."},{"n":23,"t":"나쁜 사람은 뒤에서 몰래 뇌물을 받고 재판을 비틀어 버려."},{"n":24,"t":"깨달은 사람은 지혜를 자기 앞에 두지만 어리석은 사람은 눈을 세상 끝까지 굴리며 두리번거려."},{"n":25,"t":"어리석은 아들은 아빠에게는 근심이 되고 엄마에게는 마음의 아픔이 돼."},{"n":26,"t":"옳은 사람을 벌하는 것이나 귀한 사람을 정직하다고 때리는 것은 둘 다 잘못된 일이야."},{"n":27,"t":"말을 아끼는 사람은 지식이 있고 마음이 차분한 사람은 깨달은 사람이야."},{"n":28,"t":"어리석은 사람도 말없이 가만히 있으면 지혜로운 사람으로 보이고 입을 닫고 있으면 슬기로운 사람처럼 보인단다."}]}},{"chapter":18,"title":"피난처와 이름","verses":{"krv":[{"n":1,"t":"무리에게서 스스로 나뉘는 자는 자기 소욕을 따르는 자라 온갖 참 지혜를 배척하느니라"},{"n":2,"t":"미련한 자는 명철을 기뻐하지 아니하고 자기의 의사를 드러내기만 기뻐하느니라"},{"n":3,"t":"악한 자가 이를 때에는 멸시도 따라오고 부끄러운 것이 이를 때에는 능욕도 함께 오느니라"},{"n":4,"t":"명철한 사람의 입의 말은 깊은 물과 같고 지혜의 샘은 솟쳐 흐르는 내와 같으니라"},{"n":5,"t":"악인을 두호하는 것과 재판할 때에 의인을 억울하게 하는 것이 선하지 아니하니라"},{"n":6,"t":"미련한 자의 입술은 다툼을 일으키고 그 입은 매를 자청하느니라"},{"n":7,"t":"미련한 자의 입은 그의 멸망이 되고 그 입술은 그의 영혼의 그물이 되느니라"},{"n":8,"t":"남의 말하기를 좋아하는 자의 말은 별식과 같아서 뱃 속 깊은 데로 내려가느니라"},{"n":9,"t":"자기의 일을 게을리 하는 자는 패가 하는 자의 형제니라"},{"n":10,"t":"여호와의 이름은 견고한 망대라 의인은 그리로 달려가서 안전함을 얻느니라"},{"n":11,"t":"부자의 재물은 그의 견고한 성이라 그가 높은 성벽 같이 여기느니라"},{"n":12,"t":"사람의 마음의 교만은 멸망의 선봉이요 겸손은 존귀의 앞잡이니라"},{"n":13,"t":"사연을 듣기 전에 대답하는 자는 미련하여 욕을 당하느니라"},{"n":14,"t":"사람의 심령은 그 병을 능히 이기려니와 심령이 상하면 그것을 누가 일으키겠느냐"},{"n":15,"t":"명철한 자의 마음은 지식을 얻고 지혜로운 자의 귀는 지식을 구하느니라"},{"n":16,"t":"선물은 그 사람의 길을 너그럽게 하며 또 존귀한 자의 앞으로 그를 인도하느니라"},{"n":17,"t":"송사에 원고의 말이 바른 것 같으나 그 피고가 와서 밝히느니라"},{"n":18,"t":"제비 뽑는 것은 다툼을 그치게 하여 강한 자 사이에 해결케 하느니라"},{"n":19,"t":"노엽게 한 형제와 화목하기가 견고한 성을 취하기 보다 어려운즉 이러한 다툼은 산성 문빗장 같으니라"},{"n":20,"t":"사람은 입에서 나오는 열매로 하여 배가 부르게 되나니 곧 그 입술에서 나는 것으로하여 만족케 되느니라"},{"n":21,"t":"죽고 사는 것이 혀의 권세에 달렸나니 혀를 쓰기 좋아하는 자는 그 열매를 먹으리라"},{"n":22,"t":"아내를 얻는 자는 복을 얻고 여호와께 은총을 받는 자니라"},{"n":23,"t":"가난한 자는 간절한 말로 구하여도 부자는 엄한 말로 대답하느니라"},{"n":24,"t":"많은 친구를 얻는 자는 해를 당하게 되거니와 어떤 친구는 형제보다 친밀하니라"}],"kids":[{"n":1,"t":"사람들과 일부러 떨어져 자기 생각만 따라가는 사람은 모든 참된 지혜를 다 멀리해."},{"n":2,"t":"어리석은 사람은 깨달음을 좋아하지 않고 자기 생각을 드러내기만 좋아해."},{"n":3,"t":"나쁜 사람이 오면 멸시도 함께 따라오고 부끄러운 일이 오면 욕설도 같이 따라와."},{"n":4,"t":"깨달은 사람의 입에서 나오는 말은 깊은 물 같고 지혜의 샘은 시원하게 솟아 흐르는 시냇물 같아."},{"n":5,"t":"나쁜 사람의 편을 들거나 옳은 사람을 재판에서 억울하게 만드는 것은 잘못된 일이야."},{"n":6,"t":"어리석은 사람의 입은 다툼을 일으키고 그 입은 결국 매를 자초해."},{"n":7,"t":"어리석은 사람의 입은 자기 자신을 망치고 그 입술은 자기 영혼을 옭아매는 그물이 돼."},{"n":8,"t":"남의 이야기를 떠벌리는 사람의 말은 맛있는 음식 같아서 사람들의 마음속 깊은 곳까지 들어가."},{"n":9,"t":"자기 일을 게을리하는 사람은 살림을 망치는 사람과 형제 같단다."},{"n":10,"t":"하나님의 이름은 든든한 망대 같아서 옳은 사람은 그곳으로 달려가 안전함을 얻어."},{"n":11,"t":"부자는 자기 재산을 든든한 성으로 여기고 높은 성벽처럼 든든하다고 생각해."},{"n":12,"t":"마음의 잘난 척은 멸망보다 먼저 오고 겸손은 존귀로 가는 길잡이가 돼."},{"n":13,"t":"누가 말하는 사연을 다 듣기도 전에 대답하는 사람은 어리석어서 부끄러움을 당해."},{"n":14,"t":"사람의 마음은 자기 몸의 병도 이겨 낼 수 있지만 그 마음이 상하면 누가 일으켜 줄 수 있겠니?"},{"n":15,"t":"깨달은 사람의 마음은 지식을 잘 받아들이고 지혜로운 사람의 귀는 지식을 부지런히 찾아."},{"n":16,"t":"사람이 가져온 선물은 그 사람의 길을 넓혀 주고 높은 자리에 있는 사람 앞으로 인도해 주기도 해."},{"n":17,"t":"다툴 일에서는 먼저 말한 사람의 말이 옳아 보이지만 상대편이 와서 이야기하면 진실이 밝혀지지."},{"n":18,"t":"제비를 뽑는 것이 다툼을 멈추게 하고 힘센 사람들 사이의 문제도 해결해 줄 때가 있어."},{"n":19,"t":"마음 상한 형제와 화해하기는 든든한 성을 빼앗는 것보다 더 어렵고 그런 다툼은 굳게 잠긴 성문 빗장 같아."},{"n":20,"t":"사람은 자기 입에서 나오는 좋은 말의 결과로 배부르게 되고 입술에서 나오는 것으로 만족을 얻어."},{"n":21,"t":"죽음과 삶이 혀의 힘에 달려 있어. 자기 혀를 즐겨 사용하는 사람은 그 결과를 먹게 돼."},{"n":22,"t":"좋은 아내를 만나는 사람은 복을 얻고 하나님께 사랑을 받는 사람이야."},{"n":23,"t":"가난한 사람은 간절하게 부탁하지만 부자는 차갑게 대답할 때가 많아."},{"n":24,"t":"친구가 많다고 자랑해도 그중에는 해를 끼치는 사람도 있지만 어떤 친구는 친형제보다 더 친밀하단다."}]}},{"chapter":19,"title":"가난한 자와 훈계","verses":{"krv":[{"n":1,"t":"성실히 행하는 가난한 자는 입술이 패려하고 미련한 자 보다 나으니라"},{"n":2,"t":"지식 없는 소원은 선치 못하고 발이 급한 사람은 그릇하느니라"},{"n":3,"t":"사람이 미련하므로 자기 길을 굽게 하고 마음으로 여호와를 원망하느니라"},{"n":4,"t":"재물은 많은 친구를 더하게 하나 가난한즉 친구가 끊어지느니라"},{"n":5,"t":"거짓 증인은 벌을 면치 못할 것이요 거짓말을 내는 자도 피치 못하리라"},{"n":6,"t":"너그러운 사람에게는 은혜를 구하는 자가 많고 선물을 주기를 좋아하는 자에게는 사람마다 친구가 되느니라"},{"n":7,"t":"가난한 자는 그 형제들에게도 미움을 받거든 하물며 친구야 그를 멀리 아니하겠느냐 따라가며 말하려 할지라도 그들이 없어졌으리라"},{"n":8,"t":"지혜를 얻는 자는 자기 영혼을 사랑하고 명철을 지키는 자는 복을 얻느니라"},{"n":9,"t":"거짓 증인은 벌을 면치 못할 것이요 거짓말을 내는 자는 망할 것이니라"},{"n":10,"t":"미련한 자가 사치하는 것이 적당치 못하거든 하물며 종이 방백을 다스림이랴"},{"n":11,"t":"노하기를 더디하는 것이 사람의 슬기요 허물을 용서하는 것이 자기의 영광이니라"},{"n":12,"t":"왕의 노함은 사자의 부르짖음 같고 그의 은택은 풀 위에 이슬 같으니라"},{"n":13,"t":"미련한 아들은 그 아비의 재앙이요 다투는 아내는 이어 떨어지는 물방울이니라"},{"n":14,"t":"집과 재물은 조상에게서 상속하거니와 슬기로운 아내는 여호와께로서 말미암느니라"},{"n":15,"t":"게으름이 사람으로 깊이 잠들게 하나니 해태한 사람은 주릴 것이니라"},{"n":16,"t":"계명을 지키는 자는 자기의 영혼을 지키거니와 그 행실을 삼가지 아니하는 자는 죽으리라"},{"n":17,"t":"가난한 자를 불쌍히 여기는 것은 여호와께 꾸이는 것이니 그 선행을 갚아 주시리라"},{"n":18,"t":"네가 네 아들에게 소망이 있은즉 그를 징계하고 죽일 마음은 두지 말지니라"},{"n":19,"t":"노하기를 맹렬히 하는 자는 벌을 받을 것이라 네가 그를 건져 주면 다시 건져 주게 되리라"},{"n":20,"t":"너는 권고를 들으며 훈계를 받으라 그리하면 네가 필경은 지혜롭게 되리라"},{"n":21,"t":"사람의 마음에는 많은 계획이 있어도 오직 여호와의 뜻이 완전히 서리라"},{"n":22,"t":"사람은 그 인자함으로 남에게 사모함을 받느니라 가난한 자는 거짓말하는 자보다 나으니라"},{"n":23,"t":"여호와를 경외하는 것은 사람으로 생명에 이르게 하는 것이라 경외하는 자는 족하게 지내고 재앙을 만나지 아니하느니라"},{"n":24,"t":"게으른 자는 그 손을 그릇에 넣고도 입으로 올리기를 괴로와하느니라"},{"n":25,"t":"거만한 자를 때리라 그리하면 어리석은 자도 경성하리라 명철한 자를 견책하라 그리하면 그가 지식을 얻으리라"},{"n":26,"t":"아비를 구박하고 어미를 쫓아 내는 자는 부끄러움을 끼치며 능욕을 부르는 자식이니라"},{"n":27,"t":"내 아들아 지식의 말씀에서 떠나게 하는 교훈을 듣지 말지니라"},{"n":28,"t":"망령된 증인은 공의를 업신여기고 악인의 입은 죄악을 삼키느니라"},{"n":29,"t":"심판은 거만한 자를 위하여 예비된 것이요 채찍은 어리석은 자의 등을 위하여 예비된 것이니라"}],"kids":[{"n":1,"t":"가난해도 정직하게 사는 사람이 거짓말이나 비뚤어진 말을 하는 어리석은 사람보다 훨씬 나아."},{"n":2,"t":"마음만 앞서고 잘 모른 채 바라기만 하는 것은 좋지 않아. 발만 급한 사람은 결국 잘못된 길로 가게 돼."},{"n":3,"t":"사람은 자기 어리석음 때문에 자기 길을 망쳐 놓고는 마음으로는 하나님을 원망해."},{"n":4,"t":"재물이 많으면 친구도 많아지지만 가난해지면 친구마저 멀어지기 쉽지."},{"n":5,"t":"거짓 증인은 벌을 피할 수 없고 거짓말하는 사람도 빠져나갈 수 없어."},{"n":6,"t":"너그러운 사람에게는 도와 달라고 찾아오는 사람이 많고 잘 베푸는 사람에게는 누구나 친구가 되려고 해."},{"n":7,"t":"가난한 사람은 자기 형제들에게도 미움을 받기 쉬운데 친구야 더 말할 것도 없겠지. 말이라도 걸어 보려 따라가도 이미 사라져 버린단다."},{"n":8,"t":"지혜를 얻는 사람은 자기 영혼을 사랑하는 사람이고 깨달음을 지키는 사람은 복을 얻어."},{"n":9,"t":"거짓 증인은 벌을 피할 수 없고 거짓말을 쏟아 내는 사람은 망하게 돼."},{"n":10,"t":"어리석은 사람이 화려하게 사는 것도 어울리지 않는데 하물며 일꾼이 지도자를 다스리는 것은 더 어울리지 않지."},{"n":11,"t":"천천히 화내는 것이 사람의 슬기로움이고 다른 사람의 잘못을 용서하는 것이 자기 자신의 영광이야."},{"n":12,"t":"왕의 화는 사자가 으르렁대는 소리 같지만 왕의 사랑은 풀잎 위에 내리는 이슬 같아."},{"n":13,"t":"어리석은 아들은 아빠에게 재앙 같고 자꾸 다투는 아내는 떨어지는 물방울이 똑똑 거리는 것 같이 사람을 지치게 해."},{"n":14,"t":"집과 재산은 부모에게서 물려받지만 슬기로운 아내는 하나님께서 주시는 거란다."},{"n":15,"t":"게으름은 사람을 깊은 잠에 빠지게 만들고 게으른 사람은 굶주리게 돼."},{"n":16,"t":"가르침을 지키는 사람은 자기 영혼을 지키지만 자기 행동을 조심하지 않는 사람은 결국 망하게 돼."},{"n":17,"t":"가난한 사람을 불쌍히 여기는 것은 하나님께 꾸어 드리는 것과 같아서 그 선한 일을 하나님이 갚아 주신단다."},{"n":18,"t":"자식에게 아직 희망이 있을 때 바르게 가르치고 끝까지 포기하는 마음은 갖지 마라."},{"n":19,"t":"화를 너무 심하게 내는 사람은 벌을 받게 되어 있고 네가 한 번 도와줘도 또 같은 일이 반복될 거야."},{"n":20,"t":"충고를 듣고 가르침을 잘 받으면 네가 결국은 지혜로워질 거야."},{"n":21,"t":"사람의 마음에는 여러 가지 계획이 있지만 오직 하나님의 뜻만이 완전히 이루어진단다."},{"n":22,"t":"사람을 사랑받게 하는 것은 그 사람의 친절함이고 가난해도 정직한 사람이 거짓말하는 사람보다 훨씬 나아."},{"n":23,"t":"하나님을 두려워하고 공경하는 것은 사람을 생명으로 이끌어. 하나님을 공경하는 사람은 만족하며 살고 큰 재앙을 만나지 않아."},{"n":24,"t":"게으른 사람은 손을 그릇에 넣어 두고도 입으로 들어 올리는 것조차 귀찮아해."},{"n":25,"t":"잘난 척하는 사람을 따끔하게 다스리면 어리석은 사람도 슬기를 얻고 깨달은 사람을 충고하면 그 사람은 지식을 더 얻게 돼."},{"n":26,"t":"아빠를 함부로 대하고 엄마를 내쫓는 자식은 부끄러움을 끼치고 욕을 부르는 자식이야."},{"n":27,"t":"내 아들아, 지식에서 벗어나게 만드는 가르침은 듣지도 마라."},{"n":28,"t":"거짓 증인은 정의를 우습게 여기고 나쁜 사람의 입은 죄를 마구 삼켜."},{"n":29,"t":"잘난 척하는 사람을 위해 심판이 준비되어 있고 어리석은 사람의 등을 위해 매가 준비되어 있단다."}]}},{"chapter":20,"title":"정직한 저울","verses":{"krv":[{"n":1,"t":"포도주는 거만케 하는 것이요 독주는 떠들게 하는 것이라 무릇 이에 미혹되는 자에게는 지혜가 없느니라"},{"n":2,"t":"왕의 진노는 사자의 부르짖음 같으니 그를 노하게 하는 것은 자기의 생명을 해하는 것이니라"},{"n":3,"t":"다툼을 멀리 하는 것이 사람에게 영광이어늘 미련한 자마다 다툼을 일으키느니라"},{"n":4,"t":"게으른 자는 가을에 밭 같지 아니하나니 그러므로 거둘 때에는 구걸할지라도 얻지 못하리라"},{"n":5,"t":"사람의 마음에 있는 모략은 깊은 물 같으니라 그럴찌라도 명철한 사람은 그것을 길어 내느니라"},{"n":6,"t":"많은 사람은 각기 자기의 인자함을 자랑하나니 충성된 자를 누가 만날 수 있으랴"},{"n":7,"t":"완전히 행하는 자가 의인이라 그 후손에게 복이 있느니라"},{"n":8,"t":"심판 자리에 앉은 왕은 그 눈으로 모든 악을 흩어지게 하느니라"},{"n":9,"t":"내가 내 마음을 정하게 하였다, 내 죄를 깨끗하게 하였다 할 자가 누구뇨"},{"n":10,"t":"한결 같지 않은 저울 추와 말은 다 여호와께서 미워하시느니라"},{"n":11,"t":"비록 아이라도 그 동작으로 자기의 품행의 청결하며 정직한 여부를 나타내느니라"},{"n":12,"t":"듣는 귀와 보는 눈은 다 여호와의 지으신 것이니라"},{"n":13,"t":"너는 잠자기를 좋아하지 말라 네가 빈궁하게 될까 두려우니라 네눈을 뜨라 그리하면 양식에 족하리라"},{"n":14,"t":"사는 자가 물건이 좋지 못하다 좋지 못하다 하다가 돌아간 후에는 자랑하느니라"},{"n":15,"t":"세상에 금도 있고 진주도 많거니와 지혜로운 입술이 더욱 귀한 보배니라"},{"n":16,"t":"타인을 위하여 보증이 된 자의 옷을 취하라 외인들의 보증이 된 자는 그 몸을 볼모 잡힐지니라"},{"n":17,"t":"속이고 취한 식물은 맛이 좋은듯하나 후에는 그 입에 모래가 가득하게 되리라"},{"n":18,"t":"무릇 경영은 의논함으로 성취하나니 모략을 베풀고 전쟁할지니라"},{"n":19,"t":"두루 다니며 한담하는 자는 남의 비밀를 누설하나니 입술을 벌린자를 사귀지 말지니라"},{"n":20,"t":"자기의 아비나 어미를 저주하는 자는 그 등불이 유암중에 꺼짐을 당하리라"},{"n":21,"t":"처음에 속히 잡은 산업은 마침내 복이 되지 아니하느니라"},{"n":22,"t":"너는 악을 갚겠다 말하지 말고 여호와를 기다리라 그가 너를 구원하시리라"},{"n":23,"t":"한결 같지 않은 저울 추는 여호와의 미워하시는 것이요 속이는 저울은 좋지 못한 것이니라"},{"n":24,"t":"사람의 걸음은 여호와께로서 말미암나니 사람이 어찌 자기의 길을 알 수 있으랴"},{"n":25,"t":"함부로 이 물건을 거룩하다하여 서원하고 그 후에 살피면 그것이 그물이 되느니라"},{"n":26,"t":"지혜로운 왕은 악인을 키질하며 타작하는 바퀴로 그 위에 굴리느니라"},{"n":27,"t":"사람의 영혼은 여호와의 등불이라 사람의 깊은 속을 살피느니라"},{"n":28,"t":"왕은 인자와 진리로 스스로 보호하고 그 위도 인자함으로 말미암아 견고하니라"},{"n":29,"t":"젊은 자의 영화는 그 힘이요 늙은 자의 아름다운 것은 백발이니라"},{"n":30,"t":"상하게 때리는 것이 악을 없이 하나니 매는 사람의 속에 깊이 들어가느니라"}],"kids":[{"n":1,"t":"포도주는 사람을 잘난 척하게 하고 독한 술은 떠들게 만들어. 거기에 빠지는 사람은 분별이 없는 사람이야."},{"n":2,"t":"왕의 화는 사자가 으르렁대는 소리 같아서 왕을 화나게 하는 것은 자기 목숨을 위험하게 하는 일이야."},{"n":3,"t":"다툼을 피하는 것이 사람에게 영광이지만 어리석은 사람은 항상 다툼을 일으켜."},{"n":4,"t":"게으른 사람은 가을에 밭을 갈지 않으니까 추수 때 거두려 해도 아무것도 거둘 게 없게 돼."},{"n":5,"t":"사람의 마음속 생각은 깊은 물 같지만 깨달은 사람은 그것을 잘 길어 낼 줄 알아."},{"n":6,"t":"많은 사람이 자기 마음씨가 좋다고 자랑하지만 진짜 진실한 사람을 누가 만날 수 있을까?"},{"n":7,"t":"옳게 사는 사람의 자손에게는 복이 따라온단다."},{"n":8,"t":"재판 자리에 앉은 왕은 그 눈으로 모든 나쁜 일을 흩어지게 해."},{"n":9,"t":"\\"내 마음을 깨끗하게 했다, 내 죄를 다 씻었다\\" 하고 말할 수 있는 사람이 누가 있겠니?"},{"n":10,"t":"속이는 저울추와 속이는 되는 하나님이 다 싫어하셔."},{"n":11,"t":"아이라도 그가 하는 행동을 보면 마음이 깨끗한지, 정직한지 다 드러나."},{"n":12,"t":"듣는 귀와 보는 눈은 모두 하나님이 만드신 거야."},{"n":13,"t":"잠자기를 너무 좋아하면 가난해질 수 있어. 눈을 똑바로 뜨고 일해. 그러면 먹을 것이 풍성해질 거야."},{"n":14,"t":"물건을 살 때는 \\"별로다, 별로다\\" 하다가 사고 나서는 자기 흥정을 자랑하는 사람이 많아."},{"n":15,"t":"세상에 금이나 보석은 많지만 지혜로운 입술이야말로 더 귀한 보물이야."},{"n":16,"t":"모르는 사람의 보증을 함부로 선 사람의 옷을 담보로 잡고 낯선 사람을 보증한 사람에게는 책임을 단단히 물어야 해."},{"n":17,"t":"속여서 얻은 음식은 처음에는 맛있어 보여도 나중에는 입에 모래가 가득 차는 것 같아."},{"n":18,"t":"좋은 계획은 함께 의논해야 이루어지고 큰일을 할 때는 좋은 조언을 듣고 해야 해."},{"n":19,"t":"여기저기 다니며 수다 떠는 사람은 비밀을 새어 나가게 해. 입이 함부로 열리는 사람과는 가까이 사귀지 마라."},{"n":20,"t":"자기 아빠나 엄마를 저주하는 사람은 그 인생의 등불이 어둠 속에서 꺼지게 될 거야."},{"n":21,"t":"처음부터 너무 급하게 모은 재산은 결국 복이 되지 않아."},{"n":22,"t":"\\"내가 갚아 줄 거야\\" 하지 말고 하나님을 기다려. 하나님이 너를 구해 주실 거야."},{"n":23,"t":"속이는 저울추를 하나님이 싫어하시고 속이는 저울도 좋지 않은 거야."},{"n":24,"t":"사람의 걸음은 하나님이 인도하시는 거야. 사람이 어떻게 자기 갈 길을 다 알 수 있겠니?"},{"n":25,"t":"잘 살피지도 않고 \\"이것을 하나님께 드리겠다\\" 약속한 뒤에 후회하는 것은 자기에게 함정이 돼."},{"n":26,"t":"지혜로운 왕은 나쁜 사람들을 곡식 까부르듯 가려내어 그들 위에 단호한 결단을 내려."},{"n":27,"t":"사람의 마음은 하나님의 등불이라서 사람 마음속 깊은 곳까지 다 비추어 보셔."},{"n":28,"t":"왕은 사랑과 진실로 자기를 지키고 그 자리도 사랑으로 든든해진단다."},{"n":29,"t":"젊은이의 자랑은 그 힘이고 어르신의 아름다움은 흰머리야."},{"n":30,"t":"따끔한 매가 나쁜 마음을 없애 주기도 해. 매는 사람의 마음속 깊은 곳까지 닿는단다."}]}},{"chapter":21,"title":"왕의 마음","verses":{"krv":[{"n":1,"t":"왕의 마음이 여호와의 손에 있음이 마치 보의 물과 같아서 그가 임의로 인도하시느니라"},{"n":2,"t":"사람의 행위가 자기 보기에는 모두 정직하여도 여호와는 심령을 감찰하시느니라"},{"n":3,"t":"의와 공평을 행하는 것은 제사 드리는 것보다 여호와께서 기쁘게 여기시느니라"},{"n":4,"t":"눈이 높은 것과 마음이 교만한 것과 악인의 형통한 것은 다 죄니라"},{"n":5,"t":"부지런한 자의 경영은 풍부함에 이를 것이나 조급한 자는 궁핍함에 이를 따름이니라"},{"n":6,"t":"속이는 말로 재물을 모으는 것은 죽음을 구하는 것이라 곧 불려 다니는 안개니라"},{"n":7,"t":"악인의 강포는 자기를 소멸하나니 이는 공의 행하기를 싫어함이니라"},{"n":8,"t":"죄를 크게 범한 자의 길은 심히 구부러지고 깨끗한 자의 길은 곧으니라"},{"n":9,"t":"다투는 여인과 함께 큰 집에서 나는 것보다 움막에서 혼자 사는 것이 나으니라"},{"n":10,"t":"악인의 마음은 남의 재앙을 원하나니 그 이웃도 그 앞에서 은혜를 입지 못하느니라"},{"n":11,"t":"거만한 자가 벌을 받으면 어리석은 자는 경성하겠고 지혜로운 자가 교훈을 받으면 지식이 더 하리라"},{"n":12,"t":"의로우신 자는 악인의 집을 감찰하시고 악인을 환난에 던지시느니라"},{"n":13,"t":"귀를 막아 가난한 자의 부르짖는 소리를 듣지 아니하면 자기의 부르짖을 때에도 들을 자가 없으리라"},{"n":14,"t":"은밀한 선물은 노를 쉬게 하고 품의 뇌물은 맹렬한 분을 그치게 하느니라"},{"n":15,"t":"공의를 행하는 것이 의인에게는 즐거움이요 죄인에게는 패망이니라"},{"n":16,"t":"명철의 길을 떠난 사람은 사망의 회중에 거하리라"},{"n":17,"t":"연락을 좋아하는 자는 가난하게 되고 술과 기름을 좋아하는 자는 부하게 되지 못하느니라"},{"n":18,"t":"악인은 의인의 대속이 되고 궤사한 자는 정직한 자의 대신이 되느니라"},{"n":19,"t":"다투며 성내는 여인과 함께 사는 것보다 광야에서 혼자 사는 것이 나으니라"},{"n":20,"t":"지혜있는 자의 집에는 귀한 보배와 기름이 있으나 미련한 자는 이것을 다 삼켜버리느니라"},{"n":21,"t":"의와 인자를 따라 구하는 자는 생명과 의와 영광을 얻느니라"},{"n":22,"t":"지혜로운 자는 용사의 성에 올라가서 그 성의 견고히 의뢰하는 것을 파하느니라"},{"n":23,"t":"입과 혀를 지키는 자는 그 영혼을 환난에서 보전하느니라"},{"n":24,"t":"무례하고 교만한 자를 이름하여 망령된 자라 하나니 이는 넘치는 교만으로 행함이니라"},{"n":25,"t":"게으른 자의 정욕이 그를 죽이나니 이는 그 손으로 일하기를 싫어 함이니라"},{"n":26,"t":"어떤 자는 종일토록 탐하기만 하나 의인은 아끼지 아니하고 시제하느니라"},{"n":27,"t":"악인의 제물은 본래 가증하거든 하물며 악한 뜻으로 드리는 것이랴"},{"n":28,"t":"거짓 증인은 패망하려니와 확실한 증인의 말은 힘이 있느니라"},{"n":29,"t":"악인은 그 얼굴을 굳게 하나 정직한 자는 그 행위를 삼가느니라"},{"n":30,"t":"지혜로도 명철로도 모략으로도 여호와를 당치 못하느니라"},{"n":31,"t":"싸울 날을 위하여 마병을 예비하거니와 이김은 여호와께 있느니라"}],"kids":[{"n":1,"t":"왕의 마음도 하나님의 손안에 있어서 시냇물처럼 하나님이 원하시는 방향으로 흘러가게 하셔."},{"n":2,"t":"사람은 자기 행동이 다 옳아 보이지만 하나님은 그 마음속까지 다 들여다보셔."},{"n":3,"t":"옳고 바르게 행동하는 것을 하나님은 제사 드리는 것보다 더 기뻐하셔."},{"n":4,"t":"잘난 척하는 눈빛과 교만한 마음 그리고 나쁜 사람이 잘되는 것까지 다 죄가 된단다."},{"n":5,"t":"부지런한 사람의 계획은 풍요로움에 이르지만 너무 급하게 서두르는 사람은 가난해질 뿐이야."},{"n":6,"t":"속여서 모은 재물은 사라지는 안개 같고 결국은 죽음을 부르는 거야."},{"n":7,"t":"나쁜 사람의 거친 행동은 자기를 망치게 돼. 옳은 일을 하기 싫어하기 때문이야."},{"n":8,"t":"큰 죄를 지은 사람의 길은 매우 비뚤어져 있지만 깨끗한 사람의 길은 곧단다."},{"n":9,"t":"자꾸 다투는 사람과 큰 집에서 함께 사는 것보다 작은 다락방에서 혼자 사는 게 차라리 나아."},{"n":10,"t":"나쁜 사람은 다른 사람이 잘못되기를 바라기 때문에 가까운 이웃에게도 친절하게 대하지 않아."},{"n":11,"t":"잘난 척하는 사람이 벌받는 모습을 보면 어리석은 사람도 슬기를 얻고 지혜로운 사람이 가르침을 받으면 지식이 더 풍성해져."},{"n":12,"t":"의로우신 하나님은 나쁜 사람의 집을 살펴보시고 결국 그 사람을 어려움 속에 던지셔."},{"n":13,"t":"가난한 사람의 부르짖는 소리에 귀를 막는 사람은 자기가 도움을 청할 때 아무도 들어 주지 않을 거야."},{"n":14,"t":"몰래 주는 선물이 화를 누그러뜨리고 조용히 건네는 보상이 거센 분노를 그치게 하기도 해."},{"n":15,"t":"옳은 일을 하는 것은 옳은 사람에게는 즐거움이지만 죄짓는 사람에게는 무너지는 일이 돼."},{"n":16,"t":"깨달음의 길에서 벗어난 사람은 결국 죽음의 자리에 머물게 돼."},{"n":17,"t":"흥청망청 즐기는 것만 좋아하는 사람은 가난해지고 술과 기름진 음식을 좋아하는 사람은 풍요로워질 수 없어."},{"n":18,"t":"옳은 사람을 대신해서 나쁜 사람이 벌을 받게 되고 정직한 사람을 대신해서 못된 사람이 책임을 지게 되기도 해."},{"n":19,"t":"다투며 자꾸 화내는 사람과 함께 사는 것보다 사람이 없는 빈 들에서 사는 게 차라리 나아."},{"n":20,"t":"지혜로운 사람의 집에는 귀한 보물과 기름이 있지만 어리석은 사람은 그것을 금세 다 써 버려."},{"n":21,"t":"정의와 사랑을 따라 살기를 구하는 사람은 생명과 의로움과 영광을 얻게 돼."},{"n":22,"t":"지혜로운 사람은 힘센 사람들이 지키는 성에 올라가서 그 성이 의지하는 방벽까지도 허물 수 있어."},{"n":23,"t":"입과 혀를 잘 지키는 사람은 자기 영혼을 어려움에서 지키는 거야."},{"n":24,"t":"무례하고 잘난 척하는 사람은 망령된 자라고 불리는데 자기 자랑이 넘쳐서 그렇게 행동하기 때문이야."},{"n":25,"t":"게으른 사람은 갖고 싶은 마음만 가득해서 자기를 죽게 만들어. 자기 손으로 일하기를 싫어하기 때문이지."},{"n":26,"t":"어떤 사람은 하루 종일 자기만 더 가지려 하지만 옳은 사람은 아끼지 않고 베푼단다."},{"n":27,"t":"나쁜 사람이 드리는 예물도 하나님이 싫어하시는데 하물며 나쁜 마음으로 드리는 것은 더더욱 그러시지."},{"n":28,"t":"거짓 증인은 결국 무너지지만 진실하게 들은 것을 전하는 사람의 말에는 힘이 있어."},{"n":29,"t":"나쁜 사람은 얼굴을 뻔뻔하게 하지만 정직한 사람은 자기 행동을 늘 조심해서 살펴."},{"n":30,"t":"어떤 지혜도, 깨달음도, 좋은 계획도 하나님을 이길 수는 없어."},{"n":31,"t":"사람이 싸움을 위해 말을 잘 준비할 수 있지만 승리는 결국 하나님께 달려 있어."}]}},{"chapter":22,"title":"선한 이름","verses":{"krv":[{"n":1,"t":"많은 재물보다 명예를 택할 것이요 은이나 금보다 은총을 더욱 택할 것이니라"},{"n":2,"t":"빈부가 섞여 살거니와 무릇 그들을 지으신 이는 여호와시니라"},{"n":3,"t":"슬기로운 자는 재앙을 보면 숨어 피하여도 어리석은 자들은 나아가다가 해를 받느니라"},{"n":4,"t":"겸손과 여호와를 경외함의 보응은 재물과 영광과 생명이니라"},{"n":5,"t":"패역한 자의 길에는 가시와 올무가 있거니와 영혼을 지키는 자는 이를 멀리 하느니라"},{"n":6,"t":"마땅히 행할 길을 아이에게 가르치라 그리하면 늙어도 그것을 떠나지 아니하리라"},{"n":7,"t":"부자는 가난한 자를 주관하고 빚진 자는 채주의 종이 되느니라"},{"n":8,"t":"악을 뿌리는 자는 재앙을 거두리니 그 분노의 기세가 쇠하리라"},{"n":9,"t":"선한 눈을 가진 자는 복을 받으리니 이는 양식을 가난한 자에게 줌이니라"},{"n":10,"t":"거만한 자를 쫓아내면 다툼이 쉬고 싸움과 수욕이 그치느니라"},{"n":11,"t":"마음의 정결을 사모하는 자의 입술에는 덕이 있으므로 임금이 그의 친구가 되느니라"},{"n":12,"t":"여호와께서는 지식있는 자를 그 눈으로 지키시나 궤사한 자의 말은 패하게 하시느니라"},{"n":13,"t":"게으른 자는 말하기를 사자가 밖에 있은즉 내가 나가면 거리에서 찢기겠다 하느니라"},{"n":14,"t":"음녀의 입은 깊은 함정이라 여호와의 노를 당한 자는 거기 빠지리라"},{"n":15,"t":"아이의 마음에는 미련한 것이 얽혔으나 징계하는 채찍이 이를 멀리 쫓아내리라"},{"n":16,"t":"이를 얻으려고 가난한 자를 학대하는 자와 부자에게 주는 자는 가난하여질 뿐이니라"},{"n":17,"t":"너는 귀를 기울여 지혜있는 자의 말씀을 들으며 내 지식에 마음을 둘지어다"},{"n":18,"t":"이것을 네 속에 보존하며 네 입술에 있게 함이 아름다우니라"},{"n":19,"t":"내가 너로 여호와를 의뢰하게 하려 하여 이것을 오늘 특별히 네게 알게 하였노니"},{"n":20,"t":"내가 모략과 지식의 아름다운 것을 기록하여"},{"n":21,"t":"너로 진리의 확실한 말씀을 깨닫게 하며 또 너를 보내는 자에게 진리의 말씀으로 회답하게 하려 함이 아니냐"},{"n":22,"t":"약한 자를 약하다고 탈취하지 말며 곤고한 자를 성문에서 압제하지 말라"},{"n":23,"t":"대저 여호와께서 신원하여 주시고 또 그를 노략하는 자의 생명을 빼앗으시리라"},{"n":24,"t":"노를 품는 자와 사귀지 말며 울분한 자와 동행하지 말지니"},{"n":25,"t":"그 행위를 본받아서 네 영혼을 올무에 빠칠까 두려움이니라"},{"n":26,"t":"너는 사람으로 더불어 손을 잡지 말며 남의 빚에 보증이 되지 말라"},{"n":27,"t":"만일 갚을 것이 없으면 네 누운 침상도 빼앗길 것이라 네가 어찌그리하겠느냐"},{"n":28,"t":"네 선조의 세운 옛 지계석을 옮기지 말지니라"},{"n":29,"t":"네가 자기 사업에 근실한 사람을 보았느냐 이러한 사람은 왕 앞에 설 것이요 천한 자 앞에 서지 아니하리라"}],"kids":[{"n":1,"t":"많은 재물보다 좋은 평판을 택하고 은이나 금보다 사람들의 사랑을 더 귀하게 여겨라."},{"n":2,"t":"부자와 가난한 사람이 함께 어울려 살지만 그 모두를 만드신 분은 한 분, 하나님이셔."},{"n":3,"t":"슬기로운 사람은 재앙이 다가오는 것을 보면 숨어 피하지만 어리석은 사람은 그냥 나가다가 해를 입어."},{"n":4,"t":"겸손하고 하나님을 두려워하는 사람은 재물과 영광과 생명을 보상으로 받아."},{"n":5,"t":"비뚤어진 사람의 길에는 가시와 함정이 가득하지만 자기 영혼을 지키는 사람은 그런 길을 멀리해."},{"n":6,"t":"아이에게 마땅히 가야 할 바른 길을 가르쳐라. 그러면 자라서도 그 길을 떠나지 않을 거야."},{"n":7,"t":"부자는 가난한 사람을 부리고 돈을 빌린 사람은 빌려준 사람의 일꾼처럼 끌려다니게 돼."},{"n":8,"t":"나쁜 마음을 뿌리는 사람은 재앙을 거둬들이고 그가 화내던 그 기세도 결국 사그라들어."},{"n":9,"t":"너그러운 눈으로 가난한 사람에게 음식을 나눠 주는 사람은 복을 받게 돼."},{"n":10,"t":"잘난 척하는 사람을 멀리하면 다툼이 그치고 싸움과 욕설도 멈춰."},{"n":11,"t":"깨끗한 마음을 사랑하는 사람은 그 입술에 좋은 말이 가득해서 왕도 그의 친구가 되고 싶어 해."},{"n":12,"t":"하나님의 눈은 지식을 가진 사람을 지켜 주시고 못된 사람의 말은 결국 무너지게 하셔."},{"n":13,"t":"게으른 사람은 \\"밖에 사자가 있어서 나가면 거리에서 잡혀 먹힌다\\" 하고 핑계를 댄단다."},{"n":14,"t":"유혹하는 사람의 입은 깊은 함정 같아서 하나님의 화를 산 사람이 그 안에 빠지게 돼."},{"n":15,"t":"아이의 마음에는 어리석음이 자연스럽게 얽혀 있지만 바른 가르침으로 채찍처럼 잡아 주면 그것을 멀리 떨쳐 낼 수 있어."},{"n":16,"t":"이익을 얻으려고 가난한 사람을 괴롭히는 사람이나 이미 부자인 사람에게 또 주는 사람은 결국 자기가 가난해질 뿐이야."},{"n":17,"t":"귀를 기울여서 지혜로운 사람들의 말을 잘 듣고 내가 가르치는 지식에 마음을 두렴."},{"n":18,"t":"이 가르침을 마음속에 잘 간직하고 입술에 늘 함께 있게 하는 것은 정말 아름다운 일이야."},{"n":19,"t":"네가 하나님을 의지하게 하려고 오늘 특별히 이 가르침을 너에게 알려 주는 거야."},{"n":20,"t":"너를 위해 좋은 조언과 아름다운 지식 서른 가지를 적어 두었어."},{"n":21,"t":"진실한 말씀을 네가 깨닫게 하고 너를 보낸 사람에게 참된 말로 대답할 수 있게 해 주려는 거야."},{"n":22,"t":"약한 사람이 약하다고 해서 빼앗으려 하지 말고 어려운 사람을 재판 자리에서 함부로 누르지 마라."},{"n":23,"t":"하나님이 그 사람을 위해 변호해 주시고 그 사람을 괴롭힌 사람의 생명까지도 다 빼앗으실 거야."},{"n":24,"t":"화를 자주 내는 사람과 사귀지 말고 성을 잘 내는 사람과는 함께 다니지도 마라."},{"n":25,"t":"그 행동을 따라 하다가 네 영혼이 함정에 빠질 수 있기 때문이야."},{"n":26,"t":"함부로 다른 사람과 손을 잡고 약속하지 말고 남의 빚을 대신 갚아 주는 보증을 서지 마라."},{"n":27,"t":"만약 갚을 돈이 없으면 네가 자는 침대까지 빼앗기게 될지도 몰라. 왜 그렇게 위험한 일을 하려 하니?"},{"n":28,"t":"네 조상들이 세워 둔 오래된 경계 돌을 함부로 옮기지 마라."},{"n":29,"t":"자기 일에 능숙한 사람을 보았니? 그런 사람은 왕 앞에도 설 수 있고 평범한 사람들 사이에 머물러 있지 않을 거야."}]}},{"chapter":23,"title":"지혜자의 말씀","verses":{"krv":[{"n":1,"t":"네가 관원과 함께 앉아 음식을 먹게 되거든 삼가 네 앞에 있는 자가 누구인지 생각하며"},{"n":2,"t":"네가 만일 탐식자여든 네 목에 칼을 둘 것이니라"},{"n":3,"t":"그 진찬을 탐하지 말라 그것은 간사하게 베푼 식물이니라"},{"n":4,"t":"부자 되기에 애쓰지 말고 네 사사로운 지혜를 버릴지어다"},{"n":5,"t":"네가 어찌 허무한 것에 주목하겠느냐 정녕히 재물은 날개를 내어 하늘에 나는 독수리처럼 날아가리라"},{"n":6,"t":"악한 눈이 있는 자의 음식을 먹지 말며 그 진찬을 탐하지 말지어다"},{"n":7,"t":"대저 그 마음의 생각이 어떠하면 그 위인도 그러한즉 그가 너더러 먹고 마시라 할지라도 그 마음은 너와 함께하지 아니함이라"},{"n":8,"t":"네가 조금 먹은 것도 토하겠고 네 아름다운 말도 헛된 데로 돌아가리라"},{"n":9,"t":"미련한 자의 귀에 말하지 말지니 이는 그가 네 지혜로운 말을 업신여길 것임이니라"},{"n":10,"t":"옛 지계석을 옮기지 말며 외로운 자식의 밭을 침범하지 말찌어다"},{"n":11,"t":"대저 그들의 구속자는 강하시니 너를 대적하사 그 원을 펴시리라"},{"n":12,"t":"훈계에 착심하며 지식의 말씀에 귀를 기울이라"},{"n":13,"t":"아이를 훈계하지 아니치 말라 채찍으로 그를 때릴지라도 죽지 아니하리라"},{"n":14,"t":"그를 채찍으로 때리면 그 영혼을 음부에서 구원하리라"},{"n":15,"t":"내 아들아 만일 네 마음이 지혜로우면 나 곧 내 마음이 즐겁겠고"},{"n":16,"t":"만일 네 입술이 정직을 말하면 내 속이 유쾌하리라"},{"n":17,"t":"네 마음으로 죄인의 형통을 부러워하지 말고 항상 여호와를 경외하라"},{"n":18,"t":"정녕히 네 장래가 있겠고 네 소망이 끊어지지 아니하리라"},{"n":19,"t":"내 아들아 너는 듣고 지혜를 얻어 네 마음을 정로로 인도할지니라"},{"n":20,"t":"술을 즐겨하는 자와 고기를 탐하는 자로 더불어 사귀지 말라"},{"n":21,"t":"술 취하고 탐식하는 자는 가난하여질 것이요 잠자기를 즐겨하는자는 해어진 옷을 입을 것임이니라"},{"n":22,"t":"너 낳은 아비에게 청종하고 네 늙은 어미를 경히 여기지 말지니라"},{"n":23,"t":"진리를 사고서 팔지 말며 지혜와 훈계와 명철도 그리할지니라"},{"n":24,"t":"의인의 아비는 크게 즐거울 것이요 지혜로운 자식을 낳은 자는 그를 인하여 즐거울 것이니라"},{"n":25,"t":"네 부모를 즐겁게 하며 너 낳은 어미를 기쁘게 하라"},{"n":26,"t":"내 아들아 네 마음을 내게 주며 네 눈으로 내 길을 즐거워할지어다"},{"n":27,"t":"대저 음녀는 깊은 구렁이요 이방 여인은 좁은 함정이라"},{"n":28,"t":"그는 강도 같이 매복하며 인간에 궤사한 자가 많아지게 하느니라"},{"n":29,"t":"재앙이 뉘게 있느뇨 근심이 뉘게 있느뇨 분쟁이 뉘게 있느뇨 원망이 뉘게 있느뇨 까닭없는 창상이 뉘게 있느뇨 붉은 눈이 뉘게 있느뇨"},{"n":30,"t":"술에 잠긴 자에게 있고 혼합한 술을 구하러 다니는 자에게 있느니라"},{"n":31,"t":"포도주는 붉고 잔에서 번쩍이며 순하게 내려가나니 너는 그것을 보지도 말지어다"},{"n":32,"t":"이것이 마침내 뱀 같이 물 것이요 독사 같이 쏠 것이며"},{"n":33,"t":"또 네 눈에는 괴이한 것이 보일 것이요 네 마음은 망령된 것을 발할 것이며"},{"n":34,"t":"너는 바다 가운데 누운 자 같을 것이요 돛대 위에 누운 자 같을 것이며"},{"n":35,"t":"네가 스스로 말하기를 사람이 나를 때려도 나는 아프지 아니하고 나를 상하게 하여도 내게 감각이 없도다 내가 언제나 깰까 다시 술을 찾겠다 하리라"}],"kids":[{"n":1,"t":"높은 사람과 함께 식사를 하게 되면 네 앞에 있는 사람이 누구인지 잘 생각해."},{"n":2,"t":"만약 네가 음식을 마음껏 탐하는 사람이라면 스스로 자기 입에 칼을 대듯 조심해야 해."},{"n":3,"t":"그 사람이 차린 맛있는 음식을 너무 탐내지 마라. 그것은 너를 속이는 음식일 수 있어."},{"n":4,"t":"부자가 되려고 너무 애쓰지 말고 그런 잔꾀를 부리는 일도 그만둬."},{"n":5,"t":"잠시 보이던 재물에 왜 마음을 빼앗기니? 재물은 어느새 날개를 달고 독수리처럼 하늘로 날아가 버려."},{"n":6,"t":"인색한 사람의 음식은 먹지 말고 그가 차린 맛있는 음식을 탐내지 마라."},{"n":7,"t":"그 사람은 마음속으로 늘 계산하는 사람이라서 \\"어서 먹고 마셔라\\" 말해도 그의 마음은 너와 함께 있지 않아."},{"n":8,"t":"결국 네가 조금 먹은 것까지 토하게 될 거고 네가 했던 좋은 말도 헛된 곳으로 가 버릴 거야."},{"n":9,"t":"어리석은 사람에게는 함부로 말하지 마라. 네가 한 지혜로운 말도 우습게 여길 거니까."},{"n":10,"t":"아주 오래된 경계 돌을 옮기지 말고 부모 없는 아이들의 밭을 함부로 침범하지 마라."},{"n":11,"t":"그들의 편이 되어 주시는 분이 강하셔. 그분이 너를 막아서 그 아이들을 위해 변호해 주실 거야."},{"n":12,"t":"가르침에 마음을 두고 지식의 말씀에 귀를 기울여."},{"n":13,"t":"아이를 가르치는 것을 그만두지 마라. 따끔하게 매로 가르친다고 해서 아이가 죽지는 않아."},{"n":14,"t":"매로 잘 가르치면 그 아이의 영혼을 죽음에서 구할 수 있단다."},{"n":15,"t":"내 아들아, 네 마음이 지혜로우면 내 마음도 그만큼 즐거울 거야."},{"n":16,"t":"네 입에서 정직한 말이 나오면 내 마음속도 시원해질 거야."},{"n":17,"t":"죄짓는 사람이 잘되는 것을 마음으로 부러워하지 말고 항상 하나님을 두려워하고 공경해라."},{"n":18,"t":"그러면 네 미래가 분명히 있고 네 희망이 끊어지지 않을 거야."},{"n":19,"t":"내 아들아, 잘 듣고 지혜를 얻어서 네 마음을 바른 길로 이끌어 가렴."},{"n":20,"t":"술을 즐기는 사람들이나 고기를 탐하는 사람들과는 가까이 어울리지 마라."},{"n":21,"t":"술에 취하고 음식만 탐하는 사람은 가난해지고 잠만 자려는 사람은 해진 옷을 입게 될 거야."},{"n":22,"t":"너를 낳아 주신 아빠 말씀을 잘 듣고 나이 드신 엄마를 가볍게 여기지 마라."},{"n":23,"t":"진리를 사 두고 절대로 팔지 마. 지혜와 가르침과 깨달음도 그렇게 소중히 여겨라."},{"n":24,"t":"옳은 사람의 아빠는 큰 기쁨을 누리고 지혜로운 자식을 둔 부모는 그 자식 때문에 기뻐해."},{"n":25,"t":"너의 부모님을 기쁘게 해 드리고 너를 낳아 주신 엄마를 즐겁게 해 드려라."},{"n":26,"t":"내 아들아, 네 마음을 내게 맡기고 네 눈으로 내가 가르치는 길을 즐겁게 보아라."},{"n":27,"t":"유혹하는 사람은 깊은 구덩이 같고 낯선 유혹은 좁은 함정 같아."},{"n":28,"t":"그런 사람은 마치 강도처럼 숨어 기다리면서 사람들 사이에 못된 사람들을 더 많아지게 만들어."},{"n":29,"t":"누구에게 재앙이 있을까? 누구에게 근심이 있을까? 누구에게 다툼과 원망이 있고 까닭 없는 상처와 빨갛게 핏발 선 눈이 있을까?"},{"n":30,"t":"그건 술에 빠진 사람과 잘 섞은 술을 찾아 헤매는 사람에게 있단다."},{"n":31,"t":"포도주가 붉게 빛나고 잔 속에서 반짝이며 부드럽게 넘어간다고 해도 그것을 너무 빤히 보지도 마라."},{"n":32,"t":"그것이 결국에는 뱀처럼 물고 독사처럼 쏘게 되니까."},{"n":33,"t":"그러면 네 눈에는 이상한 것들이 보이고 네 마음은 비뚤어진 말을 하게 될 거야."},{"n":34,"t":"너는 마치 바다 위에 떠 있는 것 같고 흔들리는 돛대 위에 누워 있는 것처럼 어지러워질 거야."},{"n":35,"t":"그러고도 \\"누가 때려도 안 아프고 나를 다치게 해도 느낌이 없네. 언제쯤 깰까? 깨면 또 술을 찾아야지\\" 하고 말하게 될 거야."}]}},{"chapter":24,"title":"악인을 부러워하지 말라","verses":{"krv":[{"n":1,"t":"너는 악인의 형통을 부러워하지 말며 그와 함께 있기도 원하지 말지어다"},{"n":2,"t":"그들의 마음은 강포를 품고 그 입술은 잔해를 말함이니라"},{"n":3,"t":"집은 지혜로 말미암아 건축되고 명철로 말미암아 견고히 되며"},{"n":4,"t":"또 방들은 지식으로 말미암아 각종 귀하고 아름다운 보배로 채우게 되느니라"},{"n":5,"t":"지혜 있는 자는 강하고 지식 있는 자는 힘을 더하나니"},{"n":6,"t":"너는 모략으로 싸우라 승리는 모사가 많음에 있느니라"},{"n":7,"t":"지혜는 너무 높아서 미련한 자의 미치지 못할 것이므로 그는 성 문에서 입을 열지 못하느니라"},{"n":8,"t":"악을 행하기를 꾀하는 자를 일컬어 사특한 자라 하느니라"},{"n":9,"t":"미련한 자의 생각은 죄요 거만한 자는 사람의 미움을 받느니라"},{"n":10,"t":"네가 만일 환난날에 낙담하면 네 힘의 미약함을 보임이니라"},{"n":11,"t":"너는 사망으로 끌려가는 자를 건져주며 살륙을 당하게 된 자를 구원하지 아니치 말라"},{"n":12,"t":"네가 말하기를 나는 그것을 알지 못하였노라 할지라도 마음을 저울질 하시는 이가 어찌 통찰하지 못하시겠으며 네 영혼을 지키시는 이가 어찌 알지 못하시겠느냐 그가 각 사람의 행위대로 보증 하시리라"},{"n":13,"t":"내 아들아 꿀을 먹으라 이것이 좋으니라 송이꿀을 먹으라 이것이 네 입에 다니라"},{"n":14,"t":"지혜가 네 영혼에게 이와 같은 줄을 알라 이것을 얻으면 정녕히 네 장래가 있겠고 네 소망이 끊어지지 아니하리라"},{"n":15,"t":"악한 자여 의인의 집을 엿보지 말며 그 쉬는 처소를 헐지 말지니라"},{"n":16,"t":"대저 의인은 일곱번 넘어질지라도 다시 일어나려니와 악인은 재앙으로 인하여 엎드러지느니라"},{"n":17,"t":"네 원수가 넘어질 때에 즐거워하지 말며 그가 엎드러질 때에 마음에 기뻐하지 말라"},{"n":18,"t":"여호와께서 이것을 보시고 기뻐 아니하사 그 진노를 그에게서 옮기실까 두려우니라"},{"n":19,"t":"너는 행악자의 득의함을 인하여 분을 품지 말며 악인의 형통을 부러워하지 말라"},{"n":20,"t":"대저 행악자는 장래가 없겠고 악인의 등불은 꺼지리라"},{"n":21,"t":"내 아들아 여호와와 왕을 경외하고 반역자로 더불어 사귀지 말라"},{"n":22,"t":"대저 그들의 재앙은 속히 임하리니 이 두 자의 멸망을 누가 알랴"},{"n":23,"t":"이것도 지혜로운 자의 말씀이라 재판할 때에 낯을 보아주는 것이 옳지 못하니라"},{"n":24,"t":"무릇 악인더러 옳다 하는 자는 백성에게 저주를 받을 것이요 국민에게 미움을 받으려니와"},{"n":25,"t":"오직 그를 견책하는 자는 기쁨을 얻을 것이요 또 좋은 복을 받으리라"},{"n":26,"t":"적당한 말로 대답함은 입맞춤과 같으니라"},{"n":27,"t":"네 일을 밖에서 다스리며 밭에서 예비하고 그 후에 네 집을 세울지니라"},{"n":28,"t":"너는 까닭없이 네 이웃을 쳐서 증인이 되지 말며 네 입술로 속이지 말지니라"},{"n":29,"t":"너는 그가 내게 행함 같이 나도 그에게 행하여 그 행한대로 갚겠다 말하지 말지니라"},{"n":30,"t":"내가 증왕에 게으른 자의 밭과 지혜 없는 자의 포도원을 지나며 본즉"},{"n":31,"t":"가시덤불이 퍼졌으며 거친 풀이 지면에 덮였고 돌담이 무너졌기 로"},{"n":32,"t":"내가 보고 생각이 깊었고 내가 보고 훈계를 받았었노라"},{"n":33,"t":"네가 좀더 자자, 좀더 졸자, 손을 모으고 좀더 눕자 하니 네 빈궁이 강도 같이 오며"},{"n":34,"t":"네 곤핍이 군사 같이 이르리라"}],"kids":[{"n":1,"t":"나쁜 사람이 잘되는 것을 부러워하지 말고 그런 사람과 함께 있으려고 하지도 마라."},{"n":2,"t":"그 사람들은 마음에 거친 생각을 품고 그 입술은 재앙이 되는 말을 한단다."},{"n":3,"t":"집은 지혜로 세워지고 깨달음으로 든든해져."},{"n":4,"t":"그리고 방마다 지식으로 각종 귀하고 아름다운 보물이 가득 채워진단다."},{"n":5,"t":"지혜로운 사람은 강하고 지식이 있는 사람은 그 힘이 더 커져."},{"n":6,"t":"좋은 계획으로 싸워라. 승리는 좋은 조언이 많은 데서 나오는 거야."},{"n":7,"t":"지혜는 어리석은 사람이 닿기에 너무 높은 곳에 있어. 그래서 어리석은 사람은 사람들이 모인 자리에서 입도 열지 못해."},{"n":8,"t":"나쁜 일을 일부러 꾸미는 사람을 사람들은 사악한 자라고 불러."},{"n":9,"t":"어리석은 사람이 꾸미는 생각은 죄가 되고 잘난 척하는 사람은 사람들의 미움을 받아."},{"n":10,"t":"어려운 날에 쉽게 낙담하면 너의 힘이 약하다는 걸 보여 주는 거야."},{"n":11,"t":"죽음으로 끌려가는 사람을 못 본 척하지 말고 위험에 처한 사람을 구해 주는 일을 외면하지 마라."},{"n":12,"t":"\\"몰랐어요\\" 하고 변명해도 마음을 보시는 하나님이 그것을 모르실까? 너의 영혼을 지키시는 분이 모르실 리 없어. 그분은 사람마다 자기 행동에 맞게 갚아 주셔."},{"n":13,"t":"내 아들아, 꿀을 먹어 봐. 좋은 거란다. 송이꿀은 네 입에 달콤할 거야."},{"n":14,"t":"지혜도 네 영혼에 그와 같이 달콤하단다. 지혜를 얻으면 너의 앞날이 분명히 있고 네 희망이 끊어지지 않아."},{"n":15,"t":"나쁜 사람아, 옳은 사람의 집을 노리지 말고 그가 쉬고 있는 자리를 무너뜨리지 마라."},{"n":16,"t":"옳은 사람은 일곱 번 넘어져도 다시 일어나지만 나쁜 사람은 재앙 한 번에 무너져 버려."},{"n":17,"t":"너의 원수가 넘어질 때 좋아하지 말고 그가 무너질 때 마음으로 기뻐하지 마라."},{"n":18,"t":"그러면 하나님이 보시고 마음 아파하시며 그 화를 그 사람에게서 옮기실 수도 있어."},{"n":19,"t":"나쁜 일 하는 사람들 때문에 화내지 말고 나쁜 사람이 잘되는 것을 부러워하지 마라."},{"n":20,"t":"나쁜 일 하는 사람에게는 미래가 없고 나쁜 사람의 등불은 결국 꺼지게 돼."},{"n":21,"t":"내 아들아, 하나님을 두려워하고 왕을 공경해라. 그리고 거역하는 사람들과는 어울리지 마라."},{"n":22,"t":"그런 사람들에게는 재앙이 갑자기 닥치는데 그 두 사람이 어떻게 무너질지 누가 다 알겠니?"},{"n":23,"t":"이것도 지혜로운 사람들이 한 말씀이야. 재판할 때 사람의 얼굴을 봐 가며 다르게 판단하는 것은 옳지 않아."},{"n":24,"t":"나쁜 사람을 \\"네가 옳다\\" 해 주는 사람은 백성에게 욕을 듣고 사람들의 미움을 받아."},{"n":25,"t":"그러나 그런 사람을 바르게 꾸짖는 사람은 기쁨을 얻고 좋은 복도 받게 돼."},{"n":26,"t":"알맞은 말로 대답하는 것은 마치 친한 사람의 입맞춤처럼 따뜻한 거야."},{"n":27,"t":"먼저 밖에서 할 일을 잘 마치고 밭일도 끝낸 다음에 네 집을 세워라."},{"n":28,"t":"까닭 없이 이웃을 거짓 증인으로 해치지 말고 네 입술로 속이지도 마라."},{"n":29,"t":"\\"그 사람이 나에게 한 대로 나도 똑같이 갚아 줄 거야\\" 하고 말하지 마라."},{"n":30,"t":"내가 한 게으른 사람의 밭과 분별 없는 사람의 포도원을 지나며 보니"},{"n":31,"t":"가시덤불이 온 밭에 퍼져 있고 거친 풀이 땅을 다 덮었으며 돌담도 무너져 있었어."},{"n":32,"t":"그것을 보고 나는 깊이 생각했고 큰 교훈을 얻었단다."},{"n":33,"t":"\\"조금만 더 자자, 조금만 더 졸자, 손을 모으고 잠깐만 더 눕자\\" 하다 보면"},{"n":34,"t":"가난이 갑자기 도둑처럼 들이닥치고 어려움이 무장한 군사처럼 너에게 찾아올 거야."}]}},{"chapter":25,"title":"왕 앞의 지혜","verses":{"krv":[{"n":1,"t":"이것도 솔로몬의 잠언이요 유다 왕 히스기야의 신하들의 편집한 것이니라"},{"n":2,"t":"일을 숨기는 것은 하나님의 영화요 일을 살피는 것은 왕의 영화니라"},{"n":3,"t":"하늘의 높음과 땅의 깊음 같이 왕의 마음은 헤아릴 수 없느니라"},{"n":4,"t":"은에서 찌끼를 제하라 그리하면 장색의 쓸만한 그릇이 나올 것이요"},{"n":5,"t":"왕 앞에서 악한 자를 제하라 그리하면 그 위가 의로 말미암아 견고히 서리라"},{"n":6,"t":"왕 앞에서 스스로 높은 체 하지말며 대인의 자리에 서지 말라"},{"n":7,"t":"이는 사람이 너더러 이리로 올라오라 하는 것이 네 눈에 보이는 귀인 앞에서 저리로 내려가라 하는 것보다 나음이니라"},{"n":8,"t":"너는 급거히 나가서 다투지 말라 마침내 네가 이웃에게 욕을 보게 될 때에 네가 어찌 할 줄을 알지 못할까 두려우니라"},{"n":9,"t":"너는 이웃과 다투거든 변론만 하고 남의 은밀한 일을 누설하지 말라"},{"n":10,"t":"듣는 자가 너를 꾸짖을 터이요 또 수욕이 네게서 떠나지 아니할까 두려우니라"},{"n":11,"t":"경우에 합당한 말은 아로새긴 은쟁반에 금사과니라"},{"n":12,"t":"슬기로운 자의 책망은 청종하는 귀에 금고리와 정금 장식이니라"},{"n":13,"t":"충성된 사자는 그를 보낸 이에게 마치 추수하는 날에 얼음 냉수 같아서 능히 그 주인의 마음을 시원케 하느니라"},{"n":14,"t":"선물한다고 거짓 자랑하는 자는 비 없는 구름과 바람 같으니라"},{"n":15,"t":"오래 참으면 관원이 그 말을 용납하나니 부드러운 혀는 뼈를 꺾느니라"},{"n":16,"t":"너는 꿀을 만나거든 족하리만큼 먹으라 과식하므로 토할까 두려우니라"},{"n":17,"t":"너는 이웃집에 자주 다니지 말라 그가 너를 싫어하며 미워할까 두려우니라"},{"n":18,"t":"그 이웃을 쳐서 거짓 증거하는 사람은 방망이요 칼이요 뾰족한 살이니라"},{"n":19,"t":"환난날에 진실치 못한 자를 의뢰하는 의뢰는 부러진 이와 위골된 발 같으니라"},{"n":20,"t":"마음이 상한 자에게 노래하는 것은 추운 날에 옷을 벗음 같고 쏘다 위에 초를 부음 같으니라"},{"n":21,"t":"네 원수가 배고파하거든 식물을 먹이고 목말라하거든 물을 마시우라"},{"n":22,"t":"그리하는 것은 핀 숯으로 그의 머리에 놓는 것과 일반이요 여호와께서는 네게 상을 주시리라"},{"n":23,"t":"북풍이 비를 일으킴 같이 참소하는 혀는 사람의 얼굴에 분을 일으키느니라"},{"n":24,"t":"다투는 여인과 함께 큰 집에서 사는 것보다 움막에서 혼자 사는 것이 나으니라"},{"n":25,"t":"먼 땅에서 오는 좋은 기별은 목마른 사람에게 냉수 같으니라"},{"n":26,"t":"의인이 악인 앞에 굴복하는 것은 우물의 흐리어짐과 샘의 더러워짐 같으니라"},{"n":27,"t":"꿀을 많이 먹는 것이 좋지 못하고 자기의 영예를 구하는 것이 헛되니라"},{"n":28,"t":"자기의 마음을 제어하지 아니하는 자는 성읍이 무너지고 성벽이 없는 것 같으니라"}],"kids":[{"n":1,"t":"이것 또한 솔로몬의 잠언인데 유다 왕 히스기야 시대의 신하들이 모아 정리한 거야."},{"n":2,"t":"어떤 일을 비밀로 두시는 것은 하나님의 영광이고 그 일을 깊이 살펴 밝히는 것은 왕의 영광이야."},{"n":3,"t":"하늘이 높고 땅이 깊은 것처럼 왕의 마음도 사람이 다 헤아릴 수 없어."},{"n":4,"t":"은에서 찌꺼기를 걸러 내야 솜씨 좋은 장인이 좋은 그릇을 만들 수 있어."},{"n":5,"t":"왕 앞에서 나쁜 사람을 멀리하면 그 왕의 자리가 옳음 위에 든든히 서게 돼."},{"n":6,"t":"왕 앞에서 잘난 척하지 말고 큰 사람들이 앉는 자리에 함부로 서지도 마라."},{"n":7,"t":"\\"이리 올라와 앉으세요\\" 하고 누군가 권하는 게 너의 눈앞에서 귀한 사람 앞에서 낮아지는 것보다 훨씬 나아."},{"n":8,"t":"서둘러 나가서 누구와 다투지 마라. 결국 이웃에게 욕을 들었을 때 어떻게 해야 할지 몰라 곤란해질 수 있으니까."},{"n":9,"t":"이웃과 다툴 일이 있으면 그 사람과 직접 이야기해서 풀고 다른 사람의 비밀까지 함부로 흘리지 마라."},{"n":10,"t":"듣는 사람이 너를 꾸짖을 거고 너에 대한 나쁜 말이 계속 따라다닐 수도 있어."},{"n":11,"t":"때에 맞는 말은 은쟁반에 놓인 금 사과처럼 아름다워."},{"n":12,"t":"슬기로운 사람의 충고는 잘 듣는 사람에게 금 귀고리나 순금 장식 같아."},{"n":13,"t":"신실한 일꾼은 그를 보낸 사람에게 추수 날의 시원한 얼음물 같아서 그 주인의 마음을 시원하게 해 줘."},{"n":14,"t":"\\"선물을 주겠다\\" 하고서 거짓으로 떠벌리는 사람은 비 한 방울 없이 지나가는 구름과 바람 같아."},{"n":15,"t":"오래 참으면 높은 사람도 설득할 수 있고 부드러운 말은 단단한 뼈도 부러뜨릴 만큼 힘이 있어."},{"n":16,"t":"꿀을 보더라도 알맞게만 먹어. 너무 많이 먹으면 토할 수 있으니까."},{"n":17,"t":"이웃집에 너무 자주 드나들지 마라. 그렇게 하면 결국 너를 싫어하게 될 수 있어."},{"n":18,"t":"이웃을 거짓 증거로 해치는 사람은 방망이와 칼과 날카로운 화살 같단다."},{"n":19,"t":"어려운 때 진실하지 못한 사람을 의지하는 것은 부러진 이로 음식을 씹고 삐끗한 발로 걷는 것과 같아."},{"n":20,"t":"마음이 상한 사람 앞에서 신나는 노래를 부르는 것은 추운 날에 옷을 벗기는 것 같고 소다 위에 식초를 붓는 것 같아."},{"n":21,"t":"너의 원수가 배가 고프면 먹을 것을 주고 목이 마르면 물을 마시게 해 줘."},{"n":22,"t":"그렇게 하면 그 사람의 머리 위에 뜨거운 숯불을 쌓는 것과 같고 하나님이 너에게 갚아 주실 거야."},{"n":23,"t":"북풍이 비를 몰고 오듯이 뒤에서 험담하는 혀는 사람들의 얼굴에 화를 불러일으켜."},{"n":24,"t":"자꾸 다투는 사람과 큰 집에서 함께 사는 것보다 작은 다락방에서 혼자 사는 게 차라리 나아."},{"n":25,"t":"먼 곳에서 오는 좋은 소식은 목마른 사람에게 시원한 냉수 같단다."},{"n":26,"t":"옳은 사람이 나쁜 사람 앞에 무릎을 꿇는 것은 깨끗한 우물이 흐려지고 맑은 샘이 더러워지는 것과 같아."},{"n":27,"t":"꿀도 너무 많이 먹으면 좋지 않고 자기 영광을 너무 찾는 것도 헛된 일이야."},{"n":28,"t":"자기 마음을 다스리지 못하는 사람은 성벽이 무너진 성처럼 무방비 상태가 되어 버려."}]}},{"chapter":26,"title":"미련한 자와 게으른 자","verses":{"krv":[{"n":1,"t":"미련한 자에게는 영예가 적당하지 아니하니 마치 여름에 눈오는 것과 추수 때에 비오는 것 같으니라"},{"n":2,"t":"까닭 없는 저주는 참새의 떠도는 것과 제비의 날아가는 것 같이 이르지 아니하느니라"},{"n":3,"t":"말에게는 채찍이요 나귀에게는 자갈이요 미련한 자의 등에는 막대기니라"},{"n":4,"t":"미련한 자의 어리석은 것을 따라 대답하지 말라 두렵건대 네가 그와 같을까 하노라"},{"n":5,"t":"미련한 자의 어리석은 것을 따라 그에게 대답하라 두렵건대 그가 스스로 지혜롭게 여길까 하노라"},{"n":6,"t":"미련한자 편에 기별하는 것은 자기의 발을 베어 버림이라 해를 받느니라"},{"n":7,"t":"저는 자의 다리는 힘 없이 달렸나니 미련한 자의 입의 잠언도 그러하니라"},{"n":8,"t":"미련한 자에게 영예를 주는 것은 돌을 물매에 매는 것과 같으니라"},{"n":9,"t":"미련한 자의 입의 잠언은 술 취한 자의 손에 든 가시나무 같으니라"},{"n":10,"t":"장인이 온갖 것을 만들지라도 미련한 자를 고용하는 것은 지나가는 자를 고용함과 같으니라"},{"n":11,"t":"개가 그 토한 것을 도로 먹는 것 같이 미련한 자는 그 미련한 것을 거듭 행하느니라"},{"n":12,"t":"네가 스스로 지혜롭게 여기는 자를 보느냐 그보다 미련한 자에게 오히려 바랄 것이 있느니라"},{"n":13,"t":"게으른 자는 길에 사자가 있다 거리에 사자가 있다 하느니라"},{"n":14,"t":"문짝이 돌쩌귀를 따라서 도는 것 같이 게으른 자는 침상에서 구으느니라"},{"n":15,"t":"게으른 자는 그 손을 그릇에 넣고도 입으로 올리기를 괴로와 하느니라"},{"n":16,"t":"게으른 자는 선히 대답하는 사람 일곱보다 자기를 지혜롭게 여기느니라"},{"n":17,"t":"길로 지나다가 자기에게 상관없는 다툼을 간섭하는 자는 개 귀를 잡는 자와 같으니라"},{"n":18,"t":"횃불을 던지며 살을 쏘아서 사람을 죽이는 미친 사람이 있나니"},{"n":19,"t":"자기 이웃을 속이고 말하기를 내가 희롱하였노라 하는 자도 그러하니라"},{"n":20,"t":"나무가 다하면 불이 꺼지고 말장이가 없어지면 다툼이 쉬느니라"},{"n":21,"t":"숯불 위에 숯을 더하는 것과 타는 불에 나무를 더하는 것 같이 다툼을 좋아하는 자는 시비를 일으키느니라"},{"n":22,"t":"남의 말하기를 좋아하는 자의 말은 별식과 같아서 뱃 속 깊은 데로 내려가느니라"},{"n":23,"t":"온유한 입술에 악한 마음은 낮은 은을 입힌 토기니라"},{"n":24,"t":"감정있는 자는 입술로는 꾸미고 속에는 궤휼을 품나니"},{"n":25,"t":"그 말이 좋을지라도 믿지 말 것은 그 마음에 일곱 가지 가증한 것이 있음이라"},{"n":26,"t":"궤휼로 그 감정을 감출지라도 그 악이 회중 앞에 드러나리라"},{"n":27,"t":"함정을 파는 자는 그것에 빠질 것이요 돌을 굴리는 자는 도리어 그것에 치이리라"},{"n":28,"t":"거짓말하는 자는 자기의 해한 자를 미워하고 아첨하는 입은 패망을 일으키느니라"}],"kids":[{"n":1,"t":"어리석은 사람에게 영광이 어울리지 않는 것은 여름에 눈이 오는 것이나 추수철에 비가 오는 것 같아."},{"n":2,"t":"까닭 없는 저주는 휙 날아가는 참새나 제비처럼 너에게 닿지 못해."},{"n":3,"t":"말에게는 채찍이 필요하고 당나귀에게는 재갈이 필요하듯이 어리석은 사람에게는 매가 필요해."},{"n":4,"t":"어리석은 사람의 어리석은 말에 똑같이 어리석게 대답하지 마라. 너도 그와 같이 될 수 있어."},{"n":5,"t":"그러나 어리석은 사람에게는 때로 그 어리석음에 맞게 대답해 주어야 해. 그러지 않으면 자기가 진짜 지혜롭다고 생각할 거니까."},{"n":6,"t":"어리석은 사람 편에 중요한 소식을 보내는 것은 자기 발을 잘라 버리는 것과 같고 큰 손해를 보는 것과 같아."},{"n":7,"t":"절뚝거리는 사람의 다리에 힘이 없는 것처럼 어리석은 사람의 입에서 나오는 잠언도 그렇게 어울리지 않아."},{"n":8,"t":"어리석은 사람에게 영광을 주는 것은 돌을 물매에 매다는 것처럼 위험한 일이야."},{"n":9,"t":"어리석은 사람의 입에서 나오는 잠언은 술 취한 사람이 가시나무를 손에 들고 있는 것 같아."},{"n":10,"t":"누구나 어리석은 사람을 일꾼으로 고용하면 지나가는 낯선 사람에게 큰일을 맡기는 것과 똑같아."},{"n":11,"t":"개가 자기가 토한 것을 다시 먹는 것처럼 어리석은 사람은 똑같이 어리석은 행동을 자꾸자꾸 반복해."},{"n":12,"t":"스스로 자기가 지혜롭다고 생각하는 사람을 보았니? 그런 사람보다는 차라리 어리석은 사람에게 더 희망이 있을 정도란다."},{"n":13,"t":"게으른 사람은 \\"길에 사자가 있어요, 거리에 사자가 있어서 못 가요\\" 하면서 핑계를 대."},{"n":14,"t":"문이 돌쩌귀에 매달려 빙글빙글 돌듯이 게으른 사람은 침대 위에서만 이리저리 뒤척여."},{"n":15,"t":"게으른 사람은 손을 그릇에 넣고도 입에 가져가는 것조차 귀찮아해."},{"n":16,"t":"게으른 사람은 똑똑하게 대답하는 일곱 사람보다 자기가 더 지혜롭다고 생각해."},{"n":17,"t":"길을 지나다가 자기와 상관 없는 남의 다툼에 끼어드는 사람은 마치 지나가는 개의 귀를 함부로 잡는 사람과 같아."},{"n":18,"t":"횃불을 던지고 화살을 쏘아서 사람을 다치게 하는 미친 사람이 있는데"},{"n":19,"t":"자기 이웃을 속여 놓고는 \\"장난친 거야\\" 하고 말하는 사람도 그런 사람과 똑같아."},{"n":20,"t":"나무가 다 떨어지면 불이 꺼지듯이 말 옮기는 사람이 없어지면 다툼도 멈춘단다."},{"n":21,"t":"숯불 위에 숯을 더하고 타는 불에 장작을 더하듯이 다툼을 좋아하는 사람은 싸움을 더 크게 만들어."},{"n":22,"t":"남의 이야기를 옮기는 사람의 말은 맛있는 음식 같아서 사람들의 마음속 깊이 들어가."},{"n":23,"t":"부드러운 입술에 못된 마음을 가진 사람은 싸구려 은을 입힌 토기 그릇 같아."},{"n":24,"t":"원수는 입술로는 좋게 말하면서도 속으로는 속임수를 품고 있어."},{"n":25,"t":"그 사람이 말을 좋게 한다고 해서 믿지 마라. 그 마음에는 미운 것들이 가득해."},{"n":26,"t":"미움을 거짓으로 감추려 해도 결국 그 못된 행동이 사람들 앞에 다 드러나게 돼."},{"n":27,"t":"함정을 파는 사람은 자기가 그 함정에 빠지고 돌을 굴리는 사람은 그 돌에 자기가 치이게 돼."},{"n":28,"t":"거짓말을 하는 사람은 자기가 해친 사람을 오히려 미워하고 아첨하는 입은 결국 자기와 다른 사람까지 망하게 한단다."}]}},{"chapter":27,"title":"내일 일을 자랑하지 말라","verses":{"krv":[{"n":1,"t":"너는 내일 일을 자랑하지 말라 하루 동안에 무슨 일이 날는지 네가 알 수 없음이니라"},{"n":2,"t":"타인으로 너를 칭찬하게 하고 네 입으로는 말며 외인으로 너를 칭찬하게 하고 네 입술로는 말지니라"},{"n":3,"t":"돌은 무겁고 모래도 가볍지 아니하거니와 미련한 자의 분노는 이 둘보다 무거우니라"},{"n":4,"t":"분은 잔인하고 노는 창수 같거니와 투기 앞에야 누가 서리요"},{"n":5,"t":"면책은 숨은 사랑보다 나으니라"},{"n":6,"t":"친구의 통책은 충성에서 말미암은 것이나 원수의 자주 입맞춤은 거짓에서 난 것이니라"},{"n":7,"t":"배부른 자는 꿀이라도 싫어하고 주린 자에게는 쓴 것이라도 다니라"},{"n":8,"t":"본향을 떠나 유리하는 사람은 보금자리를 떠나 떠도는 새와 같으니라"},{"n":9,"t":"기름과 향이 사람의 마음을 즐겁게 하나니 친구의 충성된 권고가 이와 같이 아름다우니라"},{"n":10,"t":"네 친구와 네 아비의 친구를 버리지 말며 네 환난날에 형제의 집에 들어가지 말지어다 가까운 이웃이 먼 형제보다 나으니라"},{"n":11,"t":"내 아들아 지혜를 얻고 내 마음을 기쁘게 하라 그리하면 나를 비방하는 자에게 내가 대답할 수 있겠노라"},{"n":12,"t":"슬기로운 자는 재앙을 보면 숨어 피하여도 어리석은 자들은 나아가다가 해를 받느니라"},{"n":13,"t":"타인을 위하여 보증이 된 자의 옷을 취하라 외인들의 보증이 된 자는 그 몸을 볼모로 잡힐지니라"},{"n":14,"t":"이른 아침에 큰 소리로 그 이웃을 축복하면 도리어 저주 같이 여기게 되리라"},{"n":15,"t":"다투는 부녀는 비오는 날에 이어 떨어지는 물방울이라"},{"n":16,"t":"그를 제어하기가 바람을 제어하는 것 같고 오른손으로 기름을 움키는 것 같으니라"},{"n":17,"t":"철이 철을 날카롭게 하는 것 같이 사람이 그 친구의 얼굴을 빛나게 하느니라"},{"n":18,"t":"무화과나무를 지키는 자는 그 과실을 먹고 자기 주인을 시종하는 자는 영화를 얻느니라"},{"n":19,"t":"물에 비취이면 얼굴이 서로 같은 것 같이 사람의 마음도 서로 비취느니라"},{"n":20,"t":"음부와 유명은 만족함이 없고 사람의 눈도 만족함이 없느니라"},{"n":21,"t":"도가니로 은을, 풀무로 금을, 칭찬으로 사람을 시련하느니라"},{"n":22,"t":"미련한 자를 곡물과 함께 절구에 넣고 공이로 찧을지라도 그의 미련은 벗어지지 아니하느니라"},{"n":23,"t":"네 양떼의 형편을 부지런히 살피며 네 소떼에 마음을 두라"},{"n":24,"t":"대저 재물은 영영히 있지 못하나니 면류관이 어찌 대대에 있으랴"},{"n":25,"t":"풀을 벤 후에는 새로 움이 돋나니 산에서 꼴을 거둘 것이니라"},{"n":26,"t":"어린 양의 털은 네 옷이 되며 염소는 밭을 사는 값이 되며"},{"n":27,"t":"염소의 젖은 넉넉하여 너와 네 집 사람의 식물이 되며 네 여종의 먹을 것이 되느니라"}],"kids":[{"n":1,"t":"내일 일을 자랑하지 마라. 하루에 무슨 일이 일어날지 아무도 모르는 거야."},{"n":2,"t":"너의 입으로 너 자신을 칭찬하지 말고 다른 사람이 너를 칭찬하도록 살아."},{"n":3,"t":"돌은 무겁고 모래도 가볍지 않지만 어리석은 사람의 화는 그 두 가지보다 더 무겁단다."},{"n":4,"t":"화는 잔인하고 분노는 큰 물결 같지만 시기심 앞에서는 누가 견딜 수 있을까?"},{"n":5,"t":"차라리 따끔하게 충고해 주는 것이 마음속에만 감춰 둔 사랑보다 훨씬 나아."},{"n":6,"t":"친구가 따끔하게 충고하는 것은 진심에서 나온 거지만 원수가 자주 입을 맞춰 오는 것은 거짓에서 나온 거야."},{"n":7,"t":"배부른 사람은 꿀이라도 싫어하지만 배고픈 사람에게는 쓴 음식도 달콤하게 느껴지지."},{"n":8,"t":"고향을 떠나 이리저리 떠도는 사람은 자기 보금자리를 떠나 헤매는 새와 같아."},{"n":9,"t":"기름과 향이 사람의 마음을 즐겁게 하듯 친구의 진실한 조언도 그렇게 마음을 따뜻하게 해 줘."},{"n":10,"t":"너의 친구와 아빠의 친구를 함부로 버리지 마라. 어려운 날에 멀리 사는 형제 집에 가는 것보다 가까이 있는 이웃이 더 큰 도움이 될 수 있어."},{"n":11,"t":"내 아들아, 지혜를 얻어 내 마음을 기쁘게 해. 그래야 누가 나를 욕할 때 내가 떳떳하게 대답할 수 있단다."},{"n":12,"t":"슬기로운 사람은 재앙을 미리 보고 피하지만 어리석은 사람은 그냥 나가다가 해를 입어."},{"n":13,"t":"모르는 사람의 보증을 함부로 선 사람의 옷을 담보로 잡고 낯선 사람을 보증한 사람에게는 책임을 단단히 물어야 해."},{"n":14,"t":"이른 아침에 큰 소리로 이웃을 축복한답시고 떠들면 도리어 저주처럼 들릴 수도 있어."},{"n":15,"t":"자꾸 다투는 사람은 비 오는 날 끝없이 떨어지는 물방울 같아."},{"n":16,"t":"그런 사람을 막아 보려는 건 바람을 막으려는 것 같고 오른손으로 기름을 움켜쥐려는 것과 같단다."},{"n":17,"t":"쇠가 쇠를 날카롭게 만들 듯이 사람도 친구를 통해 더 빛나는 사람이 된단다."},{"n":18,"t":"무화과나무를 잘 가꾸는 사람은 그 열매를 먹고 주인을 잘 섬기는 사람은 영광을 얻어."},{"n":19,"t":"물에 비친 얼굴이 그 사람의 얼굴을 그대로 비추듯 사람의 마음도 서로의 마음을 비춰 줘."},{"n":20,"t":"깊은 무덤이 만족할 줄 모르듯이 사람의 눈도 만족할 줄을 모른단다."},{"n":21,"t":"도가니로 은을, 풀무로 금을 단련하듯이 사람은 칭찬을 받을 때 그 마음이 드러나."},{"n":22,"t":"어리석은 사람을 곡식과 함께 절구에 넣고 빻아도 그 어리석음은 벗겨지지 않아."},{"n":23,"t":"네가 기르는 양 떼의 상태를 부지런히 살피고 소 떼에게 마음을 잘 써."},{"n":24,"t":"재물은 영원히 있는 게 아니고 왕관도 대대로 가는 게 아니니까."},{"n":25,"t":"풀을 베고 나면 다시 새 풀이 돋아나고 산에서도 풀을 거두어 모을 수 있을 거야."},{"n":26,"t":"어린 양의 털은 네 옷이 되고 염소를 팔아 밭을 살 수 있어."},{"n":27,"t":"염소의 젖은 넉넉해서 너와 네 식구의 음식이 되고 너의 일꾼들이 먹을 양식도 될 거야."}]}},{"chapter":28,"title":"악인의 도망","verses":{"krv":[{"n":1,"t":"악인은 쫓아 오는 자가 없어도 도망하나 의인은 사자 같이 담대하니라"},{"n":2,"t":"나라는 죄가 있으면 주관자가 많아져도 명철과 지식 있는 사람으로 말미암아 장구하게 되느니라"},{"n":3,"t":"가난한 자를 학대하는 가난한 자는 곡식을 남기지 아니하는 폭우같으니라"},{"n":4,"t":"율법을 버린 자는 악인을 칭찬하나 율법을 지키는 자는 악인을 대적하느니라"},{"n":5,"t":"악인은 공의를 깨닫지 못하나 여호와를 찾는 자는 모든 것을 깨닫느니라"},{"n":6,"t":"성실히 행하는 가난한 자는 사곡히 행하는 부자보다 나으니라"},{"n":7,"t":"율법을 지키는 자는 지혜로운 아들이요 탐식자를 사귀는 자는 아비를 욕되게 하는 자니라"},{"n":8,"t":"중한 변리로 자기 재산을 많아지게 하는 것은 가난한 사람 불쌍히 여기는 자를 위하여 그 재산을 저축하는 것이니라"},{"n":9,"t":"사람이 귀를 돌이키고 율법을 듣지 아니하면 그의 기도도 가증하니라"},{"n":10,"t":"정직한 자를 악한 길로 유인하는 자는 스스로 자기 함정에 빠져도 성실한 자는 복을 얻느니라"},{"n":11,"t":"부자는 자기를 지혜롭게 여겨도 명철한 가난한 자는 그를 살펴 아느니라"},{"n":12,"t":"의인이 득의하면 큰 영화가 있고 악인이 일어나면 사람이 숨느니라"},{"n":13,"t":"자기의 죄를 숨기는 자는 형통치 못하나 죄를 자복하고 버리는 자는 불쌍히 여김을 받으리라"},{"n":14,"t":"항상 경외하는 자는 복되거니와 마음을 강퍅하게 하는 자는 재앙에 빠지리라"},{"n":15,"t":"가난한 백성을 압제하는 악한 관원은 부르짖는 사자와 주린 곰 같으니라"},{"n":16,"t":"무지한 치리자는 포학을 크게 행하거니와 탐욕을 미워하는 자는 장수하리라"},{"n":17,"t":"사람의 피를 흘린 자는 함정으로 달려갈 것이니 그를 막지 말지니라"},{"n":18,"t":"성실히 행하는 자는 구원을 얻을 것이나 사곡히 행하는 자는 곧 넘어지리라"},{"n":19,"t":"자기의 토지를 경작하는 자는 먹을 것이 많으려니와 방탕을 좇는자는 궁핍함이 많으리라"},{"n":20,"t":"충성된 자는 복이 많아도 속히 부하고자 하는 자는 형벌을 면치 못하리라"},{"n":21,"t":"사람의 낯을 보아주는 것이 좋지 못하고 한 조각 떡을 인하여 범법하는 것도 그러하니라"},{"n":22,"t":"악한 눈이 있는 자는 재물을 얻기에만 급하고 빈궁이 자기에게로 임할 줄은 알지 못하느니라"},{"n":23,"t":"사람을 경책하는 자는 혀로 아첨하는 자보다 나중에 더욱 사랑을 받느니라"},{"n":24,"t":"부모의 물건을 도적질하고 죄가 아니라 하는 자는 멸망케 하는 자의 동류니라"},{"n":25,"t":"마음이 탐하는 자는 다툼을 일으키나 여호와를 의지하는 자는 풍족하게 되느니라"},{"n":26,"t":"자기의 마음을 믿는 자는 미련한 자요 지혜롭게 행하는 자는 구원을 얻을 자니라"},{"n":27,"t":"가난한 자를 구제하는 자는 궁핍하지 아니 하려니와 못본체 하는자에게는 저주가 많으리라"},{"n":28,"t":"악인이 일어나면 사람이 숨고 그가 멸망하면 의인이 많아지느니라"}],"kids":[{"n":1,"t":"나쁜 사람은 쫓아오는 사람이 없어도 도망치지만 옳은 사람은 사자처럼 담대해."},{"n":2,"t":"나라에 죄가 많아지면 다스리는 사람이 자주 바뀌지만 분별과 지식이 있는 사람이 다스리면 그 나라는 오래갈 수 있어."},{"n":3,"t":"가난하면서 다른 가난한 사람을 괴롭히는 사람은 곡식을 다 휩쓸어 가는 폭우 같단다."},{"n":4,"t":"가르침을 버린 사람은 나쁜 사람을 칭찬하지만 가르침을 지키는 사람은 나쁜 짓을 그냥 두지 않아."},{"n":5,"t":"나쁜 사람은 정의가 무엇인지 깨닫지 못하지만 하나님을 찾는 사람은 모든 것을 깨닫게 돼."},{"n":6,"t":"가난해도 정직하게 사는 사람이 부자면서도 비뚤어진 길로 가는 사람보다 훨씬 나아."},{"n":7,"t":"가르침을 잘 지키는 사람은 지혜로운 아들이지만 못된 친구들과 어울리는 사람은 부모를 부끄럽게 해."},{"n":8,"t":"큰 이자로 자기 재산을 자꾸 늘리는 사람은 결국 가난한 사람을 도와주는 다른 사람을 위해 그 재산을 모아 두는 셈이 돼."},{"n":9,"t":"누구라도 가르침을 듣지 않으려고 귀를 돌리면 그 사람의 기도조차 하나님께 가증한 것이 돼."},{"n":10,"t":"정직한 사람을 나쁜 길로 끌어들이는 사람은 자기가 판 함정에 자기가 빠지고 정직하게 사는 사람은 복을 받는단다."},{"n":11,"t":"부자는 자기를 지혜롭다고 여기지만 가난해도 깨달은 사람은 자기 자신을 잘 살펴 알아."},{"n":12,"t":"옳은 사람이 잘되면 큰 영광이 함께하지만 나쁜 사람이 권력을 잡으면 사람들이 숨어 버려."},{"n":13,"t":"자기 죄를 감추는 사람은 잘되지 못하지만 죄를 고백하고 버리는 사람은 불쌍히 여김을 받게 돼."},{"n":14,"t":"늘 하나님을 두려워하는 사람은 복되지만 마음을 차갑게 굳히는 사람은 결국 재앙에 빠져."},{"n":15,"t":"가난한 백성을 괴롭히는 못된 지도자는 사납게 으르렁대는 사자나 굶주린 곰 같단다."},{"n":16,"t":"분별 없는 지도자는 폭정을 일삼지만 욕심을 싫어하는 지도자는 오래도록 잘 다스리게 돼."},{"n":17,"t":"다른 사람의 피를 흘리게 한 사람은 결국 자기 죽음으로 달려갈 거니까 그를 막지 마라."},{"n":18,"t":"정직하게 사는 사람은 구원을 받지만 비뚤어진 길로 가는 사람은 어느 한 길에서 곧 넘어지게 돼."},{"n":19,"t":"자기 밭을 부지런히 가꾸는 사람은 먹을 것이 많지만 헛된 즐거움을 좇아다니는 사람은 가난해질 거야."},{"n":20,"t":"진실한 사람은 복이 가득하지만 빨리 부자가 되려는 사람은 벌을 피할 수 없어."},{"n":21,"t":"사람의 얼굴을 보아 가며 다르게 대하는 것은 좋지 않아. 빵 한 조각 때문에 죄를 짓는 사람도 있단다."},{"n":22,"t":"욕심 가득한 눈을 가진 사람은 재물 모으는 일에만 급하지 가난이 자기에게 다가오는 줄도 몰라."},{"n":23,"t":"사람을 따끔하게 충고하는 사람이 혀로 아첨하는 사람보다 나중에는 더 큰 사랑을 받아."},{"n":24,"t":"부모의 물건을 훔쳐 놓고도 \\"죄가 아니야\\" 하는 사람은 결국 다른 사람을 망하게 하는 사람과 다르지 않아."},{"n":25,"t":"욕심 많은 사람은 다툼을 일으키지만 하나님을 의지하는 사람은 풍족함을 누리게 돼."},{"n":26,"t":"자기 마음만 믿는 사람은 어리석은 사람이고 지혜롭게 사는 사람은 구원을 얻게 돼."},{"n":27,"t":"가난한 사람을 도와주는 사람은 가난해지지 않지만 모른 척하는 사람에게는 저주가 따라와."},{"n":28,"t":"나쁜 사람이 권력을 잡으면 사람들이 숨고 그 사람이 망하면 옳은 사람이 많아진단다."}]}},{"chapter":29,"title":"공의와 책망","verses":{"krv":[{"n":1,"t":"자주 책망을 받으면서도 목이 곧은 사람은 갑자기 패망을 당하고 피하지 못하리라"},{"n":2,"t":"의인이 많아지면 백성이 즐거워하고 악인이 권세를 잡으면 백성이 탄식하느니라"},{"n":3,"t":"지혜를 사모하는 자는 아비를 즐겁게 하여도 창기를 사귀는 자는 재물을 없이하느니라"},{"n":4,"t":"왕은 공의로 나라를 견고케 하나 뇌물을 억지로 내게 하는 자는 나라를 멸망시키느니라"},{"n":5,"t":"이웃에게 아첨하는 것은 그의 발 앞에 그물을 치는 것이니라"},{"n":6,"t":"악인의 범죄하는 것은 스스로 올무가 되게 하는 것이나 의인은 노래하고 기뻐하느니라"},{"n":7,"t":"의인은 가난한 자의 사정을 알아 주나 악인은 알아 줄 지식이 없느니라"},{"n":8,"t":"모만한 자는 성읍을 요란케 하여도 슬기로운 자는 노를 그치게 하느니라"},{"n":9,"t":"지혜로운 자와 미련한 자가 다투면 지혜로운 자가 노하든지 웃든지 그 다툼이 그침이 없느니라"},{"n":10,"t":"피 흘리기를 좋아하는 자는 온전한 자를 미워하고 정직한 자의 생명을 찾느니라"},{"n":11,"t":"어리석은 자는 그 노를 다 드러내어도 지혜로운 자는 그 노를 억제하느니라"},{"n":12,"t":"관원이 거짓말을 신청하면 그 하인은 다 악하니라"},{"n":13,"t":"가난한 자와 포학한 자가 섞여 살거니와 여호와께서는 그들의 눈에 빛을 주시느니라"},{"n":14,"t":"왕이 가난한 자를 성실히 신원하면 그 위가 영원히 견고하리라"},{"n":15,"t":"채찍과 꾸지람이 지혜를 주거늘 임의로 하게 버려두면 그 자식은 어미를 욕되게 하느니라"},{"n":16,"t":"악인이 많아지면 죄도 많아지나니 의인은 그들의 망함을 보리라"},{"n":17,"t":"네 자식을 징계하라 그리하면 그가 너를 평안하게 하겠고 또 네 마음에 기쁨을 주리라"},{"n":18,"t":"묵시가 없으면 백성이 방자히 행하거니와 율법을 지키는 자는 복이 있느니라"},{"n":19,"t":"종은 말로만 하면 고치지 아니하나니 이는 그가 알고도 청종치 아니함이니라"},{"n":20,"t":"네가 언어에 조급한 사람을 보느냐 그보다 미련한 자에게 오히려 바랄 것이 있느니라"},{"n":21,"t":"종을 어렸을 때부터 곱게 양육하면 그가 나중에는 자식인체하리라"},{"n":22,"t":"노하는 자는 다툼을 일으키고 분하여 하는 자는 범죄함이 많으니라"},{"n":23,"t":"사람이 교만하면 낮아지게 되겠고 마음이 겸손하면 영예를 얻으리라"},{"n":24,"t":"도적과 짝하는 자는 자기의 영혼을 미워하는 자라 그는 맹세함을 들어도 직고하지 아니하느니라"},{"n":25,"t":"사람을 두려워하면 올무에 걸리게 되거니와 여호와를 의지하는 자는 안전하리라"},{"n":26,"t":"주권자에게 은혜를 구하는 자가 많으나 사람의 일의 작정은 여호와께로 말미암느니라"},{"n":27,"t":"불의한 자는 의인에게 미움을 받고 정직한 자는 악인에게 미움을받느니라"}],"kids":[{"n":1,"t":"자주 충고를 듣고도 고집을 부리는 사람은 갑자기 무너지고 피할 길도 없게 돼."},{"n":2,"t":"옳은 사람이 많아지면 백성이 기뻐하지만 나쁜 사람이 권력을 잡으면 백성이 한숨을 쉬게 돼."},{"n":3,"t":"지혜를 사랑하는 사람은 아빠를 기쁘게 하지만 못된 길에 빠지는 사람은 재물을 다 잃어버려."},{"n":4,"t":"왕은 정의로 나라를 든든하게 하지만 뇌물을 억지로 받아 가는 사람은 나라를 망쳐."},{"n":5,"t":"이웃에게 아첨만 하는 사람은 그 사람의 발 앞에 함정을 치는 사람과 같단다."},{"n":6,"t":"나쁜 사람이 죄를 짓는 것은 스스로 함정을 만드는 거지만 옳은 사람은 노래하며 기뻐할 수 있어."},{"n":7,"t":"옳은 사람은 가난한 사람의 사정을 잘 알고 헤아리지만 나쁜 사람은 그런 마음 자체를 알지 못해."},{"n":8,"t":"잘난 척하는 사람은 마을을 시끄럽게 만들지만 슬기로운 사람은 그 화를 가라앉혀."},{"n":9,"t":"지혜로운 사람이 어리석은 사람과 다투면 그 어리석은 사람이 화내든 웃든 다툼이 멈추지 않아."},{"n":10,"t":"사람을 해치기 좋아하는 사람은 정직한 사람을 미워하고 옳은 사람의 생명을 노려."},{"n":11,"t":"어리석은 사람은 자기 화를 다 드러내지만 지혜로운 사람은 그 화를 잘 다스려."},{"n":12,"t":"높은 사람이 거짓말에 귀를 기울이면 그 아래 일하는 사람들이 다 못되게 된단다."},{"n":13,"t":"가난한 사람도 못된 사람도 함께 살아가는데 그들 모두의 눈에 빛을 비춰 주시는 분은 하나님이셔."},{"n":14,"t":"왕이 가난한 사람의 억울함을 진심으로 풀어 주면 그 왕의 자리가 영원히 든든해질 거야."},{"n":15,"t":"따끔한 매와 꾸지람이 지혜를 더해 주지만 마음대로 자라게 내버려 둔 자식은 엄마를 부끄럽게 해."},{"n":16,"t":"나쁜 사람이 많아지면 죄도 많아지지만 옳은 사람은 결국 그들이 무너지는 모습을 보게 될 거야."},{"n":17,"t":"자식을 바르게 가르쳐라. 그러면 자식이 너를 평안하게 하고 네 마음에 기쁨을 줄 거야."},{"n":18,"t":"하나님이 주시는 말씀이 없으면 백성이 멋대로 행하지만 가르침을 지키는 사람은 복을 받아."},{"n":19,"t":"일꾼은 말만으로 고쳐지지 않아. 알면서도 따르지 않는 경우가 많거든."},{"n":20,"t":"말부터 급하게 내뱉는 사람을 보았니? 그런 사람보다는 차라리 어리석은 사람에게 더 희망이 있단다."},{"n":21,"t":"어렸을 때부터 일꾼을 너무 곱게만 키우면 나중에 자기가 자식인 양 행동하려 할 거야."},{"n":22,"t":"화를 자주 내는 사람은 다툼을 일으키고 성을 잘 내는 사람은 죄도 많이 짓게 돼."},{"n":23,"t":"사람이 잘난 척하면 낮아지지만 마음이 겸손한 사람은 영광을 얻게 돼."},{"n":24,"t":"도둑과 어울리는 사람은 자기 영혼을 미워하는 사람이야. 진실을 말하라 해도 입을 다물어 버리니까."},{"n":25,"t":"사람을 두려워하면 함정에 걸리지만 하나님을 의지하는 사람은 안전해."},{"n":26,"t":"높은 사람에게 잘 봐 달라고 부탁하는 사람이 많지만 사람의 일을 결정하시는 분은 결국 하나님이셔."},{"n":27,"t":"옳은 사람은 못된 사람을 미워하고 바른 길로 사는 사람은 나쁜 사람에게 미움을 받아."}]}},{"chapter":30,"title":"아굴의 잠언","verses":{"krv":[{"n":1,"t":"이 말씀은 야게의 아들 아굴의 잠언이니 그가 이디엘과 우갈에게 이른 것이니라"},{"n":2,"t":"나는 다른 사람에게 비하면 짐승이라 내게는 사람의 총명이 있지아니하니라"},{"n":3,"t":"나는 지혜를 배우지 못하였고 또 거룩하신 자를 아는 지식이 없거니와"},{"n":4,"t":"하늘에 올라갔다가 내려온 자가 누구인지, 바람을 그 장중에 모은자가 누구인지, 물을 옷에 싼자가 누구인지, 땅의 모든 끝을 정한 자가 누구인지, 그이름이 무엇인지, 그 아들의 이름이 무엇인지 너는 아느냐"},{"n":5,"t":"하나님의 말씀은 다 순전하며 하나님은 그를 의지하는 자의 방패시니라"},{"n":6,"t":"너는 그 말씀에 더하지 말라 그가 너를 책망하시겠고 너는 거짓말 하는 자가 될까 두려우니라"},{"n":7,"t":"내가 두 가지 일을 주께 구하였사오니 나의 죽기 전에 주시옵소서"},{"n":8,"t":"곧 허탄과 거짓말을 내게서 멀리 하옵시며 나로 가난하게도 마옵시고 부하게도 마옵시고 오직 필요한 양식으로 내게 먹이시옵소서"},{"n":9,"t":"혹 내가 배불러서 하나님을 모른다 여호와가 누구냐 할까 하오며 혹 내가 가난하여 도적질하고 내 하나님의 이름을 욕되게 할까 두려워함이니이다"},{"n":10,"t":"너는 종을 그 상전에게 훼방하지 말라 그가 너를 저주하겠고 너는 죄책을 당할까 두려우니라"},{"n":11,"t":"아비를 저주하며 어미를 축복하지 아니하는 무리가 있느니라"},{"n":12,"t":"스스로 깨끗한 자로 여기면서 오히려 그 더러운 것을 씻지 아니하는 무리가 있느니라"},{"n":13,"t":"눈이 심히 높으며 그 눈꺼풀이 높이 들린 무리가 있느니라"},{"n":14,"t":"앞니는 장검 같고 어금니는 군도 같아서 가난한 자를 땅에서 삼키며 궁핍한 자를 사람 중에서 삼키는 무리가 있느니라"},{"n":15,"t":"거머리에게는 두 딸이 있어 다고 다고 하느니라 족한 줄을 알지 못하여 족하다 하지 아니하는 것 서넛이 있나니"},{"n":16,"t":"곧 음부와 아이 배지 못하는 태와 물로 채울 수 없는 땅과 족하다 하지 아니하는 불이니라"},{"n":17,"t":"아비를 조롱하며 어미 순종하기를 싫어하는 자의 눈은 골짜기의 까마귀에게 쪼이고 독수리 새끼에게 먹히리라"},{"n":18,"t":"내가 심히 기이히 여기고도 깨닫지 못하는 것 서넛이 있나니"},{"n":19,"t":"곧 공중에 날아 다니는 독수리의 자취와 바다로 지나다니는 배의 자취와 남자가 여자와 함께 한 자취며"},{"n":20,"t":"음녀의 자취도 그러하니라 그가 먹고 그 입을 씻음 같이 말하기를 내가 악을 행치 아니하였다 하느니라"},{"n":21,"t":"세상을 진동시키며 세상으로 견딜 수 없게 하는 것 서넛이 있나니"},{"n":22,"t":"곧 종이 임금된 것과 미련한 자가 배부른 것과"},{"n":23,"t":"꺼림을 받는 계집이 시집간 것과 계집 종이 주모를 이은 것이니라"},{"n":24,"t":"땅에 작고도 가장 지혜로운 것 넷이 있나니"},{"n":25,"t":"곧 힘이 없는 종류로되 먹을 것을 여름에 예비하는 개미와"},{"n":26,"t":"약한 종류로되 집을 바위 사이에 짓는 사반과"},{"n":27,"t":"임군이 없으되 다 떼를 지어 나아가는 메뚜기와"},{"n":28,"t":"손에 잡힐만하여도 왕궁에 있는 도마뱀이니라"},{"n":29,"t":"잘 걸으며 위풍 있게 다니는 것 서넛이 있나니"},{"n":30,"t":"곧 짐승 중에 가장 강하여 아무 짐승 앞에서도 물러가지 아니하는 사자와"},{"n":31,"t":"사냥개와 수염소와 및 당할 수 없는 왕이니라"},{"n":32,"t":"만일 네가 미련하여 스스로 높은체 하였거나 혹 악한 일을 도모하였거든 네 손으로 입을 막으라"},{"n":33,"t":"대저 젖을 저으면 뻐터가 되고 코를 비틀면 피가 나는 것 같이 노를 격동하면 다툼이 남이니라"}],"kids":[{"n":1,"t":"이 말씀은 야게의 아들 아굴의 잠언인데 그가 이디엘과 우갈에게 한 말이야."},{"n":2,"t":"나는 다른 사람에 비하면 그저 짐승 같고 사람다운 깨달음이 부족한 사람이에요."},{"n":3,"t":"나는 지혜도 제대로 배우지 못했고 거룩하신 하나님을 깊이 아는 지식도 없어요."},{"n":4,"t":"누가 하늘에 올라갔다가 내려왔니? 누가 바람을 손바닥에 모으고 누가 물을 옷에 싸 두었으며 누가 땅 끝을 정해 두었니? 그분의 이름이 무엇이며 그분의 아들의 이름이 무엇인지 네가 알 수 있겠니?"},{"n":5,"t":"하나님의 말씀은 모두 거짓이 없고 하나님은 자기를 의지하는 사람의 든든한 방패가 되어 주셔."},{"n":6,"t":"하나님의 말씀에 함부로 무엇을 더하지 마라. 하나님이 너를 꾸짖으시고 너는 거짓말쟁이가 될 수도 있어."},{"n":7,"t":"하나님, 제가 두 가지를 부탁드려요. 제가 살아 있는 동안 들어주세요."},{"n":8,"t":"헛된 것과 거짓말을 저에게서 멀리하시고 저를 너무 가난하게도, 너무 부유하게도 하지 마세요. 그저 매일 필요한 만큼의 양식만 주세요."},{"n":9,"t":"너무 부유해서 \\"하나님이 누구신가\\" 하며 하나님을 잊을까 두렵고 너무 가난해서 도둑질하다가 하나님의 이름을 욕되게 할까 두렵습니다."},{"n":10,"t":"일꾼을 그 주인 앞에서 함부로 흉보지 마라. 그가 너를 저주하고 너는 그 일로 책임을 지게 될 수 있어."},{"n":11,"t":"아빠를 저주하고 엄마를 축복하지 않는 못된 무리들이 있단다."},{"n":12,"t":"자기는 깨끗하다 하면서 자기 안의 더러운 것을 씻지 않는 무리들이 있어."},{"n":13,"t":"눈을 높이 치켜뜨고 잘난 척하며 사람들을 우습게 여기는 무리들도 있지."},{"n":14,"t":"앞니는 칼 같고 어금니는 큰 칼 같아서 가난한 사람을 땅에서 삼키고 어려운 사람을 사람들 사이에서 삼키는 무리들도 있단다."},{"n":15,"t":"거머리에게는 \\"더 줘, 더 줘\\" 하는 두 딸이 있어. 만족할 줄 모르고 \\"이제 됐다\\" 하지 않는 것 세 가지, 아니 네 가지가 있는데"},{"n":16,"t":"곧 깊은 무덤, 아이를 못 낳는 태, 물로도 채워지지 않는 메마른 땅, \\"이제 됐다\\" 하지 않는 불이야."},{"n":17,"t":"아빠를 조롱하고 엄마 말 듣기를 싫어하는 사람의 눈은 골짜기의 까마귀에게 쪼이고 독수리 새끼에게 먹힐 거야."},{"n":18,"t":"내가 보고 너무 놀라워하면서도 다 알지 못하는 것 세 가지, 아니 네 가지가 있어."},{"n":19,"t":"곧 하늘에 날아다니는 독수리의 자취, 바위 위로 기어 다니는 뱀의 자취, 바다 위를 지나가는 배의 자취, 남자와 여자가 만나는 자취야."},{"n":20,"t":"못된 길로 가는 사람의 모습도 그래. 마음대로 살아 놓고는 입을 닦은 듯이 \\"나는 잘못한 게 없어\\" 하고 말해."},{"n":21,"t":"세상을 흔들리게 하고 견딜 수 없게 만드는 것 세 가지, 아니 네 가지가 있는데"},{"n":22,"t":"일꾼이 갑자기 임금이 된 것, 어리석은 사람이 배부르게 먹는 것,"},{"n":23,"t":"미움받던 여자가 시집을 가게 된 것, 일하는 여자가 안주인의 자리를 차지한 것이야."},{"n":24,"t":"땅 위에 작고도 가장 지혜로운 것이 네 가지 있어."},{"n":25,"t":"힘이 없지만 여름 동안에 먹을 것을 미리 준비하는 개미,"},{"n":26,"t":"약하지만 바위 사이에 집을 짓는 너구리 비슷한 작은 동물,"},{"n":27,"t":"왕이 없는데도 모두 떼를 지어 나아가는 메뚜기,"},{"n":28,"t":"손에 잡힐 만큼 작지만 왕의 궁궐에까지 들어가는 도마뱀이지."},{"n":29,"t":"잘 걷고 위풍당당하게 다니는 것이 세 가지, 아니 네 가지가 있는데"},{"n":30,"t":"곧 짐승 중에 가장 강해서 어떤 짐승 앞에서도 물러서지 않는 사자,"},{"n":31,"t":"사냥개와 숫염소, 그리고 누구도 막을 수 없는 왕이야."},{"n":32,"t":"네가 어리석어서 잘난 척했거나 나쁜 일을 꾸몄다면 손으로 네 입을 막고 조용히 있어라."},{"n":33,"t":"우유를 저으면 엉긴 젖이 되고 코를 비틀면 피가 나는 것처럼 화를 자꾸 돋우면 결국 다툼이 생긴단다."}]}},{"chapter":31,"title":"르무엘 왕의 말씀","verses":{"krv":[{"n":1,"t":"르무엘왕의 말씀한바 곧 그 어머니가 그를 훈계한 잠언이라"},{"n":2,"t":"내 아들아 내가 무엇을 말할꼬 내 태에서 난 아들아 내가 무엇을 말할꼬 서원대로 얻은 아들아 내가 무엇을 말할꼬"},{"n":3,"t":"네 힘을 여자들에게 쓰지 말며 왕들을 멸망시키는 일을 행치 말지어다"},{"n":4,"t":"르무엘아 포도주를 마시는 것이 왕에게 마땅치 아니하고 왕에게 마땅치 아니하며 독주를 찾는 것이 주권자에게 마땅치 않도다"},{"n":5,"t":"술을 마시다가 법을 잊어버리고 모든 간곤한 백성에게 공의를 굽게 할까 두려우니라"},{"n":6,"t":"독주는 죽게된 자에게, 포도주는 마음에 근심하는 자에게 줄지어다"},{"n":7,"t":"그는 마시고 빈궁한 것을 잊어버리겠고 다시 그 고통을 기억지 아니하리라"},{"n":8,"t":"너는 벙어리와 고독한 자의 송사를 위하여 입을 열지니라"},{"n":9,"t":"너는 입을 열어 공의로 재판하여 간곤한 자와 궁핍한 자를 신원 할지니라"},{"n":10,"t":"누가 현숙한 여인을 찾아 얻겠느냐 그 값은 진주보다 더하니라"},{"n":11,"t":"그런 자의 남편의 마음은 그를 믿나니 산업이 핍절치 아니하겠으며"},{"n":12,"t":"그런 자는 살아 있는 동안에 그 남편에게 선을 행하고 악을 행치아니하느니라"},{"n":13,"t":"그는 양털과 삼을 구하여 부지런히 손으로 일하며"},{"n":14,"t":"상고의 배와 같아서 먼 데서 양식을 가져오며"},{"n":15,"t":"밤이 새기 전에 일어나서 그 집 사람에게 식물을 나눠주며 여종 에게 일을 정하여 맡기며"},{"n":16,"t":"밭을 간품하여 사며 그 손으로 번 것을 가지고 포도원을 심으며"},{"n":17,"t":"힘으로 허리를 묶으며 그 팔을 강하게 하며"},{"n":18,"t":"자기의 무역하는 것이 이로운 줄을 깨닫고 밤에 등불을 끄지 아니하고"},{"n":19,"t":"손으로 솜뭉치를 들고 손가락으로 가락을 잡으며"},{"n":20,"t":"그는 간곤한 자에게 손을 펴며 궁핍한 자를 위하여 손을 내밀며"},{"n":21,"t":"그 집 사람들은 다 홍색 옷을 입었으므로 눈이 와도 그는 집 사람을 위하여 두려워하지 아니하며"},{"n":22,"t":"그는 자기를 위하여 아름다운 방석을 지으며 세마포와 자색 옷을 입으며"},{"n":23,"t":"그 남편은 그 땅의 장로로 더불어 성문에 앉으며 사람의 아는 바가 되며"},{"n":24,"t":"그는 베로 옷을 지어 팔며 띠를 만들어 상고에게 맡기며"},{"n":25,"t":"능력과 존귀로 옷을 삼고 후일을 웃으며"},{"n":26,"t":"입을 열어 지혜를 베풀며 그 혀로 인애의 법을 말하며"},{"n":27,"t":"그 집안 일을 보살피고 게을리 얻은 양식을 먹지 아니하나니"},{"n":28,"t":"그 자식들은 일어나 사례하며 그 남편은 칭찬하기를"},{"n":29,"t":"덕행 있는 여자가 많으나 그대는 여러 여자보다 뛰어난다 하느니라"},{"n":30,"t":"고운 것도 거짓되고 아름다운 것도 헛되나 오직 여호와를 경외하는 여자는 칭찬을 받을 것이라"},{"n":31,"t":"그 손의 열매가 그에게로 돌아갈 것이요 그 행한 일을 인하여 성문에서 칭찬을 받으리라"}],"kids":[{"n":1,"t":"이것은 르무엘 왕이 한 말씀인데 그의 엄마가 그에게 가르쳐 준 잠언이야."},{"n":2,"t":"내 아들아, 내가 어떤 말을 해 줄까? 내 배 속에서 난 아들아, 내가 무엇을 말해 줄까? 하나님께 약속하고 얻은 아들아, 어떤 가르침을 줄까?"},{"n":3,"t":"너의 힘을 잘못된 곳에 쏟지 말고 왕들을 망하게 하는 일에 마음을 쓰지 마라."},{"n":4,"t":"르무엘아, 포도주를 즐기는 것은 왕에게 어울리지 않고 독한 술을 찾는 것은 다스리는 사람에게 어울리지 않아."},{"n":5,"t":"술을 마시면 법을 잊어버리고 어려운 사람의 재판을 비뚤어지게 할 수도 있어."},{"n":6,"t":"독한 술은 죽음을 앞둔 사람에게 주고 포도주는 마음이 너무 힘든 사람에게 주어라."},{"n":7,"t":"그래야 그 사람들이 잠시라도 자기 가난을 잊고 자기 고통을 기억하지 않을 수 있으니까."},{"n":8,"t":"너는 말 못 하는 사람과 외로운 사람의 일을 위해 입을 열어 주어라."},{"n":9,"t":"입을 열어 옳게 판단하고 어려운 사람과 가난한 사람의 억울함을 풀어 주어라."},{"n":10,"t":"누가 정말 훌륭한 여자를 만날 수 있을까? 그 사람의 값은 보석보다도 훨씬 귀해."},{"n":11,"t":"그런 사람의 남편은 마음으로 그를 믿고 살아서 부족함이 없게 돼."},{"n":12,"t":"그는 평생 동안 남편에게 좋은 일만 하고 나쁜 일은 하지 않아."},{"n":13,"t":"양털과 삼을 구해다가 부지런히 손으로 일하고"},{"n":14,"t":"무역하는 배처럼 멀리에서도 양식을 가져와."},{"n":15,"t":"밤이 다 새기 전에 일어나서 식구들에게 음식을 챙겨 주고 일하는 사람들에게 그날의 일을 나누어 맡겨."},{"n":16,"t":"좋은 밭을 살펴보고 사 두며 자기가 일해서 번 것으로 포도밭을 가꿔."},{"n":17,"t":"허리를 단단히 묶고 자기 팔을 힘있게 만들어 부지런히 일해."},{"n":18,"t":"자기가 하는 일이 잘되는 걸 알고 밤에도 등불을 끄지 않을 만큼 부지런해."},{"n":19,"t":"손으로 실 잣는 도구를 다루고 손가락으로 정성껏 실을 만들어."},{"n":20,"t":"어려운 사람에게는 손을 펴서 도와주고 가난한 사람에게는 손을 내밀어 친절을 베풀어."},{"n":21,"t":"자기 집 식구들이 따뜻한 옷을 다 갖춰 입었기에 눈이 내려도 그는 식구들을 걱정하지 않아."},{"n":22,"t":"자기 집에 쓸 아름다운 이불을 직접 만들고 자기는 좋은 옷감과 자주색 옷을 입고 다녀."},{"n":23,"t":"그의 남편은 마을 어른들과 함께 성문 앞에 앉아 사람들의 존경을 받게 돼."},{"n":24,"t":"그는 천으로 옷을 지어 팔고 띠도 만들어 상인들에게 맡겨."},{"n":25,"t":"그는 힘과 위엄을 자기 옷처럼 입고 앞날을 웃으며 바라봐."},{"n":26,"t":"입을 열면 지혜로운 말을 하고 그 혀에서는 친절을 가르치는 말이 흘러나와."},{"n":27,"t":"자기 집안일을 잘 살피고 게으르게 얻은 음식은 먹지 않아."},{"n":28,"t":"그의 자식들은 일어나서 \\"엄마, 감사해요\\" 하고 말하고 그의 남편은 이렇게 칭찬해."},{"n":29,"t":"\\"좋은 여자가 많지만 당신은 그 모든 여자들보다 뛰어나오.\\""},{"n":30,"t":"고운 외모도 잠시 지나고 아름다움도 헛되지만 하나님을 두려워하고 공경하는 여자는 진정으로 칭찬받을 거야."},{"n":31,"t":"그가 손으로 일한 모든 좋은 결과가 그에게로 돌아가고 그가 행한 좋은 일들이 마을 사람들 앞에서 칭찬받게 될 거야."}]}}]}');

